<template>
  <div v-if="projectWizardVisible" class="project-flow-shell">
    <div v-if="toastMessage" class="toast project-flow-toast" role="status" aria-live="polite">
      {{ toastMessage }}
    </div>

    <header class="project-flow-navbar">
      <a class="brand-link" href="/" @click.prevent="closeProjectWizard(); openPublicPage('home')">
        <span class="brand-mark" aria-hidden="true">
          <img src="/favicon.svg" alt="" />
        </span>
        <strong>MergeOS</strong>
      </a>

      <nav class="nav-links project-flow-nav" aria-label="Project setup navigation">
        <div class="nav-menu" :class="{ open: activeNavMenu === 'product' }" @mouseenter="openNavContextMenu('product', $event)" @focusin="openNavContextMenu('product', $event)" @mouseleave="scheduleNavContextClose" @keydown.escape.stop="closeNavContextMenu">
          <button
            type="button"
            :class="['nav-menu-trigger', { 'nav-active': productNavIsActive }]"
            aria-haspopup="true"
            :aria-expanded="activeNavMenu === 'product'"
            @click.stop="toggleNavContextMenu('product', $event)"
          >
            {{ publicNavCopy.product }}
            <ChevronDown :size="13" />
          </button>
          <div class="nav-context-menu nav-mega-menu product-menu" :style="navContextMenuInlineStyle('product')" role="menu" aria-label="Product menu" @mouseenter="cancelNavContextClose" @mouseleave="scheduleNavContextClose">
            <section class="nav-context-panel" aria-hidden="false">
              <span class="nav-context-eyebrow">{{ publicNavCopy.productMenuEyebrow }}</span>
              <strong class="nav-context-title">{{ publicNavCopy.productMenuTitle }}</strong>
              <p>{{ publicNavCopy.productMenuBody }}</p>
              <div class="nav-context-feature-list">
                <button v-for="item in productNavFeaturedItems" :key="item.title" class="nav-feature-item" type="button" role="menuitem" @click="handlePublicAction(item.action)">
                  <span :class="['public-card-icon', item.tone]">
                    <component :is="item.icon" :size="15" />
                  </span>
                  <span>
                    <strong>{{ item.title }}</strong>
                    <small>{{ item.body }}</small>
                  </span>
                </button>
              </div>
            </section>
            <section class="nav-context-grid" aria-label="Product workflows">
              <button v-for="item in productNavMenuItems" :key="item.title" class="nav-context-item" type="button" role="menuitem" @click="handlePublicAction(item.action)">
                <span :class="['public-card-icon', item.tone]">
                  <component :is="item.icon" :size="16" />
                </span>
                <span>
                  <strong>{{ item.title }}</strong>
                  <small>{{ item.body }}</small>
                </span>
              </button>
            </section>
          </div>
        </div>
        <div class="nav-menu" :class="{ open: activeNavMenu === 'solutions' }" @mouseenter="openNavContextMenu('solutions', $event)" @focusin="openNavContextMenu('solutions', $event)" @mouseleave="scheduleNavContextClose" @keydown.escape.stop="closeNavContextMenu">
          <button
            type="button"
            :class="['nav-menu-trigger', { 'nav-active': solutionNavIsActive }]"
            aria-haspopup="true"
            :aria-expanded="activeNavMenu === 'solutions'"
            @click.stop="toggleNavContextMenu('solutions', $event)"
          >
            {{ publicNavCopy.solutions }}
            <ChevronDown :size="13" />
          </button>
          <div class="nav-context-menu nav-mega-menu solutions-menu" :style="navContextMenuInlineStyle('solutions')" role="menu" aria-label="Solutions menu" @mouseenter="cancelNavContextClose" @mouseleave="scheduleNavContextClose">
            <section class="nav-context-panel" aria-hidden="false">
              <span class="nav-context-eyebrow">{{ publicNavCopy.solutionMenuEyebrow }}</span>
              <strong class="nav-context-title">{{ publicNavCopy.solutionMenuTitle }}</strong>
              <p>{{ publicNavCopy.solutionMenuBody }}</p>
              <div class="nav-context-feature-list">
                <button v-for="item in solutionNavFeaturedItems" :key="item.title" class="nav-feature-item" type="button" role="menuitem" @click="handlePublicAction(item.action)">
                  <span :class="['public-card-icon', item.tone]">
                    <component :is="item.icon" :size="15" />
                  </span>
                  <span>
                    <strong>{{ item.title }}</strong>
                    <small>{{ item.body }}</small>
                  </span>
                </button>
              </div>
            </section>
            <section class="nav-context-grid" aria-label="Solution lanes">
              <button v-for="item in solutionNavMenuItems" :key="item.title" class="nav-context-item" type="button" role="menuitem" @click="handlePublicAction(item.action)">
                <span :class="['public-card-icon', item.tone]">
                  <component :is="item.icon" :size="16" />
                </span>
                <span>
                  <strong>{{ item.title }}</strong>
                  <small>{{ item.body }}</small>
                </span>
              </button>
            </section>
          </div>
        </div>
        <a href="/marketplace" @click.prevent="closeProjectWizard(); openPublicPage('marketplace')">{{ publicNavCopy.marketplace }}</a>
        <a :href="publicPathForPage('live')" @click.prevent="closeProjectWizard(); openPublicPage('live')">{{ publicNavCopy.liveFeed }}</a>
        <a href="/how-it-works" @click.prevent="closeProjectWizard(); openPublicPage('how-it-works')">{{ publicNavCopy.howItWorks }}</a>
        <a :href="publicPathForPage('ledger')" @click.prevent="closeProjectWizard(); openPublicPage('ledger')">{{ publicNavCopy.ledger }}</a>
        <a :href="publicPathForPage('protocol')" @click.prevent="closeProjectWizard(); openPublicPage('protocol')">{{ publicNavCopy.protocol }}</a>
      </nav>

      <div class="nav-actions project-flow-actions">
        <div class="locale-menu" :class="{ open: activeNavMenu === 'locale' }" @mouseleave="scheduleNavContextClose" @keydown.escape.stop="closeNavContextMenu">
          <button
            class="locale-button icon-only"
            type="button"
            :aria-label="publicNavCopy.language"
            aria-haspopup="true"
            :aria-expanded="activeNavMenu === 'locale'"
            @click.stop="toggleNavContextMenu('locale')"
          >
            <Globe2 :size="17" />
            {{ activeLocaleLabel }}
            <ChevronDown :size="13" />
          </button>
          <div class="locale-context-menu" :class="{ 'context-menu-visible': activeNavMenu === 'locale' }" role="menu" aria-label="Language menu">
            <button
              v-for="option in localeOptions"
              :key="option.code"
              class="locale-context-item"
              :class="{ selected: activeLocale === option.code }"
              :data-locale-code="option.code"
              type="button"
              role="menuitemradio"
              :aria-checked="activeLocale === option.code"
              @click="setLocalePreference(option.code)"
            >
              <span>
                <strong>{{ localeDisplayLabel(option) }}</strong>
                <small>{{ localeDisplayDetail(option) }}</small>
              </span>
              <CheckCircle2 v-if="activeLocale === option.code" :size="15" />
            </button>
          </div>
        </div>
        <div class="account-menu project-account-menu" :class="{ open: activeNavMenu === 'account' }" @mouseleave="scheduleNavContextClose" @keydown.escape.stop="closeNavContextMenu">
          <button
            class="account-icon-button"
            type="button"
            :aria-label="publicNavCopy.account"
            aria-haspopup="true"
            :aria-expanded="activeNavMenu === 'account'"
            @click.stop="toggleNavContextMenu('account')"
          >
            <span v-if="user" class="profile-avatar">{{ initialsFor(user.name || user.email) }}</span>
            <User v-else :size="18" />
            <ChevronDown :size="13" />
          </button>
          <div class="account-context-menu" :class="{ 'context-menu-visible': activeNavMenu === 'account' }" role="menu" :aria-label="publicNavCopy.account">
            <div class="account-context-head">
              <strong>{{ user ? (user.name || user.email) : publicNavCopy.guest }}</strong>
              <small>{{ user ? publicNavCopy.signedIn : publicNavCopy.signInPrompt }}</small>
            </div>
            <template v-if="user">
              <button type="button" role="menuitem" @click="openProjectWizardMessagesFromAccountMenu">
                <MessageCircle :size="15" />
                {{ publicNavCopy.messages }}
              </button>
              <button type="button" role="menuitem" @click="openDashboardFromAccountMenu">
                <LayoutDashboard :size="15" />
                {{ publicNavCopy.dashboard }}
              </button>
              <button type="button" role="menuitem" @click="logoutFromAccountMenu">
                <ArrowLeft :size="15" />
                {{ publicNavCopy.logout }}
              </button>
            </template>
            <template v-else>
              <button type="button" role="menuitem" @click="openAuthFromProjectWizard('login')">
                <User :size="15" />
                {{ publicNavCopy.login }}
              </button>
              <button type="button" role="menuitem" @click="openAuthFromProjectWizard('register')">
                <ArrowRight :size="15" />
                {{ publicNavCopy.signUp }}
              </button>
            </template>
          </div>
        </div>
        <button class="primary-button compact" type="button" @click="restartProjectWizard">
          {{ publicHomeCopy.primaryAction }}
          <ArrowRight :size="16" />
        </button>
      </div>
    </header>

    <main class="project-flow-main" :class="`stage-${projectWizardStage}`">
      <aside class="project-flow-sidebar">
        <button class="back-link" type="button" @click="closeProjectWizard">
          <ArrowLeft :size="15" />
          Back to home
        </button>

        <div class="project-flow-title">
          <h1>{{ projectWizardStage === 'success' ? 'Payment complete' : 'Start a project' }}</h1>
          <p>{{ wizardIntroCopy }}</p>
        </div>

        <article v-if="projectWizardStage === 'setup' && tokenLaunchBriefMode" class="wizard-token-brief-card" aria-label="CEO token launch research brief">
          <span class="wizard-token-brief-icon">
            <Compass :size="17" />
          </span>
          <div>
            <strong>{{ tokenLaunchWizardBriefCopy.title }}</strong>
            <p>{{ tokenLaunchWizardBriefCopy.body }}</p>
          </div>
          <ol>
            <li v-for="item in tokenLaunchWizardChecklist" :key="item.label">
              <span>{{ item.label }}</span>
              <small>{{ item.detail }}</small>
            </li>
          </ol>
        </article>

        <nav class="project-step-list" aria-label="Project setup steps">
          <button
            v-for="step in projectSetupSteps"
            :key="step.number"
            :class="projectStepNavClass(step.number)"
            type="button"
            @click="goProjectStep(step.number)"
          >
            <span>
              <CheckCircle2 v-if="projectStepNavDone(step.number)" :size="16" />
              <template v-else>{{ step.number }}</template>
            </span>
            <strong>
              <span class="project-step-full-label">{{ step.label }}</span>
              <span class="project-step-short-label">{{ step.shortLabel || step.label }}</span>
            </strong>
            <small>{{ step.description }}</small>
          </button>
        </nav>

        <article v-if="projectWizardStage === 'setup' && projectWizardStep === 1" class="wizard-help-card">
          <Sparkles :size="17" />
          <strong>Need help?</strong>
          <p>Our AI assistant can help you structure your project.</p>
          <button type="button" :disabled="briefAssistantBusy" @click="runProjectBriefAssistant">
            {{ briefAssistantBusy ? 'Structuring brief...' : 'Use AI assistant' }}
          </button>
        </article>

        <article v-else-if="projectWizardStage === 'setup' && projectWizardStep === 3" class="wizard-help-card accent">
          <Calculator :size="17" />
          <strong>AI Budget Estimator</strong>
          <p>Let AI analyze your requirements and suggest the right budget range.</p>
          <button type="button" :disabled="priceEvaluationBusy" @click="runProjectPriceEvaluation">
            {{ priceEvaluationBusy ? 'Estimating...' : 'Estimate with AI' }}
          </button>
        </article>

        <article v-else class="wizard-quality-card" :class="{ ready: projectQualityScore >= 75 }" aria-label="AI brief readiness review">
          <div class="wizard-quality-head">
            <span class="wizard-quality-icon" aria-hidden="true">
              <Sparkles :size="16" />
            </span>
            <div>
              <strong>AI Review</strong>
              <small>{{ projectQualityStatusLabel }}</small>
            </div>
            <span class="wizard-quality-score">
              <b>{{ projectQualityScoreLabel }}</b>
              <small>ready</small>
            </span>
          </div>
          <div
            class="quality-meter"
            role="meter"
            aria-label="AI routing readiness score"
            :aria-valuenow="projectQualityScore"
            aria-valuemin="0"
            aria-valuemax="100"
          >
            <div class="quality-meter-labels">
              <span>AI routing readiness</span>
              <b>{{ projectQualityCompletedCount }}/{{ projectQualityChecklist.length }}</b>
            </div>
            <i><b :style="{ width: `${projectQualityScore}%` }" /></i>
          </div>
          <div class="quality-signal-grid" aria-label="AI review signals">
            <span v-for="signal in projectQualitySummaryRows" :key="signal.label" :class="signal.tone">
              <small>{{ signal.label }}</small>
              <strong>{{ signal.value }}</strong>
            </span>
          </div>
          <p>{{ projectQualityCopy }}</p>
          <button
            v-if="projectQualityScore < 100"
            class="quality-next-action"
            type="button"
            @click="openNextProjectQualityIssue"
          >
            {{ projectQualityNextActionLabel }}
            <ArrowRight :size="14" />
          </button>
          <div v-if="projectQualityBlockingRows.length" class="quality-blocker-list" aria-label="AI review blockers">
            <strong>{{ projectQualityBlockingRows.length }} blocker{{ projectQualityBlockingRows.length === 1 ? '' : 's' }}</strong>
            <button
              v-for="item in projectQualityBlockingRows"
              :key="item.key"
              type="button"
              @click="openProjectQualityItem(item)"
            >
              <span>{{ item.label }}</span>
              <small>{{ item.detail }}</small>
            </button>
          </div>
          <ol class="quality-check-list" aria-label="AI review checkpoints">
            <li
              v-for="(item, index) in projectQualityChecklist"
              :key="item.key"
              :class="{ done: item.done, current: item.current }"
            >
              <span>
                <CheckCircle2 v-if="item.done" :size="12" />
                <small v-else>{{ index + 1 }}</small>
              </span>
              <div>
                <strong>{{ item.label }}</strong>
                <small>{{ item.detail }}</small>
              </div>
            </li>
          </ol>
        </article>
      </aside>

      <section class="project-flow-board">
        <article v-if="projectWizardStage === 'setup'" class="wizard-card project-step-panel">
          <header class="wizard-card-heading">
            <div>
              <span class="step-kicker">{{ projectWizardStep }}. {{ currentProjectStep.label }}</span>
              <h2>{{ currentProjectStep.title }}</h2>
              <p>{{ currentProjectStep.helper }}</p>
            </div>
            <button v-if="projectWizardStep === 4" class="secondary-button compact ghost" type="button" @click="openProjectPreview">
              <Eye :size="15" />
              Preview
            </button>
          </header>
          <div v-if="projectShouldShowStepErrors && currentProjectValidationList.length" class="wizard-validation-banner" role="alert">
            <strong>{{ currentProjectValidationList.length }} item{{ currentProjectValidationList.length === 1 ? '' : 's' }} need attention</strong>
            <ul>
              <li v-for="item in currentProjectValidationList" :key="item.field">{{ item.message }}</li>
            </ul>
          </div>

          <div v-if="projectWizardStep === 1" class="wizard-form-grid">
            <label class="wizard-field full" :class="{ invalid: projectFieldError('title') }">
              <span>Project title <b>*</b></span>
              <input
                v-model.trim="projectSetupForm.title"
                maxlength="120"
                :aria-invalid="Boolean(projectFieldError('title'))"
                :placeholder="projectSetupForm.projectType === 'Bug Fix' ? 'Briefly describe the bug you need fixed' : 'Enter a clear project title'"
                @blur="markProjectFieldTouched('title')"
              />
              <small>{{ projectSetupForm.title.length }} / 120</small>
              <p v-if="projectFieldError('title')" class="wizard-field-error">{{ projectFieldError('title') }}</p>
            </label>

            <label class="wizard-field full" :class="{ invalid: projectFieldError('shortDescription') }">
              <span>Short description <b>*</b></span>
              <textarea
                v-model.trim="projectSetupForm.shortDescription"
                rows="5"
                maxlength="1000"
                :aria-invalid="Boolean(projectFieldError('shortDescription'))"
                :placeholder="projectSetupForm.projectType === 'Bug Fix' ? 'Describe the bug, expected behavior, and how to reproduce it' : 'Describe your project, what you want to build, and the problem you are solving...'"
                @blur="markProjectFieldTouched('shortDescription')"
              />
              <small>{{ projectSetupForm.shortDescription.length }} / 1000</small>
              <p v-if="projectFieldError('shortDescription')" class="wizard-field-error">{{ projectFieldError('shortDescription') }}</p>
            </label>

            <section class="wizard-section full" :class="{ invalid: projectFieldError('projectType') }">
              <div class="wizard-section-title">
                <strong>Project type <b>*</b></strong>
                <small>What kind of work do you need?</small>
              </div>
              <div class="project-type-grid project-type-split">
                <button
                  v-for="type in projectTypeOptions"
                  :key="type.label"
                  :class="{ selected: projectSetupForm.projectType === type.label }"
                  class="select-tile select-tile-big"
                  type="button"
                  @click="projectSetupForm.projectType = type.label; markProjectFieldTouched('projectType')"
                >
                  <component :is="type.icon" :size="24" />
                  <strong>{{ type.label }}</strong>
                  <small>{{ type.caption }}</small>
                  <CheckCircle2 v-if="projectSetupForm.projectType === type.label" class="tile-check" :size="20" />
                </button>
              </div>
              <p v-if="projectFieldError('projectType')" class="wizard-field-error">{{ projectFieldError('projectType') }}</p>
            </section>

            <label class="wizard-field full">
              <span>Tech stack <small>(optional)</small></span>
              <input v-model.trim="projectSetupForm.techStack"
                :placeholder="projectSetupForm.projectType === 'Bug Fix' ? 'Technologies used in the existing project' : 'Add technologies or frameworks'" />
            </label>

            <section v-if="projectSetupForm.projectType === 'Bug Fix'" class="wizard-section full attach-repo">
              <div class="attach-repo-head">
                <div>
                  <strong>Attach repository <b>*</b></strong>
                  <p>Load open issues and turn them into scored fix tasks.</p>
                </div>
                <button class="secondary-button compact" :disabled="repoImportBusy" type="button" @click="loadRepoIssues">
                  <RefreshCw :size="15" />
                  {{ repoImportBusy ? 'Loading issues' : 'Load issues' }}
                </button>
              </div>
              <label class="wizard-field full repo-url-field" :class="{ invalid: projectFieldError('repoUrl') || projectFieldError('repoImport') }">
                <span>GitHub repository</span>
                <input
                  v-model.trim="projectSetupForm.repoUrl"
                  placeholder="https://github.com/owner/repo"
                  :aria-invalid="Boolean(projectFieldError('repoUrl') || projectFieldError('repoImport'))"
                  @blur="markProjectFieldTouched('repoUrl')"
                  @keyup.enter="loadRepoIssues"
                />
                <p v-if="projectFieldError('repoUrl')" class="wizard-field-error">{{ projectFieldError('repoUrl') }}</p>
                <p v-else-if="projectFieldError('repoImport')" class="wizard-field-error">{{ projectFieldError('repoImport') }}</p>
              </label>
              <p v-if="repoImportError" class="modal-error repo-import-error">{{ repoImportError }}</p>
              <div v-if="repoImportedIssues.length" class="repo-issue-panel">
                <div class="repo-issue-summary">
                  <strong>{{ repoImportResult.owner }}/{{ repoImportResult.name }}</strong>
                  <span>{{ repoImportedIssues.length }} issues / {{ formatMRGFromCents(repoImportedEstimateCents) }} scored</span>
                </div>
                <article v-for="issue in repoImportedIssues.slice(0, 4)" :key="issue.number" class="repo-issue-row">
                  <span>#{{ issue.number }}</span>
                  <div>
                    <strong>{{ issue.title }}</strong>
                    <small>Score {{ issue.score }} / {{ issue.complexity }} / {{ formatMRGFromCents(issue.estimated_cents) }}</small>
                  </div>
                </article>
              </div>
            </section>

            <section v-if="projectSetupForm.projectType === 'New Project'" class="wizard-section full">
              <div class="new-project-hint">
                <p>Describe your idea below, then we will help you scope it, price it, and find the right contributor.</p>
              </div>
            </section>
          </div>

          <div v-else-if="projectWizardStep === 2" class="wizard-form-grid">
            <section class="wizard-section full" :class="{ invalid: projectFieldError('overview') }">
              <div class="wizard-section-title">
                <strong>Project overview</strong>
                <small>Provide more details about your project goals and what you want to achieve.</small>
              </div>
              <div class="rich-editor">
                <div class="editor-toolbar" aria-label="Text formatting tools">
                  <button type="button" aria-label="Bold"><strong>B</strong></button>
                  <button type="button" aria-label="Italic"><em>I</em></button>
                  <button type="button" aria-label="Bulleted list"><ListTodo :size="15" /></button>
                  <button type="button" aria-label="Quote"><Quote :size="15" /></button>
                  <button type="button" aria-label="Link"><Link2 :size="15" /></button>
                </div>
                <textarea
                  v-model.trim="projectSetupForm.overview"
                  rows="7"
                  maxlength="6000"
                  placeholder="Describe in detail what you need built, the goals, key features, and any important context..."
                  @blur="markProjectFieldTouched('overview')"
                />
                <small>{{ projectSetupForm.overview.length }} / 6000</small>
              </div>
              <p v-if="projectFieldError('overview')" class="wizard-field-error">{{ projectFieldError('overview') }}</p>
            </section>

            <section class="wizard-section full" :class="{ invalid: projectFieldError('deliverables') }">
              <div class="wizard-section-title row">
                <div>
                  <strong>Key deliverables</strong>
                  <small>What are the main things you expect to receive?</small>
                </div>
                <button class="text-action" type="button" @click="addDeliverable">
                  <Plus :size="14" />
                  Add deliverable
                </button>
              </div>
              <div class="deliverable-list">
                <label v-for="(deliverable, index) in projectDeliverables" :key="index" class="deliverable-row">
                  <GripVertical :size="15" />
                  <input v-model.trim="projectDeliverables[index]" maxlength="160" :placeholder="projectDeliverablePlaceholders[index] || 'Describe another deliverable'" @blur="markProjectFieldTouched('deliverables')" />
                  <button type="button" :aria-label="`Remove deliverable ${index + 1}`" @click="removeDeliverable(index)">
                    <X :size="14" />
                  </button>
                </label>
              </div>
              <p v-if="projectFieldError('deliverables')" class="wizard-field-error">{{ projectFieldError('deliverables') }}</p>
            </section>

            <label class="wizard-field split" :class="{ invalid: projectFieldError('requirements') }">
              <span>Project requirements</span>
              <textarea
                v-model.trim="projectSetupForm.requirements"
                rows="7"
                maxlength="2000"
                :aria-invalid="Boolean(projectFieldError('requirements'))"
                placeholder="Add constraints, quality bar, compliance, or integration requirements"
                @blur="markProjectFieldTouched('requirements')"
              />
              <small>{{ projectSetupForm.requirements.length }} / 2000</small>
              <p v-if="projectFieldError('requirements')" class="wizard-field-error">{{ projectFieldError('requirements') }}</p>
            </label>

            <section
              class="wizard-section split reference-dropzone"
              :class="{ uploading: referenceUploadBusy, 'has-files': referenceAttachments.length }"
              @dragover.prevent
              @drop.prevent="handleReferenceDrop"
            >
              <input
                ref="referenceFileInput"
                class="visually-hidden-file"
                type="file"
                multiple
                accept=".png,.jpg,.jpeg,.webp,.gif,.pdf,.doc,.docx,.txt,.md,.json,.zip"
                @change="handleReferenceFilesSelected"
              />
              <UploadCloud :size="24" />
              <strong>{{ referenceUploadBusy ? 'Uploading references...' : 'Attach reference files' }}</strong>
              <button class="text-action" type="button" :disabled="referenceUploadBusy" @click="openReferenceFilePicker">
                {{ referenceAttachments.length ? 'add more files' : 'browse your files' }}
              </button>
              <small>Supports images, PDFs, docs, text specs, and ZIPs up to 15MB each.</small>
              <p v-if="referenceUploadError" class="modal-error reference-upload-error">{{ referenceUploadError }}</p>
              <div v-if="referenceAttachments.length" class="reference-file-list" aria-label="Uploaded reference files">
                <article v-for="attachment in referenceAttachments" :key="attachment.id">
                  <FileCheck2 :size="15" />
                  <div>
                    <strong>{{ attachment.original_name }}</strong>
                    <small>{{ formatFileSize(attachment.size_bytes) }} - {{ attachment.content_type || 'file' }}</small>
                  </div>
                  <button type="button" :aria-label="`Remove ${attachment.original_name}`" @click="removeReferenceAttachment(attachment.id)">
                    <X :size="14" />
                  </button>
                </article>
              </div>
            </section>
          </div>

          <div v-else-if="projectWizardStep === 3" class="wizard-form-grid">
