                  <span class="currency-chip">{{ tokenSymbol }}</span>
                  <input
                    v-model.number="projectSetupForm.budgetAmount"
                    placeholder="0"
                    type="number"
                    min="10000"
                    step="1000"
                    :aria-invalid="Boolean(projectFieldError('budgetAmount'))"
                    @blur="markProjectFieldTouched('budgetAmount')"
                  />
                </div>
                <p v-if="projectFieldError('budgetAmount')" class="wizard-field-error">{{ projectFieldError('budgetAmount') }}</p>
              </label>

              <div class="wizard-section grow">
