        <button type="button" @click="openMRGRewards">
          Learn more
          <ArrowRight :size="14" />
        </button>
      </article>
    </aside>

    <section class="dash-workspace">
      <header class="dash-topbar">
        <label :class="['dash-search', { 'mobile-open': dashboardMobileSearchOpen }]">
          <Search :size="16" />
          <input v-model.trim="dashboardSearch" :placeholder="dashboardSearchPlaceholder" />
          <kbd>Ctrl K</kbd>
        </label>

        <nav class="dash-topnav" aria-label="Dashboard sections">
          <button
            v-for="item in topNavItems"
            :key="item.label"
            :class="{ active: isDashboardNavActive(item) }"
            type="button"
            @click="handleDashboardNav(item)"
          >
            {{ item.label }}
          </button>
        </nav>

        <div class="dash-top-actions">
          <button
            class="dash-icon-button dash-search-toggle"
            type="button"
            :aria-label="dashboardMobileSearchOpen ? 'Close dashboard search' : 'Open dashboard search'"
            :aria-expanded="dashboardMobileSearchOpen ? 'true' : 'false'"
            @click="toggleDashboardMobileSearch"
          >
            <Search :size="17" />
          </button>
          <div ref="dashboardNotificationMenu" class="notification-menu-wrap" @click.stop @keydown.escape.stop="closeDashboardNotificationMenu">
            <button
              ref="dashboardNotificationTrigger"
              class="dash-icon-button"
              aria-label="Notifications"
              type="button"
              aria-haspopup="dialog"
              aria-controls="dashboard-notification-dropdown"
              :aria-expanded="dashboardNotificationMenuOpen ? 'true' : 'false'"
              @click="toggleDashboardNotificationMenu"
            >
              <Bell :size="18" />
              <span v-if="dashboardNotificationCount > 0" class="notification-badge">{{ dashboardNotificationBadgeLabel }}</span>
            </button>
          </div>
          <Teleport to="body">
            <section
              v-if="dashboardNotificationMenuOpen"
              id="dashboard-notification-dropdown"
              ref="dashboardNotificationDropdown"
              :class="[
                'notification-dropdown',
                {
                  'is-above': dashboardNotificationMenuPlacement === 'above',
                  'is-mobile-sheet': dashboardNotificationMenuPlacement === 'mobile-sheet',
                },
              ]"
              :style="dashboardNotificationDropdownStyle"
              role="dialog"
              aria-label="Notifications"
              tabindex="-1"
              @click.stop
              @keydown.escape.stop="closeDashboardNotificationMenu"
            >
              <header class="notification-dropdown-head">
                <div>
                  <strong>Notifications</strong>
                  <small>{{ dashboardNotificationStatusLabel }}</small>
                </div>
                <button
                  type="button"
                  aria-label="Refresh notifications"
                  :disabled="dashboardNotificationsLoading"
                  @click="refreshDashboardNotificationMenu"
                >
                  <RefreshCw :class="{ 'loading-spin': dashboardNotificationsLoading }" :size="14" />
                </button>
              </header>

              <div v-if="dashboardNotificationMenuRows.length" class="notification-dropdown-list">
                <button
                  v-for="note in dashboardNotificationMenuRows"
                  :key="note.id"
                  :class="['notification-dropdown-item', { 'is-unread': note.isUnread }]"
                  type="button"
                  @click="handleNotificationMenuClick(note)"
                >
                  <span :class="['notification-dot', note.tone, { 'unread-pulse': note.isUnread }]" aria-hidden="true" />
                  <span class="notification-dropdown-copy">
                    <strong>{{ note.subject }}</strong>
                    <small>{{ note.body }}</small>
                    <em>{{ note.meta }}</em>
                  </span>
                  <b v-if="note.isUnread">New</b>
                </button>
              </div>

              <article v-else class="notification-dropdown-empty">
                <strong>{{ dashboardNotificationsLoading ? 'Loading notifications...' : 'No notifications yet' }}</strong>
                <p>{{ dashboardNotificationsLoading ? 'Fetching delivery records.' : dashboardNotificationsError || 'Project updates will appear here.' }}</p>
              </article>

              <footer class="notification-dropdown-actions">
                <button type="button" @click="openDashboardNotificationCenter">View all</button>
                <button v-if="dashboardNotificationCount > 0" type="button" @click="markAllNotificationsReadFromMenu">
                  Mark all read
                </button>
              </footer>
            </section>
          </Teleport>
          <button class="primary-button compact" type="button" @click="openProjectWizard">
            <Plus :size="16" />
            <span>New Project</span>
          </button>
          <div class="account-menu dashboard-account-menu" :class="{ open: activeNavMenu === 'dashboard-account' }" @mouseleave="scheduleNavContextClose" @keydown.escape.stop="closeNavContextMenu">
            <button
              class="dash-profile"
              type="button"
              :aria-label="publicNavCopy.account"
              aria-haspopup="true"
              :aria-expanded="activeNavMenu === 'dashboard-account'"
              @click.stop="toggleNavContextMenu('dashboard-account')"
            >
              <span class="profile-avatar">{{ initialsFor(user.name || user.email) }}</span>
              <span>
                <strong>{{ user.name || user.email || 'Signed-in user' }}</strong>
                <small>{{ user.wallet_address ? shortWallet(user.wallet_address) : 'Customer' }}</small>
              </span>
              <ChevronDown :size="14" />
            </button>
            <div class="account-context-menu" :class="{ 'context-menu-visible': activeNavMenu === 'dashboard-account' }" role="menu" :aria-label="publicNavCopy.account">
              <div class="account-context-head">
                <strong>{{ user.name || user.email || 'Signed-in user' }}</strong>
                <small>{{ user.wallet_address ? shortWallet(user.wallet_address) : publicNavCopy.signedIn }}</small>
              </div>
              <button type="button" role="menuitem" @click="openDashboardFromAccountMenu">
                <LayoutDashboard :size="15" />
                {{ publicNavCopy.dashboard }}
              </button>
              <button type="button" role="menuitem" @click="openProjectWizardMessagesFromAccountMenu">
                <MessageCircle :size="15" />
                {{ publicNavCopy.messages }}
              </button>
              <button type="button" role="menuitem" @click="logoutFromAccountMenu">
                <ArrowLeft :size="15" />
                {{ publicNavCopy.logout }}
              </button>
            </div>
          </div>
        </div>
      </header>

      <section class="dash-command-strip" aria-label="Dashboard command summary">
        <div class="dash-command-copy">
          <span class="marketplace-eyebrow">{{ dashboardSectionEyebrow }}</span>
          <h1>{{ dashboardCommandTitle }}</h1>
          <p>{{ dashboardCommandBody }}</p>
        </div>
        <div class="dash-command-metrics">
          <article v-for="metric in dashboardCommandStats" :key="metric.label">
            <span :class="['public-card-icon', metric.tone]">
              <component :is="metric.icon" :size="18" />
            </span>
            <div>
              <strong>{{ metric.value }}</strong>
              <small>{{ metric.label }}</small>
            </div>
          </article>
        </div>
      </section>

      <section class="dashboard-role-map" aria-label="Dashboard role coverage">
        <article
          v-for="role in dashboardRoleCoverageRows"
          :key="role.key"
          :class="{ active: role.active, locked: role.locked }"
        >
          <header>
            <span :class="['public-card-icon', role.tone]">
              <component :is="role.icon" :size="18" />
            </span>
            <div>
              <small>{{ role.eyebrow }}</small>
              <strong>{{ role.title }}</strong>
            </div>
            <b>{{ role.status }}</b>
          </header>
          <p>{{ role.body }}</p>
          <div class="dashboard-role-proof">
            <span>
              <small>Next</small>
              <strong>{{ role.nextStep }}</strong>
            </span>
            <span>
              <small>Proof</small>
              <strong>{{ role.proof }}</strong>
            </span>
          </div>
          <div class="dashboard-role-stats">
            <span v-for="stat in role.stats" :key="stat.label">
              <strong>{{ stat.value }}</strong>
              <small>{{ stat.label }}</small>
            </span>
          </div>
          <div class="dashboard-role-lanes">
            <button
              v-for="lane in role.lanes"
              :key="lane.label"
              type="button"
              :disabled="role.locked"
              @click="openDashboardRoleLane(role, lane)"
            >
              {{ lane.label }}
            </button>
          </div>
          <button class="dashboard-role-primary" type="button" :disabled="role.locked" @click="openDashboardRoleLane(role)">
            {{ role.actionLabel }}
            <ArrowRight :size="13" />
          </button>
        </article>
      </section>

      <main class="dash-content">
        <section class="dash-main">
          <template v-if="dashboardSection === 'payments'">
            <div class="dash-breadcrumb">
              <Home :size="14" />
              <span>Payments</span>
              <ChevronDown :size="13" />
              <strong>{{ dashboardPaymentView.title }}</strong>
            </div>

            <section v-if="dashboardError" class="dash-empty-state">
              <strong>Could not load your payment history</strong>
              <p>{{ dashboardError }}</p>
              <button class="secondary-button compact" type="button" @click="loadDashboardData">Retry</button>
            </section>

            <template v-else>
              <section class="dash-project-header payment-history-header">
                <div class="dash-project-title">
                  <span class="project-photo payment-photo">
                    <CreditCard :size="18" />
                  </span>
                  <div>
                    <h1>{{ dashboardPaymentView.title }}</h1>
                    <p>{{ dashboardPaymentView.body }}</p>
                  </div>
                  <span :class="['live-badge', dashboardStatusClass(dashboardPaymentView.status)]">{{ dashboardPaymentView.status }}</span>
                </div>

                <div class="dash-project-actions">
                  <button type="button" @click="loadDashboardData">
                    <RefreshCw :size="15" />
                    Refresh
                  </button>
                  <button type="button" @click="openPublicPage('ledger')">
                    <Link2 :size="15" />
                    View Ledger
                  </button>
                  <button type="button" aria-label="Copy payment history state" @click="copyDashboardPaymentState">
                    <MoreHorizontal :size="16" />
                  </button>
                </div>
              </section>

              <section class="dash-overview-grid payment-summary-grid">
                <article v-for="item in dashboardPaymentSummary" :key="item.label" class="dash-card payment-summary-card">
                  <span>{{ item.label }}</span>
                  <strong>{{ item.value }}</strong>
                  <small>{{ item.caption }}</small>
                </article>
              </section>

              <section class="dash-card payment-history-card">
                <div class="card-title-row">
                  <div>
                    <h2>Ledger-backed payment activity</h2>
                    <p>Funding, escrow, fees, mint logs, and payouts for the selected project are grouped in one place.</p>
                  </div>
                  <span>{{ dashboardPaymentRows.length }} rows</span>
                </div>

                <div v-if="dashboardPaymentRows.length" class="payment-history-list">
                  <article v-for="row in dashboardPaymentRows" :key="row.key" class="payment-history-row">
                    <div class="payment-history-main">
                      <span :class="['ledger-event-type', row.tone]">{{ row.type }}</span>
                      <strong>{{ row.title }}</strong>
                      <p>{{ row.body }}</p>
                    </div>

                    <div class="payment-history-meta">
                      <span>
                        <small>Method</small>
                        <strong>{{ row.method }}</strong>
                      </span>
                      <span>
                        <small>Status</small>
                        <strong>{{ row.status }}</strong>
                      </span>
                      <span>
                        <small>Counterparty</small>
                        <strong>{{ row.counterparty }}</strong>
                      </span>
                    </div>

                    <div class="payment-history-side">
                      <strong :class="['payment-history-amount', row.amountClass]">{{ row.amount }}</strong>
                      <small>{{ row.when }}</small>
                      <div class="payment-history-actions">
                        <button type="button" @click="copyPaymentRowReference(row)">
                          {{ row.reference }}
                        </button>
                        <button v-if="row.rawContractReference" type="button" @click="copyContractReference(row)">
                          {{ row.contractReference }}
                        </button>
                      </div>
                    </div>
                  </article>
                </div>
                <article v-else class="dash-empty-state compact">
                  <strong>{{ dashboardLoading ? 'Loading payment history...' : 'No payment history yet' }}</strong>
                  <p>{{ dashboardLoading ? 'Fetching real funding and payout logs.' : 'Fund a project or release a task payout to create the first payment row.' }}</p>
                  <div v-if="!dashboardLoading" class="dashboard-tool-empty-actions compact">
                    <button type="button" @click="openProjectWizard">
                      <Plus :size="13" />
                      Start Project
                    </button>
                    <button type="button" @click="openDashboardSection('repo-import')">
                      <UploadCloud :size="13" />
                      Import Repo
                    </button>
                    <button type="button" @click="openPublicPage('ledger')">
                      <Link2 :size="13" />
                      Public Ledger
                    </button>
                  </div>
                </article>

                <div class="watching-line">
                  <CreditCard :size="14" />
                  {{ dashboardPaymentRows.length }} payment events loaded
                </div>
              </section>
            </template>
          </template>

          <template v-else-if="dashboardSection === 'admin'">
            <div class="dash-breadcrumb">
              <Home :size="14" />
              <span>Admin</span>
              <ChevronDown :size="13" />
