                      <span :class="['notification-dot', item.ready ? 'green' : 'amber']" />
                      <div>
                        <strong>{{ item.label }}</strong>
                        <small>{{ item.value || 'Not linked' }}</small>
                      </div>
                      <b>{{ item.ready ? 'Ready' : 'Needed' }}</b>
