                        <b>{{ item.label }}</b>
                        <small>{{ item.value }}</small>
                      </span>
                    </div>
                  </div>
                  <div class="worker-audit-stats">
                    <article v-for="item in workerAuditStatRows" :key="item.label">
                      <span>{{ item.label }}</span>
