                        <strong>Fix review evidence</strong>
                        <ul>
                          <li v-for="item in taskReviewErrorList(task)" :key="item.field">{{ item.message }}</li>
                        </ul>
                      </div>
                      <label :class="{ invalid: taskReviewFieldError(task, 'pullRequestURL') }">
                        <span>Pull request URL</span>
                        <input
                          v-model.trim="task.reviewDraft.pullRequestURL"
                          type="url"
                          :aria-invalid="Boolean(taskReviewFieldError(task, 'pullRequestURL'))"
                          placeholder="https://github.com/org/repo/pull/12"
                          @input="clearTaskReviewFieldError(task, 'pullRequestURL')"
                        />
                        <small v-if="taskReviewFieldError(task, 'pullRequestURL')">{{ taskReviewFieldError(task, 'pullRequestURL') }}</small>
                      </label>
                      <label :class="{ invalid: taskReviewFieldError(task, 'evidenceURL') }">
                        <span>Evidence URL</span>
                        <input
                          v-model.trim="task.reviewDraft.evidenceURL"
                          type="url"
                          :aria-invalid="Boolean(taskReviewFieldError(task, 'evidenceURL'))"
                          placeholder="https://preview.example.com/evidence"
                          @input="clearTaskReviewFieldError(task, 'evidenceURL')"
                        />
                        <small v-if="taskReviewFieldError(task, 'evidenceURL')">{{ taskReviewFieldError(task, 'evidenceURL') }}</small>
                      </label>
                      <label class="wide" :class="{ invalid: taskReviewFieldError(task, 'notes') }">
                        <span>Review notes</span>
                        <textarea
                          v-model.trim="task.reviewDraft.notes"
                          rows="3"
                          :aria-invalid="Boolean(taskReviewFieldError(task, 'notes'))"
                          placeholder="Tests, preview, deployment, and risk notes"
                          @input="clearTaskReviewFieldError(task, 'notes')"
                        ></textarea>
                        <small v-if="taskReviewFieldError(task, 'notes')">{{ taskReviewFieldError(task, 'notes') }}</small>
                      </label>
                      <button type="submit" :disabled="reviewSubmittingTaskID === task.id">
                        <SendHorizontal :size="13" />
                        {{ reviewSubmittingTaskID === task.id ? 'Submitting' : 'Submit review' }}
                      </button>
                    </form>
