                      </button>
                      <button type="button" @click="loadWorkerDashboardData">
                        <RefreshCw :size="13" />
                        Refresh
                      </button>
                    </div>
                  </article>
                </article>

                <article class="dash-card worker-proposals-card">
                  <div class="card-title-row">
                    <h2>Proposal Opportunities</h2>
                    <span>{{ workerProposalRows.length }}</span>
                  </div>
                  <div v-if="workerProposalRows.length" class="worker-proposal-list">
                    <article v-for="proposal in workerProposalRows" :key="proposal.id">
                      <div class="worker-proposal-main">
                        <strong>{{ proposal.issue }} {{ proposal.title }}</strong>
                        <small v-if="proposal.claimHint">{{ proposal.claimHint }}</small>
                        <small>{{ proposal.project }} آ· {{ proposal.lane }}</small>
                        <p>{{ proposal.acceptance }}</p>
                        <div v-if="proposal.contextRows.length" class="worker-claim-context" aria-label="Worker claim context">
                          <a v-for="context in proposal.contextRows" :key="context.key" :href="context.url" target="_blank" rel="noreferrer">
                            {{ context.label }}
                          </a>
                        </div>
                        <ol v-if="proposal.runbookRows.length" class="worker-claim-runbook" aria-label="Worker claim runbook">
                          <li v-for="step in proposal.runbookRows" :key="step.key">
                            <b>{{ step.step }}</b>
                            <span>{{ step.label }}</span>
                            <small>{{ step.meta }}</small>
                          </li>
                        </ol>
                        <div v-if="proposal.evidenceRows.length || proposal.payloadRows.length || proposal.contractRows.length" class="worker-claim-packet" aria-label="Worker claim packet">
                          <span v-for="payload in proposal.payloadRows" :key="payload.label">
                            <b>{{ payload.label }}</b>
                            <small>{{ payload.value }}</small>
                          </span>
                          <span v-for="contract in proposal.contractRows" :key="contract.key">
                            <b>{{ contract.label }}</b>
                            <small>{{ contract.protocol }}</small>
                          </span>
                          <span v-for="evidence in proposal.evidenceRows" :key="evidence">
                            <b>Evidence</b>
                            <small>{{ evidence }}</small>
                          </span>
                        </div>
                        <div v-if="proposal.warningRows.length" class="worker-claim-warnings">
                          <span v-for="warning in proposal.warningRows" :key="warning">{{ warning }}</span>
                        </div>
                      </div>
                      <span>{{ proposal.reward }}</span>
                      <b>{{ proposal.matchScore }}%</b>
                      <div class="worker-proposal-actions">
                        <button
                          type="button"
                          :disabled="claimingBountyID === proposal.id || !proposal.canClaim"
                          @click="claimMarketplaceBounty(proposal)"
