                        <small>{{ proposal.project }} آ· {{ proposal.when }}</small>
                        <p>{{ proposal.cover }}</p>
                      </div>
                      <span>{{ proposal.bid }}</span>
                      <b :class="proposal.statusTone">{{ proposal.statusLabel }}</b>
                    </article>
                  </div>
                </article>
              </section>
            </template>
          </template>

