                        <div v-if="dashboardIssueScannerEmptyActions.length" class="dashboard-tool-empty-actions compact">
                          <button
                            v-for="action in dashboardIssueScannerEmptyActions"
                            :key="action.label"
                            type="button"
                            :disabled="action.disabled"
                            @click="action.run()"
                          >
                            <component :is="action.icon" :size="13" />
                            {{ action.label }}
                          </button>
                        </div>
                      </article>
                    </section>

                    <section class="repo-intel-section">
                      <div class="repo-intel-section-head">
