                  </div>
                  <div class="deployment-status-row">
                    <span class="deployment-icon"><Rocket :size="18" /></span>
                    <div>
                      <strong>{{ dashboardDeploymentView.progress }}%</strong>
                      <small>{{ dashboardDeploymentView.updatedAt }}</small>
                    </div>
                    <button type="button" aria-label="Refresh deployment validation" :disabled="dashboardDeploymentRefreshDisabled" @click="refreshDashboardDeploymentValidation">
                      <RefreshCw :size="14" />
