                    <FileCheck2 :size="14" />
                  </span>
                  <div>
                    <small>CEO memo</small>
                    <strong>{{ row.title }}</strong>
                    <p>{{ row.body }}</p>
                  </div>
                  <b>{{ row.created }}</b>
                </article>
              </div>
              <article v-for="row in tokenWorkflowProofRows" :key="row.key">
                <span :class="['ledger-trust-icon', row.tone]">
                  <component :is="row.icon" :size="15" />
