function tokenLaunchCandidateScore({ openTasks = 0, acceptedTasks = 0, signalCount = 0, workPoolMRG = 0 } = {}) {
  const demandScore = Math.min(Number(openTasks) || 0, 8) * 6;
  const deliveryScore = Math.min(Number(acceptedTasks) || 0, 12) * 3;
  const proofScore = Math.min(Number(signalCount) || 0, 8) * 5;
  const poolScore = Math.min(Math.floor((Number(workPoolMRG) || 0) / 10000), 8) * 2;
  return Math.min(98, Math.max(42, 42 + demandScore + deliveryScore + proofScore + poolScore));
}
function tokenLaunchCandidateDecisionRows(launchType = 'airdrop', score = 0) {
  const launchLabel = launchType === 'presale' ? 'presale' : 'airdrop';
  const strongFit = Number(score) >= 82;
  const approveLabel = launchType === 'presale'
    ? (strongFit ? 'Open presale' : 'Draft presale')
    : (strongFit ? 'Open missions' : 'Draft missions');
  return [
    {
      key: 'approve',
      label: approveLabel,
      tone: 'approve',
      proofPolicy: launchType === 'presale'
        ? 'Approve only with utility proof, reserve cap, Solana wallet path, funding reference, contract proof, and public ledger receipt.'
        : 'Approve only with repo task evidence, useful work proof, anti-bot review, wallet uniqueness, and public ledger receipt.',
      riskNotes: `CEO ${launchLabel} decision: ready to open after final proof review; score ${score}% fit.`,
    },
    {
      key: 'needs_evidence',
      label: 'Need proof',
      tone: 'evidence',
      proofPolicy: launchType === 'presale'
        ? 'Hold presale until utility, funding, wallet, contract, and receipt evidence are attached.'
        : 'Hold airdrop until repo task, PR/deploy proof, QA evidence, and wallet uniqueness are attached.',
      riskNotes: `CEO ${launchLabel} decision: request more evidence before opening; score ${score}% fit.`,
    },
    {
      key: 'reject',
      label: 'Hold launch',
      tone: 'reject',
      proofPolicy: 'Do not open token workflow until source, demand, proof quality, wallet policy, and ledger evidence are remediated.',
      riskNotes: `CEO ${launchLabel} decision: reject for now; score ${score}% fit and proof is not launch-ready.`,
    },
  ];
}
function tokenLaunchCandidateDecisionRowsFromAPI(rows = [], launchType = 'airdrop', score = 0) {
  if (!Array.isArray(rows) || !rows.length) return tokenLaunchCandidateDecisionRows(launchType, score);
  const fallbackRows = tokenLaunchCandidateDecisionRows(launchType, score);
  const normalized = rows
    .filter((row) => row && typeof row === 'object')
    .map((row) => {
      const key = row.key || row.tone || row.label;
      const fallback = fallbackRows.find((item) => item.key === key) || {};
      const riskNotes = row.risk_notes || row.riskNotes || '';
      const proofPolicy = row.proof_policy || row.proofPolicy || '';
      const expectedLabel = launchType === 'presale' ? 'presale' : 'airdrop';
      const contradictsLaunch = riskNotes && /CEO\s+(airdrop|presale)\s+decision/i.test(riskNotes)
        && !new RegExp(`CEO\\s+${expectedLabel}\\s+decision`, 'i').test(riskNotes);
      return {
        key,
        label: fallback.label || row.label || toTitleLabel(row.key || 'CEO decision'),
        tone: row.tone || row.key || fallback.tone || 'evidence',
        proofPolicy: contradictsLaunch ? fallback.proofPolicy : (proofPolicy || fallback.proofPolicy || ''),
        riskNotes: contradictsLaunch ? fallback.riskNotes : (riskNotes || fallback.riskNotes || ''),
      };
    })
    .filter((row) => row.key && row.label);
  return normalized.length ? normalized : fallbackRows;
}
function tokenLaunchCandidateDecisionPreview(rows = [], nextAction = '') {
  const list = Array.isArray(rows) ? rows : [];
  const preferred = list.find((row) => row?.key === 'approve') || list[0] || {};
  if (!preferred.proofPolicy && !preferred.riskNotes) return null;
  return {
    label: preferred.label || 'CEO decision preview',
    proofPolicy: preferred.proofPolicy || 'Review proof policy before opening the token workflow.',
    nextAction: String(nextAction || '').trim(),
    riskNotes: preferred.riskNotes || 'Risk note pending CEO review.',
  };
}
function tokenLaunchCandidateReadinessRows({
  launchType = 'airdrop',
  score = 0,
  openTasks = 0,
  acceptedTasks = 0,
  workPoolMRG = 0,
  signalCount = 0,
} = {}) {
  const numericScore = Number(score) || 0;
  const openCount = Number(openTasks) || 0;
  const acceptedCount = Number(acceptedTasks) || 0;
  const pool = Number(workPoolMRG) || 0;
  const signals = Number(signalCount) || 0;
  const strong = numericScore >= 82;
  if (launchType === 'presale') {
    return [
      { label: 'Utility', value: `${signals || 0} proof signals`, state: signals >= 3 ? 'ready' : 'review' },
      { label: 'Reserve', value: `${formatCompactNumber(pool)} MRG pool`, state: pool >= 50000 ? 'ready' : 'review' },
      { label: 'Contract', value: strong ? 'Solana gates ready' : 'Needs CEO proof', state: strong ? 'ready' : 'hold' },
    ];
  }
  return [
    { label: 'Demand', value: `${openCount} open / ${acceptedCount} accepted`, state: openCount || acceptedCount ? 'ready' : 'review' },
    { label: 'Proof', value: `${signals || 0} signals attached`, state: signals >= 3 ? 'ready' : 'review' },
    { label: 'Anti-bot', value: strong ? 'Wallet gate ready' : 'Needs policy', state: strong ? 'ready' : 'hold' },
  ];
}
function tokenLaunchCandidateReadinessRowsFromAPI(rows = [], fallback = []) {
  if (!Array.isArray(rows) || !rows.length) return fallback;
  const normalized = rows
    .filter((row) => row && typeof row === 'object')
    .map((row) => {
      const state = ['ready', 'review', 'hold'].includes(row.state) ? row.state : 'review';
      return {
        label: row.label || toTitleLabel(row.key || 'Gate'),
        value: row.value || row.evidence || 'CEO review',
        evidence: row.evidence || row.value || '',
        state,
      };
    })
    .filter((row) => row.label && row.value);
  return normalized.length ? normalized.slice(0, 3) : fallback;
}
function tokenLaunchCandidateContextRows(candidate = {}, readinessRows = [], launchType = 'airdrop') {
  const brief = String(candidate.brief || '').trim();
  const proofPolicy = String(candidate.proof_policy || '').trim();
  const source = String(candidate.research_source || '').trim();
  const gates = Array.isArray(readinessRows) ? readinessRows : [];
  const evidence = gates
    .map((gate) => String(gate.evidence || '').trim())
    .filter(Boolean)
    .filter((value, index, values) => values.indexOf(value) === index)
    .slice(0, 2)
    .join(' ');
  const rows = [
    { label: 'CEO brief', value: brief },
    { label: launchType === 'presale' ? 'Policy gates' : 'Proof gates', value: proofPolicy },
    { label: 'Evidence', value: evidence || source },
  ];
  return rows
    .map((row) => ({
      label: row.label,
      value: String(row.value || '').replace(/\s+/g, ' ').trim(),
    }))
    .filter((row) => row.value)
    .slice(0, 3);
}
function tokenLaunchCandidateVerdict({ launchType = 'airdrop', score = 0, readinessRows = [], signalCount = 0, openTasks = 0, acceptedTasks = 0 } = {}) {
  const numericScore = Number(score) || 0;
  const gates = Array.isArray(readinessRows) ? readinessRows : [];
  const holdCount = gates.filter((gate) => String(gate.state || '').toLowerCase() === 'hold').length;
  const reviewCount = gates.filter((gate) => String(gate.state || '').toLowerCase() === 'review').length;
  const readyCount = gates.filter((gate) => String(gate.state || '').toLowerCase() === 'ready').length;
  const signalTotal = Number(signalCount) || 0;
  const demandTotal = (Number(openTasks) || 0) + (Number(acceptedTasks) || 0);
  const launchLabel = launchType === 'presale' ? 'presale' : 'airdrop';
  if (holdCount || numericScore < 68) {
    return {
      tone: 'hold',
      label: `Hold ${launchLabel}`,
      reason: holdCount
        ? `${holdCount} gate needs CEO evidence before launch.`
        : 'Score is below launch threshold; collect stronger source and proof.',
    };
  }
  if (reviewCount || signalTotal < 3 || demandTotal < 1 || numericScore < 82) {
    return {
      tone: 'review',
      label: `Review ${launchLabel}`,
      reason: `${readyCount}/${Math.max(gates.length, 3)} gates ready; attach final proof before opening.`,
    };
  }
  return {
    tone: 'ready',
    label: `Ready ${launchLabel}`,
    reason: `${readyCount}/${Math.max(gates.length, 3)} gates ready with ${signalTotal} proof signals.`,
  };
}
