  const definitions = [
    {
      key: 'escrow-proof',
      title: 'Escrow funding',
      body: 'Payment verification, project reserve, treasury movement, and escrow lock records.',
      icon: ShieldCheck,
      tone: 'blue',
      tab: 'Escrow & Payments',
