      predicate: (item) => /project_funded|payment|reserve|escrow|platform_fee|funding verified/i.test(ledgerProofItemText(item)),
      actionNoun: 'escrow',
    },
    {
      key: 'pr-proof',
      title: 'PR handoff',
      body: 'Submitted reviews, accepted PRs, task claims, and repository workflow events.',
      icon: GitPullRequest,
      tone: 'green',
      tab: 'Tasks & PRs',
      type: 'All types',
      predicate: (item) => String(item.type || '').startsWith('task_') || /pull request|pr accepted|review submitted|workflow event/i.test(ledgerProofItemText(item)),
      actionNoun: 'PRs',
    },
    {
      key: 'ai-proof',
      title: 'AI audit',
      body: 'AI review webhooks and agent action packets tied to routed software work.',
      icon: Bot,
      tone: 'purple',
      tab: 'AI Actions',
      type: 'All types',
      predicate: (item) => /ai_review|agent_action|ai review|agent action|agent proof/i.test(ledgerProofItemText(item)),
      actionNoun: 'AI audit',
    },
    {
      key: 'release-proof',
      title: 'Release proof',
      body: 'Payout releases, auto-release policy evidence, task payments, and manual credits.',
      icon: Trophy,
      tone: 'amber',
      tab: 'Escrow & Payments',
      type: 'All types',
      search: 'payout',
      predicate: (item) => /task_payment|task payout|manual_credit|release|payout|auto_release|agent_release/i.test(ledgerProofItemText(item)),
      actionNoun: 'releases',
    },
  ];

  return definitions.map((lane) => {
    const rows = ledgerEventItems.value.filter((item) => lane.predicate(item));
    const sortedRows = rows.slice().sort((a, b) => new Date(b.created_at || 0) - new Date(a.created_at || 0));
    const latest = sortedRows[0];
    const latestProject = latest ? ledgerProjectFilterLabel(latest) : '';
    const latestTime = latest?.created_at ? formatLedgerDateTime(latest.created_at).time : '';
    return {
      ...lane,
      actionLabel: `${rows.length ? 'View' : 'Open'} ${lane.actionNoun}`,
      ariaLabel: `${rows.length ? 'View' : 'Open'} ${lane.title} lane`,
      count: rows.length,
      countLabel: `${rows.length} event${rows.length === 1 ? '' : 's'}`,
      latestLabel: latest ? `${latestProject} آ· ${latestTime}` : 'Waiting for public proof',
      status: rows.length ? 'Covered' : 'Waiting',
      statusTone: rows.length ? lane.tone : 'slate',
    };
  });
});
const ledgerProofTimelineRows = computed(() =>
  ledgerProofLanes.value
