const publicSystemBlueprintNodes = computed(() =>
  (publicSystemBlueprintCopy.value.nodes || []).map((row, index) => ({
    title: row[0],
    body: row[1],
    icon: publicSystemBlueprintIconRows[index]?.icon || Box,
    tone: publicSystemBlueprintIconRows[index]?.tone || 'green',
  })),
);

