function localizeTextPair(row = {}, pair = []) {
  return {
    ...row,
    label: pair[0] || row.label,
    value: pair[1] || row.value,
    title: pair[0] || row.title,
    body: pair[1] || row.body,
  };
}

function localizeRepositoryArchitecture(section = null, translation = null) {
  if (!section) return null;
  return {
    ...section,
    eyebrow: translation?.eyebrow || section.eyebrow,
    title: translation?.title || section.title,
    body: translation?.body || section.body,
    rows: (section.rows || []).map((row, index) => {
      const translatedRow = translation?.rows?.[index] || {};
      return {
        ...row,
        name: translatedRow.name || row.name,
        role: translatedRow.role || row.role,
        body: translatedRow.body || row.body,
        artifacts: translatedRow.artifacts || row.artifacts,
      };
    }),
  };
}

function localizePublicInfoPage(page = {}, translation = {}) {
  return {
    ...page,
    eyebrow: translation.eyebrow || page.eyebrow,
    title: translation.title || page.title,
    body: translation.body || page.body,
    detailsLabel: translation.detailsLabel || page.detailsLabel || 'Page details',
    flowLabel: translation.flowLabel || page.flowLabel || 'Workflow',
    flowEyebrow: translation.flowEyebrow || page.flowEyebrow || 'Workflow',
    flowTitle: translation.flowTitle || page.flowTitle || '',
    flowBody: translation.flowBody || page.flowBody || '',
    actions: (page.actions || []).map((action, index) => ({
      ...action,
      label: translation.actions?.[index] || action.label,
    })),
    summary: (page.summary || []).map((row, index) => localizeTextPair(row, translation.summary?.[index])),
    features: (page.features || []).map((row, index) => localizeTextPair(row, translation.features?.[index])),
    repositoryArchitecture: localizeRepositoryArchitecture(page.repositoryArchitecture, translation.repositoryArchitecture),
    flow: (page.flow || []).map((row, index) => localizeTextPair(row, translation.flow?.[index])),
  };
}

const publicInfoPage = computed(() => {
  const page = publicInfoPages[publicPage.value];
  if (!page) return null;
  const translations = publicInfoPageTranslations[activeLocale.value] || {};
  const rolePageTranslations = publicPage.value === 'system'
    ? publicSystemInfoPageTranslations[activeLocale.value] || publicSystemInfoPageTranslations['en-US']
    : publicPage.value === 'customers'
    ? publicCustomerInfoPageTranslations[activeLocale.value] || publicCustomerInfoPageTranslations['en-US']
    : publicPage.value === 'agents'
    ? publicAgentInfoPageTranslations[activeLocale.value] || publicAgentInfoPageTranslations['en-US']
    : publicPage.value === 'contributors'
      ? publicContributorInfoPageTranslations[activeLocale.value] || publicContributorInfoPageTranslations['en-US']
      : publicPage.value === 'sdk'
        ? publicSdkInfoPageTranslations[activeLocale.value] || publicSdkInfoPageTranslations['en-US']
        : publicPage.value === 'backend'
          ? publicBackendInfoPageTranslations[activeLocale.value] || publicBackendInfoPageTranslations['en-US']
          : publicPage.value === 'admins'
            ? publicAdminInfoPageTranslations[activeLocale.value] || publicAdminInfoPageTranslations['en-US']
            : {};
  return localizePublicInfoPage(page, translations[publicPage.value] || rolePageTranslations || {});
});

const marketplaceCategories = computed(() => {
  const categories = ['All'];
  const seen = new Set(categories);
  for (const project of marketplaceData.value.projects || []) {
    for (const tag of project.tags || []) {
      const label = toTitleLabel(tag);
      if (!label || seen.has(label)) continue;
      seen.add(label);
      categories.push(label);
    }
  }
  return categories.slice(0, 10);
});
const marketplaceProjectsView = computed(() => {
  const query = marketplaceSearch.value.toLowerCase();
  const active = activeMarketplaceCategory.value;
  return (marketplaceData.value.projects || [])
    .map(mapMarketplaceProject)
    .filter((project) => {
      const matchesCategory = active === 'All' || project.tags.some((tag) => toTitleLabel(tag) === active);
      const matchesSearch = !query || marketplaceSearchHaystack(project).includes(query);
      return matchesCategory && matchesSearch && matchesMarketplaceBudget(project.budgetCents) && matchesMarketplaceDelivery(project);
    });
});
const marketplaceBountiesView = computed(() =>
  (marketplaceData.value.bounties || [])
    .map(mapMarketplaceBounty)
    .filter((bounty) => {
      const query = marketplaceSearch.value.toLowerCase();
      const active = activeMarketplaceCategory.value;
      const matchesSearch = !query || marketplaceBountyHaystack(bounty).includes(query);
      const matchesCategory = active === 'All' || toTitleLabel(bounty.lane) === active || toTitleLabel(bounty.project) === active;
      return matchesSearch && matchesCategory && matchesMarketplaceBudget(bounty.rewardCents);
    })
    .slice(0, 8),
);
const marketplaceFiltersActive = computed(() => Boolean(
  marketplaceSearch.value.trim()
  || activeMarketplaceCategory.value !== 'All'
  || activeMarketplaceBudget.value !== 'Any budget'
  || activeMarketplaceDelivery.value !== 'Any delivery',
));
const marketplaceHasProjectRows = computed(() => (marketplaceData.value.projects || []).length > 0);
const marketplaceHasBountyRows = computed(() => (marketplaceData.value.bounties || []).length > 0);
const marketplaceProjectEmptyState = computed(() => {
  const empty = publicMarketplaceCopy.value.emptyStates;
  if (marketplaceLoading.value) {
    return {
      title: empty.projectsLoading[0],
      body: empty.projectsLoading[1],
    };
  }
  if (marketplaceFiltersActive.value && marketplaceHasProjectRows.value) {
    return {
      title: empty.projectsFiltered[0],
      body: empty.projectsFiltered[1],
    };
  }
  return {
    title: empty.projectsEmpty[0],
    body: empty.projectsEmpty[1],
  };
});
