const publicContributorWorkbenchStats = computed(() => {
  const bountyRows = marketplaceBountiesView.value;
  const contributorRows = marketplaceContributorBoardRows.value;
  const rewardCents = bountyRows.reduce((sum, bounty) => sum + (Number(bounty.rewardCents) || 0), 0);
  const acceptedTasks = contributorRows.reduce((sum, contributor) => sum + (Number(contributor.taskCount) || 0), 0);
  const statRows = publicContributorStatTranslations[activeLocale.value] || publicContributorStatTranslations['en-US'];
  return [
    {
      label: statRows[0]?.[0] || 'Open bounties',
      value: String(bountyRows.length),
      caption: marketplaceLoading.value ? (statRows[0]?.[2] || 'Syncing live tasks') : (statRows[0]?.[1] || 'Contributor-ready tasks'),
      icon: ListTodo,
      tone: 'blue',
    },
    {
      label: statRows[1]?.[0] || 'Reward pool',
      value: formatHomeMRGFromCents(rewardCents),
      caption: statRows[1]?.[1] || 'Escrow-backed public work',
      icon: CircleDollarSign,
      tone: 'green',
    },
    {
      label: statRows[2]?.[0] || 'Contributors',
      value: String(contributorRows.length),
      caption: statRows[2]?.[1] || 'Visible proof profiles',
      icon: UsersRound,
      tone: 'purple',
    },
    {
      label: statRows[3]?.[0] || 'Accepted tasks',
      value: String(acceptedTasks),
      caption: statRows[3]?.[1] || 'Payout and reputation signals',
      icon: Trophy,
      tone: 'amber',
    },
  ];
});

