const marketplaceAgentCapabilityMatrix = computed(() => {
  const base = publicMarketplaceTranslations['en-US'].agentCapabilityMatrix;
  const copy = publicMarketplaceCopy.value.agentCapabilityMatrix || base;
  const rows = Array.isArray(copy.rows) && copy.rows.length ? copy.rows : base.rows;
  return {
    ...base,
    ...copy,
    titleId: 'marketplace-agent-capability-matrix-title',
    rows: marketplaceAgentCapabilityDefinitions.map((definition) => {
      const row = rows.find((item) => item.key === definition.key) || base.rows.find((item) => item.key === definition.key) || {};
      return {
        ...row,
