const publicRepoFactoryCopy = computed(() =>
  publicRepoFactoryTranslations[activeLocale.value] || publicRepoFactoryTranslations['en-US'],
);

const publicRepoFactoryLoading = computed(() =>
  marketplaceLoading.value || agentQueueLoading.value || liveFeedLoading.value || ledgerLoading.value || protocolLoading.value,
);

const publicRepoFactorySummary = computed(() => {
  const stats = marketplaceStats.value || {};
  const bountyRows = Array.isArray(marketplaceData.value.bounties) ? marketplaceData.value.bounties : [];
  const projectRows = Array.isArray(marketplaceData.value.projects) ? marketplaceData.value.projects : [];
  const summary = publicAgentQueueSummary.value;
  const projectCount = Number(stats.project_count) || projectRows.length || 0;
  const bountyCount = Number(stats.open_task_count) || bountyRows.length || summary.bountyCount || 0;
  const taskPacketCount = Math.max(summary.openTaskCount || 0, bountyCount, marketplaceAgentWorkPacketRows.value.length);
  const rewardCents = Number(stats.total_budget_cents)
    || summary.totalRewardCents
    || bountyRows.reduce((sum, bounty) => sum + (Number(bounty.reward_cents) || 0), 0);
  const routeLaneCount = Math.max(summary.agentRows.length, marketplaceData.value.contributors?.length || 0);
  const proofCount = ledgerEventItems.value.length || liveFeedAllItemsView.value.length;
  return {
    projectCount,
    bountyCount,
    taskPacketCount,
    rewardCents,
    routeLaneCount,
    proofCount,
  };
});

const publicRepoFactoryStatus = computed(() => {
  const copy = publicRepoFactoryCopy.value.status;
  if (publicRepoFactoryLoading.value) return { label: copy.syncing, tone: 'blue' };
  if (marketplaceError.value || agentQueueError.value || liveFeedError.value || ledgerError.value || protocolError.value) {
    return { label: copy.review, tone: 'amber' };
  }
  const summary = publicRepoFactorySummary.value;
  if (summary.taskPacketCount || summary.proofCount || summary.rewardCents) return { label: copy.live, tone: 'green' };
  return { label: copy.standby, tone: 'amber' };
});

const publicRepoFactoryStats = computed(() => {
  const copy = publicRepoFactoryCopy.value;
  const summary = publicRepoFactorySummary.value;
  return [
    {
      label: copy.stats[0]?.[0] || 'Repo signals',
      value: String(summary.projectCount),
      caption: copy.stats[0]?.[1] || '',
      icon: GitBranch,
      tone: 'green',
    },
    {
      label: copy.stats[1]?.[0] || 'Task graph',
      value: String(summary.taskPacketCount),
      caption: copy.stats[1]?.[1] || '',
      icon: ListTodo,
      tone: 'blue',
    },
    {
      label: copy.stats[2]?.[0] || 'Funded bounties',
      value: String(summary.bountyCount),
      caption: copy.stats[2]?.[1] || '',
      icon: Bug,
      tone: 'amber',
    },
    {
      label: copy.stats[3]?.[0] || 'Verified escrow',
      value: formatHomeMRGFromCents(summary.rewardCents),
      caption: copy.stats[3]?.[1] || '',
      icon: ShieldCheck,
      tone: 'green',
    },
  ];
});

const publicRepoFactoryPipelineRows = computed(() => {
  const copy = publicRepoFactoryCopy.value;
  const summary = publicRepoFactorySummary.value;
  const signals = copy.signals || publicRepoFactoryTranslations['en-US'].signals;
  const rows = copy.pipeline || publicRepoFactoryTranslations['en-US'].pipeline;
  const values = [
    summary.projectCount,
    summary.bountyCount,
    summary.taskPacketCount,
    formatHomeMRGFromCents(summary.rewardCents),
    summary.bountyCount,
    summary.routeLaneCount,
    summary.proofCount,
  ];
  const active = [
    summary.projectCount > 0,
    summary.bountyCount > 0,
    summary.taskPacketCount > 0,
    summary.rewardCents > 0,
    summary.bountyCount > 0,
    summary.routeLaneCount > 0,
    summary.proofCount > 0,
  ];
  const tones = ['green', 'blue', 'purple', 'amber', 'green', 'blue', 'purple'];
  return rows.map((row, index) => ({
    key: `repo-factory-${index}`,
    sequence: String(index + 1).padStart(2, '0'),
    title: row[0],
    body: row[1],
    signal: `${values[index]} ${signals[index] || ''}`.trim(),
    active: active[index],
    tone: tones[index] || 'green',
  }));
});

const publicRepoFactoryPacketRows = computed(() => {
  const copy = publicRepoFactoryCopy.value;
  const rows = [];
  const seen = new Set();
  const pushPacket = (packet = {}) => {
    const id = String(packet.id || '').trim();
    if (!id || seen.has(id)) return;
    seen.add(id);
    rows.push(packet);
  };

  marketplaceAgentWorkPacketRows.value.forEach((packet) => {
    pushPacket({
      id: `agent-${packet.id}`,
      title: packet.title,
      body: packet.summary,
      meta: `${packet.project} / ${packet.lane} / ${packet.issue}`,
      reward: packet.reward,
      protocolUrl: packet.contextRows?.[0]?.href || publicTaskProtocolURL(packet.id),
      icon: packet.icon || Bot,
      tone: packet.tone || 'purple',
      statusTone: 'purple',
      status: copy.status.agentReady,
    });
  });

  (marketplaceData.value.bounties || []).map(mapMarketplaceBounty).forEach((bounty) => {
    pushPacket({
      id: `bounty-${bounty.id}`,
      title: bounty.title,
      body: bounty.acceptance,
      meta: `${bounty.project} / ${bounty.lane} / ${bounty.issue}`,
      reward: bounty.reward,
      protocolUrl: bounty.protocolUrl,
      icon: bounty.icon || User,
      tone: bounty.tone || 'green',
      statusTone: 'green',
      status: copy.status.claimable,
    });
  });

  return rows.slice(0, 5);
});

const publicRepoFactoryEndpointRows = computed(() => {
  const copy = publicRepoFactoryCopy.value;
  const needles = ['marketplace', 'task', 'bounty', 'agent', 'repo', 'repository', 'workflow', 'ledger', 'live'];
  const rows = protocolEndpointRows.value
    .filter((endpoint) => {
      const haystack = `${endpoint.id} ${endpoint.category} ${endpoint.path} ${endpoint.body}`.toLowerCase();
      return needles.some((needle) => haystack.includes(needle));
    })
    .slice(0, 4)
    .map((endpoint) => ({
      ...endpoint,
      title: toTitleLabel(endpoint.id || endpoint.category || 'Endpoint'),
      body: endpoint.body || '',
    }));
  if (rows.length) return rows;
  return (copy.endpoints || []).map((row, index) => ({
    id: `repo-factory-endpoint-${index}`,
    method: 'GET',
    title: row[0],
    path: row[1],
    body: row[2],
  }));
});

const publicRepoFactoryProofRows = computed(() => {
  const proofNeedles = ['repo', 'repository', 'task', 'bounty', 'escrow', 'payment', 'payout', 'agent', 'ai_review', 'deployment', 'pull request'];
  const liveRows = liveFeedAllItemsView.value
    .filter((item) => {
      const haystack = `${item.rawType} ${item.typeLabel} ${item.title} ${item.body} ${item.project} ${item.reference}`.toLowerCase();
      return proofNeedles.some((needle) => haystack.includes(needle));
    })
    .slice(0, 3)
    .map((item) => ({
      key: `live-${item.id}`,
      title: item.title,
      meta: `${item.typeLabel} / ${item.project} / ${item.time}`,
      reference: item.contractReference || item.reference || publicRepoFactoryCopy.value.proofPendingTitle,
      icon: item.icon || Zap,
      tone: item.tone || 'blue',
    }));
  if (liveRows.length) return liveRows;

  const ledgerRows = ledgerEventItems.value
    .filter((item) => proofNeedles.some((needle) => ledgerProofItemText(item).includes(needle)))
    .slice(0, 3)
    .map((item, index) => {
      const event = mapLedgerTransparencyEvent(item);
      return {
        key: `ledger-${event.key || index}`,
        title: event.type,
        meta: `${event.project} / ${event.time}`,
        reference: event.contractReference || event.ref,
        icon: event.icon || ShieldCheck,
        tone: event.tone || 'green',
      };
    });
  if (ledgerRows.length) return ledgerRows;

  const copy = publicRepoFactoryCopy.value;
  return [{
    key: 'repo-factory-proof-pending',
    title: copy.proofPendingTitle,
    meta: copy.proofPendingMeta,
    reference: copy.proofPendingBody,
    icon: ShieldCheck,
    tone: 'amber',
  }];
});

const marketplaceHeroAgent = computed(() => marketplaceAgentsView.value[0] || {
  type: 'empty-agent',
  icon: Bot,
  title: publicMarketplaceCopy.value.agentFallback.title,
  body: publicMarketplaceCopy.value.agentFallback.body,
  tone: 'green',
});
function agentPresenceCaption(agent = {}) {
  const capacity = Number(agent.capacity) || 0;
  if (capacity <= 0) return '';
  const availableSlots = Math.max(0, Number(agent.available_slots) || 0);
  const currentLoad = Math.max(0, Number(agent.current_load) || 0);
  const labels = publicMarketplaceCopy.value.agentFallback;
  const slotsLabel = availableSlots > 0 ? `${availableSlots}/${capacity} ${labels.slotsFree}` : `${currentLoad}/${capacity} ${labels.slotsBusy}`;
  const heartbeatLabel = agent.last_heartbeat_at ? ` - ${labels.heartbeat} ${formatLedgerDateTime(agent.last_heartbeat_at).time}` : '';
  return `${slotsLabel}${heartbeatLabel}`;
}

function marketplaceAgentCapabilities(agent = {}) {
  const labels = publicMarketplaceCopy.value.agentCapabilities || publicMarketplaceTranslations['en-US'].agentCapabilities;
  const haystack = [
    agent.type,
    agent.title,
    agent.body,
    agent.displayBody,
    agent.capability,
    ...(agent.labels || []),
  ].filter(Boolean).join(' ').toLowerCase();
  const definitions = [
    {
      key: 'review',
      icon: Eye,
      keywords: ['review', 'reviews', 'pr', 'pull request', 'acceptance', 'audit'],
    },
    {
      key: 'test',
      icon: CheckCircle2,
      keywords: ['test', 'tests', 'qa', 'smoke', 'validation', 'accessibility'],
    },
    {
      key: 'generate',
      icon: Sparkles,
      keywords: ['generate', 'scans', 'scan', 'groups', 'prepares', 'produces', 'task', 'design-system'],
    },
    {
      key: 'deploy',
      icon: Rocket,
      keywords: ['deploy', 'deployment', 'release', 'environment', 'devops', 'handoff'],
    },
    {
      key: 'secure',
      icon: ShieldCheck,
      keywords: ['security', 'secret', 'auth', 'payment', 'token', 'permission', 'hygiene'],
    },
    {
      key: 'code',
      icon: Code2,
      keywords: ['code', 'api', 'backend', 'frontend', 'vue', 'ui', 'implementation', 'implements', 'builds', 'go'],
    },
  ];
  return definitions.map((definition) => ({
    key: definition.key,
    label: labels[definition.key] || toTitleLabel(definition.key),
    icon: definition.icon,
    active: definition.key === 'generate'
      ? definition.keywords.some((keyword) => haystack.includes(keyword)) || haystack.includes('agent')
      : definition.keywords.some((keyword) => haystack.includes(keyword)),
  }));
}
const customerDashboardStats = computed(() => customerDashboardSnapshot.value?.stats || {});
const customerDashboardSignals = computed(() => {
  const selectedProjectID = selectedDashboardProjectID.value;
  return (customerDashboardSnapshot.value?.signals || [])
    .filter((signal) => !selectedProjectID || !signal.project_id || signal.project_id === selectedProjectID)
    .slice(0, 8)
    .map(mapCustomerDashboardSignal);
});
const customerDashboardProtocolView = computed(() => {
  const snapshot = customerDashboardSnapshot.value || {};
  const stats = snapshot.stats || {};
  const updatedAt = stats.updated_at || (snapshot.projects || [])[0]?.updated_at || '';
  return {
    version: snapshot.protocol_version || 'mergeos.customer.dashboard.v1',
    kind: snapshot.kind || 'customer_dashboard',
    status: dashboardLoading.value ? 'Syncing' : 'Protocol',
    updated: updatedAt ? formatLedgerDateTime(updatedAt).full : 'Waiting for data',
    projects: Number(stats.project_count) || dashboardProjectList.value.length,
    tasks: (Number(stats.open_task_count) || 0) + (Number(stats.claimed_task_count) || 0) + (Number(stats.submitted_task_count) || 0) + (Number(stats.accepted_task_count) || 0),
    ledger: Number(stats.ledger_entry_count) || dashboardLedgerEntries.value.length,
  };
});
const dashboardSortedProjects = computed(() =>
  dashboardProjects.value.slice().sort((a, b) => new Date(b.created_at || 0) - new Date(a.created_at || 0)),
);
const isAdminUser = computed(() => user.value?.role === 'admin');
const dashboardProjectList = computed(() => {
  const query = dashboardSearch.value.toLowerCase();
  if (!query) return dashboardSortedProjects.value;
  return dashboardSortedProjects.value.filter((project) => [
    project.title,
    project.brief,
    project.company_name,
    project.client_name,
    project.bounty_repo_name,
    project.repo_provider,
    ...(project.reference_attachments || []).map((attachment) => attachment.original_name),
  ].filter(Boolean).join(' ').toLowerCase().includes(query));
});
