  { label: 'Scan findings', value: String(dashboardRepositoryFindingRows.value.length), tone: dashboardRepositoryFindingRows.value.length ? 'amber' : 'green' },
  { label: 'Routes', value: String(dashboardRoutingRouteRows.value.length), tone: 'blue' },
