  if (dashboardRepositoryIntelligenceError.value) {
    return {
      status: 'Error',
      body: dashboardRepositoryIntelligenceError.value,
    };
  }
  if (dashboardRepositoryIntelligenceLoading.value && !dashboardRepositoryScan.value && !dashboardTaskGraph.value) {
    return {
      status: 'Syncing',
      body: 'Scanning repository signals and dependency-aware task readiness.',
    };
  }
  if (!dashboardRepositoryScan.value && !dashboardTaskGraph.value) {
    return {
      status: 'Waiting',
      body: 'No repository intelligence payload loaded yet.',
    };
  }
  const findings = Number(dashboardRepositoryScanStats.value.finding_count) || 0;
  const graph = dashboardTaskGraphStats.value;
  const repo = dashboardRepositoryScanRepositoryLabel.value && dashboardRepositoryScanRepositoryLabel.value !== 'No repo yet'
    ? `${dashboardRepositoryScanRepositoryLabel.value}: `
    : '';
  return {
    status: findings ? `${findings} findings` : 'Clear',
    body: `${repo}${dashboardRepositoryScan.value?.summary || 'Repository scan loaded.'} ${Number(graph.ready_count) || 0}/${Number(graph.open_count) || 0} open tasks are ready.`,
  };
});
