const dashboardAgentQueueRows = computed(() => {
  const query = dashboardSearch.value.toLowerCase();
  return (agentQueueData.value.tasks || [])
    .map((task, index) => {
      const bountyID = task.bounty_id || task.id || `${task.project_id || 'project'}:${task.issue_number || index}`;
      const agentType = task.agent_type || '';
      const workerKind = task.worker_kind || 'agent';
      const evidence = Array.isArray(task.evidence_required) ? task.evidence_required : [];
      const workPacket = task.work_packet || {};
      const contextUrls = workPacket.context_urls || {};
      const runbook = Array.isArray(workPacket.runbook) ? workPacket.runbook : [];
      const actionPayloads = Array.isArray(workPacket.action_payloads) ? workPacket.action_payloads : [];
      const submitEndpoint = workPacket.submit_endpoint || contextUrls.submit || `/api/tasks/${bountyID}/submit`;
      const actionRows = actionPayloads.slice(0, 3).map((actionRow, actionIndex) => {
        const body = actionRow?.body || {};
        const action = body.action || actionRow?.action || `action-${actionIndex + 1}`;
        const label = actionRow?.label || toTitleLabel(action);
        return {
          key: `${bountyID}:${action}:${actionIndex}`,
          action,
          label,
          shortLabel: label.length > 18 ? toTitleLabel(action) : label,
          body,
          endpoint: workPacket.action_endpoint || task.action_endpoint || '/api/agents/actions',
        };
      });
      const firstAction = actionRows[0] || null;
      const nextRunbookStep = runbook.find((step) => step?.action && step.action !== 'fetch_context') || runbook[0] || null;
      const lease = agentLeaseResponses[bountyID] || null;
      const packetRows = [
        { label: 'Claim', value: shortAgentEndpoint(workPacket.claim_endpoint || task.claim_endpoint || `/api/tasks/${bountyID}/claim`) },
        ...(lease ? [{ label: 'Lease', value: shortAgentEndpoint(lease.lease_id || '') }] : []),
        { label: 'Actions', value: `${actionPayloads.length} payload${actionPayloads.length === 1 ? '' : 's'}` },
        { label: 'Submit', value: shortAgentEndpoint(submitEndpoint) },
      ];
      const runbookRows = runbook.slice(0, 4).map((step, stepIndex) => ({
        key: `${bountyID}:runbook:${step?.step || stepIndex + 1}`,
        step: Number(step?.step) || stepIndex + 1,
        label: trimMarketplaceText(step?.label || toTitleLabel(step?.action || 'runbook step'), 'Runbook step.'),
        method: String(step?.method || 'GET').toUpperCase(),
        endpoint: shortAgentEndpoint(step?.endpoint || ''),
      }));
      return {
        id: bountyID,
        projectID: task.project_id || '',
        issue: task.issue_number ? `#${task.issue_number}` : 'Task',
        title: task.title || 'Agent task',
        project: task.project_title || 'MergeOS project',
        summary: trimMarketplaceText(task.summary, 'Protocol-ready task for an AI agent lane.'),
        reward: formatPublicMRGFromCents(task.reward_cents),
        rewardCents: Number(task.reward_cents) || 0,
        lane: agentType ? toTitleLabel(agentType) : toTitleLabel(workerKind),
        workerKind,
        agentType,
        readiness: toTitleLabel(task.readiness || 'agent_ready'),
        protocolUrl: absolutePublicPath(contextUrls.task_protocol || task.protocol_url || publicTaskProtocolPath(bountyID)),
        workflowUrl: contextUrls.workflow_protocol ? absolutePublicPath(contextUrls.workflow_protocol) : publicProjectWorkflowURL(task.project_id),
        deploymentUrl: task.project_id ? absolutePublicPath(contextUrls.deployment || `/api/public/projects/${encodeURIComponent(task.project_id)}/deployment`) : '',
        claimEndpoint: task.claim_endpoint || `/api/tasks/${bountyID}/claim`,
        actionEndpoint: task.action_endpoint || '/api/agents/actions',
        evidence: evidence.map(toTitleLabel).join(', ') || 'Tests',
        nextAction: nextRunbookStep?.label ? `Runbook: ${runbook.length} steps - Next: ${nextRunbookStep.label}` : firstAction?.label ? `Next: ${firstAction.label}` : '',
        actionRows,
        packetRows,
        runbookRows,
        runbook,
        workPacket,
        lease,
