function initialsFor(value = '') {
  const parts = value
    .replace(/@.*/, '')
    .split(/[\s._-]+/)
    .filter(Boolean);
  const letters = parts.length > 1
    ? `${parts[0][0]}${parts[1][0]}`
    : (parts[0] || 'MR').slice(0, 2);
  return letters.toUpperCase();
}

function shortWallet(value = '') {
  const address = String(value || '').trim();
  if (address.length <= 14) return address || 'Solana MRG wallet';
  return `${address.slice(0, 6)}...${address.slice(-6)}`;
}

function normalizeFrontendWalletAddress(value = '') {
  return String(value || '')
    .trim()
    .replace(/^wallet:/i, '')
    .replace(/^solana:/i, '')
    .replace(/^sol:/i, '');
}

function normalizeFrontendGitHubUsername(value = '') {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/^github:/i, '')
    .replace(/^@/, '')
    .replace(/^\/+|\/+$/g, '');
}

function claimWorkerIDForProfile(profile = user.value) {
  const source = profile || {};
  const github = normalizeFrontendGitHubUsername(source.github_username || source.githubUsername);
  if (github) return `github:${github}`;
  const wallet = normalizeFrontendWalletAddress(source.wallet_address || source.walletAddress);
  if (wallet) return wallet;
  return String(source.id || source.user_id || source.userID || '').trim();
}

function formatClaimWorkerID(value = '') {
  const workerID = String(value || '').trim();
  if (!workerID || workerID === 'current-user') {
    return user.value ? 'Current session' : 'Sign in to attach identity';
  }
  if (workerID.toLowerCase().startsWith('github:')) return workerID;
  if (/^[1-9A-HJ-NP-Za-km-z]{32,44}$/.test(workerID)) return shortWallet(workerID);
  return shortLedgerReference(workerID);
}

function workerAuditRiskTone(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (['critical', 'high', 'blocked'].includes(normalized)) return 'red';
  if (['medium', 'elevated', 'review'].includes(normalized)) return 'amber';
  if (['low', 'clear', 'trusted', 'none'].includes(normalized)) return 'green';
  return 'slate';
}

function randomOAuthState() {
  if (hasWindow && window.crypto?.getRandomValues) {
    const bytes = new Uint8Array(16);
    window.crypto.getRandomValues(bytes);
    return Array.from(bytes, (byte) => byte.toString(16).padStart(2, '0')).join('');
  }
  return `${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

function openWalletOnScan(address = '') {
  const wallet = String(address || '').trim();
  if (!wallet || !hasWindow) return;
  window.open(`https://scan.mergeos.shop/address/${encodeURIComponent(wallet)}`, '_blank', 'noopener,noreferrer');
}

async function submitWalletMigration() {
  if (!user.value) {
    showToast('Log in to migrate a legacy wallet.');
    return;
  }
  const legacyAddress = walletMigrationForm.legacy_address.trim();
  if (!legacyAddress) {
    walletMigrationError.value = 'Legacy wallet address is required.';
    return;
  }
  walletMigrationBusy.value = true;
  walletMigrationError.value = '';
  try {
    const migration = await api('/api/wallets/migrations', {
      method: 'POST',
      body: JSON.stringify({
        legacy_chain: walletMigrationForm.legacy_chain,
        legacy_address: legacyAddress,
      }),
    });
    walletMigrationResult.value = migration;
    if (migration.target_address && user.value) {
      user.value = {
        ...user.value,
        wallet_address: migration.target_address,
      };
    }
    walletMigrationForm.legacy_address = '';
    showToast('Legacy wallet linked to a Solana MRG wallet.');
  } catch (error) {
    walletMigrationError.value = error.message || 'Could not migrate wallet.';
    showToast(walletMigrationError.value);
  } finally {
    walletMigrationBusy.value = false;
  }
}

function openExternalURL(url = '') {
  const target = String(url || '').trim();
  if (!target || !hasWindow) return;
  if (/^https?:\/\//i.test(target)) {
    window.open(target, '_blank', 'noopener,noreferrer');
    return;
  }
  if (target.startsWith('/')) {
    window.open(new URL(target, window.location.origin).toString(), '_blank', 'noopener,noreferrer');
  }
}

async function copyTextToClipboard(value = '') {
  const text = String(value || '').trim();
  if (!text) return false;
  try {
    await navigator.clipboard?.writeText(text);
    return true;
  } catch {
    return false;
  }
}

async function copyProtocolManifestURL() {
  const copied = await copyTextToClipboard(protocolManifestURL.value);
  showToast(copied ? 'Protocol manifest URL copied.' : `Manifest ${publicProtocolManifestPath}`);
}

async function copyPublicAgentContext(context = {}) {
  const reference = context.value || '';
  if (!reference) {
    showToast('No agent context URL available.');
    return;
  }
  const copied = await copyTextToClipboard(reference);
  showToast(copied ? `${context.label || 'Agent context'} URL copied.` : reference);
}

async function copyPublicAgentActionContract(contract = {}) {
  const payload = {
    action: contract.action || '',
    endpoint: contract.endpoint || '/api/projects/{id}/agent-actions',
    output_protocol: contract.outputProtocol || 'mergeos.agent-action.v1',
    proof: contract.proof || '',
    schema: '/protocol/agent-action.v1.schema.json',
  };
  const copied = await copyTextToClipboard(JSON.stringify(payload, null, 2));
  showToast(copied ? `${contract.label || 'Agent action'} contract copied.` : 'Agent action contract is visible on the page.');
}

async function copyProtocolDocumentReference(doc = {}) {
  const reference = doc.schema || doc.endpoint || doc.version || doc.id || '';
  if (!reference) {
    showToast('No protocol reference available.');
    return;
  }
  const copied = await copyTextToClipboard(reference);
  showToast(copied ? 'Protocol reference copied.' : reference);
}

async function copyProtocolEndpoint(endpoint = {}) {
  const reference = [endpoint.method, endpoint.path].filter(Boolean).join(' ');
  if (!reference) {
    showToast('No protocol endpoint available.');
    return;
  }
  const copied = await copyTextToClipboard(reference);
  showToast(copied ? 'Protocol endpoint copied.' : reference);
}

async function copyProtocolContextURL(context = {}) {
  const reference = context.value || '';
  if (!reference) {
    showToast('No context URL available.');
    return;
  }
  const copied = await copyTextToClipboard(reference);
  showToast(copied ? 'Context URL copied.' : reference);
}

async function copyProtocolRunbook() {
  const text = protocolRunbookRows.value.map((step, index) => `${index + 1}. ${step}`).join('\n');
  const copied = await copyTextToClipboard(text);
  showToast(copied ? 'Protocol runbook copied.' : 'Protocol runbook is visible on the page.');
}

function publicSdkKitPayloadText() {
  return JSON.stringify({
    package: '@mergeos/sdk',
    protocol_index: protocolManifestURL.value,
    websocket: absolutePublicPath('/api/ws'),
    surfaces: publicSdkKitRows.value.map((row) => ({
      key: row.key,
      title: row.title,
      reference: row.value,
    })),
    endpoints: publicSdkEndpointRows.value.map((endpoint) => ({
      method: endpoint.method,
      path: endpoint.path,
      title: endpoint.title,
      category: endpoint.category,
    })),
    snippets: publicSdkSnippetRows.value.map((snippet) => ({
      key: snippet.key,
      title: snippet.title,
      code: snippet.code,
    })),
