async function startGitHubLogin() {
  if (!hasWindow) return;
  errorMessage.value = '';
  const cfg = await loadRuntimeConfig();
  if (!cfg.github_oauth_ready || !cfg.github_oauth_client_id) {
    errorMessage.value = 'GitHub App login is not configured yet.';
    showToast(errorMessage.value);
    return;
  }

  const state = randomOAuthState();
  const redirectURI = `${window.location.origin}${window.location.pathname}`;
  window.sessionStorage.setItem('mergeos_github_oauth_state', state);
  window.sessionStorage.setItem('mergeos_github_oauth_redirect', redirectURI);
  const params = new URLSearchParams({
    client_id: cfg.github_oauth_client_id,
    redirect_uri: redirectURI,
    state,
  });
  window.location.href = `https://github.com/login/oauth/authorize?${params.toString()}`;
}

async function handleGitHubCallback() {
  if (!hasWindow) return false;
  const params = new URLSearchParams(window.location.search);
  const code = params.get('code');
  const state = params.get('state');
  if (!code) return false;

  const expectedState = window.sessionStorage.getItem('mergeos_github_oauth_state') || '';
  const redirectURI = window.sessionStorage.getItem('mergeos_github_oauth_redirect') || `${window.location.origin}${window.location.pathname}`;
  window.sessionStorage.removeItem('mergeos_github_oauth_state');
  window.sessionStorage.removeItem('mergeos_github_oauth_redirect');
  window.history.replaceState({ publicPage: publicPage.value }, '', window.location.pathname || '/');

  if (!expectedState || state !== expectedState) {
    errorMessage.value = 'GitHub sign-in state did not match. Please try again.';
    showToast(errorMessage.value);
    return true;
  }

  authBusy.value = true;
  try {
    const auth = await publicApi('/api/auth/github', {
      method: 'POST',
      body: JSON.stringify({ code, redirect_uri: redirectURI }),
    });
    setSession(auth);
    showToast(auth.user?.wallet_address ? 'GitHub linked to your Solana MRG wallet.' : 'Logged in with GitHub.');
  } catch (error) {
    errorMessage.value = error.message;
    showToast(error.message);
  } finally {
    authBusy.value = false;
  }
  return true;
}

function handlePasswordResetToken() {
  if (!hasWindow) return false;
  const params = new URLSearchParams(window.location.search);
  const resetToken = params.get('reset_token');
  if (!resetToken) return false;
  params.delete('reset_token');
  params.delete('auth');
  const cleanQuery = params.toString();
  const cleanUrl = `${window.location.pathname || '/'}${cleanQuery ? `?${cleanQuery}` : ''}${window.location.hash || ''}`;
  window.history.replaceState({ publicPage: publicPage.value }, '', cleanUrl);
  resetAuthForm('reset-confirm');
  authMode.value = 'reset-confirm';
  authForm.reset_token = resetToken;
  authVisible.value = true;
  authNotice.value = 'Enter a new password to finish resetting your account.';
  showToast('Password reset token loaded.');
  return true;
}

function isPayPalCheckoutPath(path = hasWindow ? window.location.pathname : '') {
  const normalized = normalizeRoutePath(path);
  return normalized === '/paypal/return' || normalized === '/paypal/cancel';
}

function cleanPayPalCheckoutURL() {
  if (!hasWindow) return;
  window.history.replaceState({}, document.title, '/');
}

async function handlePayPalCheckoutReturn() {
  if (!hasWindow || !isPayPalCheckoutPath()) return false;
  const path = normalizeRoutePath(window.location.pathname);
  const params = new URLSearchParams(window.location.search);
  const pendingProject = readPendingProjectFunding();
  const pendingRepositoryTask = readPendingRepositoryTaskFunding();
  const flow = params.get('flow') || pendingProject?.flow || pendingRepositoryTask?.flow || '';
  if (flow === 'project_funding' || (pendingProject && !pendingRepositoryTask)) {
    return handleProjectPayPalCheckoutReturn(path, params, pendingProject);
  }
  return handleRepositoryTaskPayPalCheckoutReturn(path, params, pendingRepositoryTask);
}

async function handleProjectPayPalCheckoutReturn(path, params, pending) {
  if (!pending || pending.flow !== 'project_funding' || !pending.payload) {
    cleanPayPalCheckoutURL();
    showToast('No pending project checkout was found.');
    return true;
  }
  if (path === '/paypal/cancel') {
    clearPendingProjectFunding();
    cleanPayPalCheckoutURL();
    showToast('Project checkout cancelled.');
    return true;
  }

  const orderID = params.get('token') || params.get('order_id') || pending.orderID || '';
  if (!orderID) {
    showToast('PayPal order reference is missing.');
    return true;
  }
  if (!user.value) {
    writePendingProjectFunding({ ...pending, orderID });
    showToast('Log in to finish PayPal capture.');
    openAuth('login');
    return true;
  }

  projectPaymentBusy.value = true;
  projectWizardVisible.value = true;
  projectWizardStage.value = 'funding';
  projectWizardStep.value = 4;
  try {
    await submitProjectFunding({
      ...pending.payload,
      payment_method: 'paypal',
      payment_reference: orderID,
    }, {
      fundingAmount: pending.fundingAmount,
      paymentMethodLabel: pending.paymentMethodLabel || 'PayPal',
      replacePath: true,
    });
    clearPendingProjectFunding();
  } catch (error) {
    projectPaymentError.value = error.message || 'Could not finish PayPal capture.';
    showToast(error.message || 'Could not finish PayPal capture.');
  } finally {
    projectPaymentBusy.value = false;
  }
  return true;
}

async function handleRepositoryTaskPayPalCheckoutReturn(path, params, pending) {
  if (!pending || pending.flow !== 'repo_task_funding') {
    cleanPayPalCheckoutURL();
    showToast('No pending repository task checkout was found.');
    return true;
  }
  if (path === '/paypal/cancel') {
    clearPendingRepositoryTaskFunding();
    cleanPayPalCheckoutURL();
    if (user.value) openDashboardSection('issue-scanner');
    showToast('Repository task checkout cancelled.');
    return true;
  }

  const orderID = params.get('token') || params.get('order_id') || pending.orderID || '';
  if (!orderID) {
    showToast('PayPal order reference is missing.');
    return true;
  }
  if (!user.value) {
    writePendingRepositoryTaskFunding({ ...pending, orderID });
    showToast('Log in to finish PayPal capture.');
    openAuth('login');
    return true;
  }

  fundingSuggestedTaskID.value = pending.taskID || '';
  try {
    await submitRepositorySuggestedTaskFundingRequest(pending.projectID, pending.taskID, pending.rewardCents, 'paypal', orderID);
    clearPendingRepositoryTaskFunding();
    cleanPayPalCheckoutURL();
    openDashboardSection('issue-scanner');
  } catch (error) {
    if (/already funded/i.test(error.message || '')) {
      clearPendingRepositoryTaskFunding();
      cleanPayPalCheckoutURL();
    }
    showToast(error.message || 'Could not finish PayPal capture.');
  } finally {
    fundingSuggestedTaskID.value = '';
  }
  return true;
}

function showToast(message) {
  toastMessage.value = message;
  pushPublicNotification(message);
  if (!hasWindow) return;
  if (toastTimer) window.clearTimeout(toastTimer);
  toastTimer = window.setTimeout(() => {
    toastMessage.value = '';
  }, 2200);
}

function clearToast() {
  toastMessage.value = '';
  if (hasWindow && toastTimer) {
    window.clearTimeout(toastTimer);
    toastTimer = 0;
  }
}

function pushPublicNotification(message) {
  if (!message || (user.value && !publicModeVisible.value && !projectWizardVisible.value)) return;
  const createdAt = new Date().toISOString();
  const body = projectWizardVisible.value ? 'Project setup status changed.' : 'Public session status changed.';
  publicNotifications.value = [
    {
      id: `public-${Date.now()}`,
      subject: String(message),
      body,
      meta: formatLedgerDateTime(createdAt).full,
      tone: projectWizardVisible.value ? 'green' : 'blue',
      createdAt,
    },
    ...publicNotifications.value,
  ].slice(0, 6);
}

function scrollToSection(id) {
  if (!hasWindow) return;
  const section = document.getElementById(id);
  if (section) {
    section.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }
}

function scheduleScrollToSection(id) {
  if (!hasWindow) return;
  void nextTick().then(() => {
    window.requestAnimationFrame(() => {
      window.requestAnimationFrame(() => scrollToSection(id));
      window.setTimeout(() => scrollToSection(id), 350);
      window.setTimeout(() => scrollToSection(id), 800);
    });
  });
}

async function loadTokenLaunchCandidates(launchType = '') {
  tokenLaunchCandidatesLoading.value = true;
  tokenLaunchCandidatesError.value = '';
  try {
    const launchCandidates = await publicApi(tokenLaunchCandidateAPIPath(launchType));
    tokenLaunchCandidatesData.value = launchCandidates && typeof launchCandidates === 'object'
      ? {
          stats: launchCandidates.stats || {},
          candidates: Array.isArray(launchCandidates.candidates) ? launchCandidates.candidates : [],
        }
      : { stats: {}, candidates: [] };
  } catch (error) {
    tokenLaunchCandidatesData.value = { stats: {}, candidates: [] };
    tokenLaunchCandidatesError.value = error?.message || 'CEO candidate queue is temporarily unavailable.';
  } finally {
    tokenLaunchCandidatesLoading.value = false;
  }
}

function loadPublicPageData(page) {
  if (page === 'ledger') {
    void loadLedgerData();
    return;
  }
  if (page === 'live') {
    void loadLiveFeedData();
    void loadMarketplaceData({ silent: true });
    void loadLedgerData({ silent: true });
    return;
  }
  if (page === 'protocol' || page === 'sdk') {
    void loadProtocolManifest();
    return;
  }
  if (page === 'contracts') {
    void loadLedgerData();
    return;
  }
  if (page === 'airdrop' || page === 'presale' || page === 'whitepaper') {
    void loadMarketplaceData({ silent: true });
    void loadLedgerData({ silent: true });
    void loadLiveFeedData({ silent: true });
    void loadProtocolManifest({ silent: true });
    if (page === 'airdrop' || page === 'presale') void loadTokenLaunchCandidates(page);
    if (page === 'airdrop') void loadAirdropMissions();
    if (page === 'presale') void loadRuntimeConfig().catch(() => {});
    return;
  }
  if (page === 'backend') {
    void loadProtocolManifest();
    void loadRuntimeConfig().catch(() => {});
    void loadMarketplaceData({ silent: true });
    void loadLedgerData({ silent: true });
    void loadLiveFeedData({ silent: true });
    return;
  }
  if (page === 'product') {
    void loadMarketplaceData({ silent: true });
    void loadLedgerData({ silent: true });
    void loadLiveFeedData({ silent: true });
    void loadProtocolManifest({ silent: true });
    return;
  }
  if (page === 'solutions' || page === 'agents') {
    void loadMarketplaceData({ silent: true });
    void loadLedgerData({ silent: true });
    void loadLiveFeedData({ silent: true });
    void loadProtocolManifest({ silent: true });
    return;
  }
  if (page === 'admins') {
    void loadMarketplaceData({ silent: true });
    void loadLedgerData({ silent: true });
    void loadLiveFeedData({ silent: true });
    if (isAdminUser.value) void loadAdminConsoleData({ silent: true });
    return;
  }
  if (page === 'marketplace' || page === 'home' || page === 'contributors' || page === 'customers') {
    void loadMarketplaceData({ silent: true });
    void loadLedgerData({ silent: true });
    void loadLiveFeedData({ silent: true });
  }
}

function refreshPublicRepoFactory() {
  void loadMarketplaceData();
  void loadLedgerData({ silent: true });
  void loadLiveFeedData({ silent: true });
  void loadProtocolManifest({ silent: true });
}

function refreshPublicSolutionRouter() {
  void loadMarketplaceData();
  void loadLedgerData({ silent: true });
  void loadLiveFeedData({ silent: true });
  void loadProtocolManifest({ silent: true });
}

function refreshPublicAdminOps() {
  void loadMarketplaceData({ silent: true });
  void loadLedgerData();
  void loadLiveFeedData({ silent: true });
  if (isAdminUser.value) void loadAdminConsoleData({ silent: true });
}

function refreshTokenPageData() {
  void loadMarketplaceData({ silent: true });
  void loadLedgerData();
  void loadLiveFeedData({ silent: true });
  void loadProtocolManifest({ silent: true });
  if (publicPage.value === 'airdrop') void loadAirdropMissions();
  if (publicPage.value === 'presale') void loadRuntimeConfig().catch(() => {});
}

function updatePublicBrowserPath(page, replace = false) {
  if (!hasWindow) return;
  const targetPath = publicPathForPage(page);
  const currentPath = normalizeRoutePath(window.location.pathname);
  if (currentPath === targetPath && !window.location.search && !window.location.hash) {
    return;
  }
  const method = replace ? 'replaceState' : 'pushState';
  window.history[method]({ publicPage: page }, '', targetPath);
}

function updateProjectWizardBrowserPath(replace = false) {
  if (!hasWindow) return;
  const targetPath = projectWizardPathForState(projectWizardStage.value, projectWizardStep.value);
  const currentPath = normalizeRoutePath(window.location.pathname);
  if (currentPath === targetPath && !window.location.search && !window.location.hash) {
    return;
  }
  const method = replace ? 'replaceState' : 'pushState';
  window.history[method](
    { projectWizard: true, stage: projectWizardStage.value, step: projectWizardStep.value },
    '',
    targetPath,
  );
}

function openPublicPage(page, options = {}) {
  closeNavContextMenu();
  publicModeVisible.value = true;
  projectWizardVisible.value = false;
  const nextPage = normalizePublicPage(page);
  publicPage.value = nextPage;
  loadPublicPageData(nextPage);
  updatePublicBrowserPath(nextPage, Boolean(options.replace));
  if (!hasWindow) return;
  if (options.scroll === false) return;
  window.requestAnimationFrame(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  });
}

function syncPublicPageFromBrowserPath() {
  if (!hasWindow) return;
  publicModeVisible.value = true;
  const wizardRoute = projectWizardRouteFromPath(window.location.pathname);
  if (wizardRoute) {
    projectWizardVisible.value = true;
    projectWizardStage.value = wizardRoute.stage;
    projectWizardStep.value = wizardRoute.step;
    guardProjectWizardRouteValidation({ replace: true });
    return;
  }
  projectWizardVisible.value = false;
  const nextPage = publicPageFromPath(window.location.pathname);
  publicPage.value = nextPage;
  loadPublicPageData(nextPage);
}

function handlePublicAction(action = {}) {
  closeNavContextMenu();
  if (action.command === 'project') {
    openProjectWizard();
    return;
  }
  if (action.command === 'token-ceo-brief') {
    openProjectWizard({ intent: 'token-launch' });
    return;
  }
  if (action.command === 'token-launch-brief') {
    prefillTokenLaunchBrief();
    void nextTick().then(() => scrollTokenLaunchBriefCardIntoView());
    if (hasWindow) window.setTimeout(scrollTokenLaunchBriefCardIntoView, 220);
    return;
  }
  if (action.command === 'copy-whitepaper') {
    void copyWhitepaperOutline();
    return;
  }
  if (action.command === 'download-whitepaper') {
    downloadWhitepaper();
    return;
  }
  if (action.command === 'airdrop-claim' || action.command === 'presale-reserve') {
    scheduleScrollToSection('token-workflow');
    return;
  }
  if (action.command === 'auth-register') {
    openAuth('register');
    return;
  }
  if (action.command === 'repo-import') {
    openRepositoryImportEntry();
    return;
  }
  if (action.command === 'issue-scanner') {
    openIssueScannerEntry();
    return;
  }
  if (action.command === 'estimate') {
    openProjectEstimateEntry();
    return;
  }
  if (action.command === 'escrow-payments') {
    openEscrowPaymentsEntry();
    return;
  }
  if (action.command === 'pr-monitor') {
    openPRMonitorEntry();
    return;
  }
  if (action.command === 'deployment-gates') {
    openDeploymentGatesEntry();
    return;
  }
  if (action.command === 'bounties') {
    openBountyExplorerEntry();
    return;
  }
  if (action.command === 'agents') {
    openAgentLanesEntry();
    return;
  }
  if (action.command === 'contributors') {
    openContributorMarketplaceEntry();
    return;
  }
  if (action.command === 'admin-ops') {
    openAdminOpsEntry();
    return;
  }
  if (action.url) {
    openExternalURL(action.url);
    return;
  }
  if (action.page) {
    openPublicPage(action.page);
    return;
  }
  showToast(action.label ? `${action.label} opened.` : 'Opening page...');
}

async function copyWhitepaperOutline() {
  const sections = publicTokenTimelineRows.value
    .map((row, index) => `${index + 1}. ${row.title}\n${row.body}`)
    .join('\n\n');
  const chapters = publicTokenChapterRows.value
    .map((row) => `- ${row.title}: ${row.body}`)
    .join('\n');
  const text = [
    'MergeOS Whitepaper',
    publicTokenPageDefinitions.whitepaper.body,
    '',
    'Outline',
    sections,
    '',
    'Chapters',
    chapters,
    '',
    `Protocol: ${absolutePublicPath(publicPathForPage('protocol'))}`,
    `Contracts: ${absolutePublicPath(publicPathForPage('contracts'))}`,
    `Ledger: ${absolutePublicPath(publicPathForPage('ledger'))}`,
    `Full paper: ${absolutePublicPath(whitepaperDownloadPath)}`,
  ].join('\n');
  const copied = await copyTextToClipboard(text);
  showToast(copied ? 'Whitepaper outline copied.' : 'Whitepaper outline is visible on the page.');
}

function downloadWhitepaper() {
  if (!hasWindow) return;
  const href = absolutePublicPath(whitepaperDownloadPath);
  try {
    const link = document.createElement('a');
    link.href = href;
    link.download = 'mergeos-whitepaper.md';
    link.rel = 'noopener';
    document.body.appendChild(link);
    link.click();
    link.remove();
    showToast('Downloading MergeOS whitepaper.');
  } catch {
    openExternalURL(href);
  }
}

function publicWorkflowWalletValue(value = '') {
  let wallet = String(value || '').trim();
  for (const prefix of ['wallet:', 'solana:', 'sol:']) {
    if (wallet.toLowerCase().startsWith(prefix)) {
      wallet = wallet.slice(prefix.length).trim();
    }
  }
  return wallet;
}

function isLikelySolanaWallet(value = '') {
  return /^[1-9A-HJ-NP-Za-km-z]{32,44}$/.test(publicWorkflowWalletValue(value));
}

function tokenWorkflowURLIsValid(value = '') {
  const url = String(value || '').trim();
  if (!url) return true;
  return /^https?:\/\/[^\s/$.?#].[^\s]*$/i.test(url);
}

function airdropClaimFieldError(field) {
  if (!airdropClaimAttempted.value) return '';
  return airdropClaimValidationMap.value[field] || '';
}

function presaleReservationFieldError(field) {
  if (!presaleReservationAttempted.value) return '';
  return presaleReservationValidationMap.value[field] || '';
}

function tokenLaunchBriefFieldError(field) {
  if (!tokenLaunchBriefAttempted.value) return '';
  return tokenLaunchBriefValidationMap.value[field] || '';
}

function resetTokenLaunchBriefForm() {
  tokenLaunchBriefForm.project_title = '';
  tokenLaunchBriefForm.repository_url = '';
  tokenLaunchBriefForm.project_summary = '';
  tokenLaunchBriefForm.allocation_policy = '';
  tokenLaunchBriefForm.proof_policy = '';
  tokenLaunchBriefForm.wallet_policy = '';
  tokenLaunchBriefForm.risk_notes = '';
  tokenLaunchBriefResult.value = null;
}

function prefillTokenLaunchBrief() {
  const launchType = publicPage.value === 'presale' ? 'presale' : 'airdrop';
  resetTokenLaunchBriefForm();
  tokenLaunchBriefForm.project_title = launchType === 'presale'
    ? 'MRG presale readiness review'
    : 'Earned MRG airdrop mission review';
  if (launchType === 'presale') {
    tokenLaunchBriefForm.project_summary = 'CEO should research whether this project has enough utility, wallet readiness, reserve discipline, funding rail evidence, and Solana contract proof to open an MRG presale window.';
    tokenLaunchBriefForm.proof_policy = 'Require verified wallet, funding reference, reserve tier, contract reference, receipt review, and public ledger proof before allocation.';
    tokenLaunchBriefForm.allocation_policy = 'Cap reserve by tier, funding rail, review state, treasury risk, and compliance language.';
    tokenLaunchBriefForm.wallet_policy = 'Require Solana wallet ownership, funding reference, duplicate-wallet review, and receipt reconciliation.';
    tokenLaunchBriefForm.risk_notes = 'CEO must flag reserve caps, payment reversals, unclear utility, contract mismatch, and compliance language before opening.';
  } else {
    const missionCount = Number(airdropMissionsData.value?.stats?.mission_count) || airdropMissionRows.value.length || 0;
    tokenLaunchBriefForm.project_summary = `CEO should research whether this project deserves earned MRG airdrop missions based on repo demand, bounty depth, contributor usefulness, proof quality, wallet uniqueness, and ${missionCount} available mission types.`;
    tokenLaunchBriefForm.proof_policy = 'Require repo import, task reference, PR URL or deployment proof, QA evidence, agent review, and ledger receipt before claim approval.';
    tokenLaunchBriefForm.allocation_policy = 'Cap claims by mission score, useful work evidence, proof quality, anti-bot review, and wallet uniqueness.';
    tokenLaunchBriefForm.wallet_policy = 'Require Solana wallet uniqueness, duplicate claim review, and anti-bot checks before allocation.';
    tokenLaunchBriefForm.risk_notes = 'CEO must flag empty signups, bot farming, weak repo evidence, duplicate wallets, and unverifiable proof.';
  }
  tokenLaunchBriefAttempted.value = false;
  tokenLaunchBriefError.value = '';
  tokenLaunchBriefDecisionContext.label = '';
  tokenLaunchBriefDecisionContext.candidate = '';
  tokenLaunchBriefDecisionContext.score = '';
  showToast('CEO research template added.');
}

function scrollTokenLaunchBriefCardIntoView() {
  if (!hasWindow) return;
  const run = (behavior = 'smooth') => {
    const target = document.getElementById('token-ceo-brief') || document.querySelector('.token-ceo-brief-card');
    if (!target) return;
    const navHeight = Math.round(document.querySelector('.home-navbar')?.getBoundingClientRect().height || 64);
    const top = Math.max(0, window.scrollY + target.getBoundingClientRect().top - navHeight - 14);
    window.scrollTo({ top, behavior });
    if (behavior === 'auto') window.scrollTo(0, top);
  };
  window.requestAnimationFrame(run);
  window.setTimeout(run, 60);
  window.setTimeout(run, 140);
  window.setTimeout(() => run('auto'), 260);
  window.setTimeout(() => run('auto'), 360);
  window.setTimeout(() => run('auto'), 760);
  window.setTimeout(() => run('auto'), 1600);
  window.setTimeout(() => run('auto'), 2600);
  window.setTimeout(() => run('auto'), 4200);
}

function prefillTokenLaunchBriefFromCandidate(candidate = {}) {
  prefillTokenLaunchBrief();
  const launchType = publicPage.value === 'presale' ? 'presale' : 'airdrop';
  tokenLaunchBriefForm.project_title = candidate.title || tokenLaunchBriefForm.project_title;
  tokenLaunchBriefForm.repository_url = candidate.sourceUrl || tokenLaunchBriefForm.repository_url;
  tokenLaunchBriefForm.project_summary = launchType === 'presale'
    ? `CEO should research whether ${candidate.title || 'this project'} is ready for an MRG presale window. ${candidate.projectSummary || candidate.body || ''}`.trim()
    : `CEO should research whether ${candidate.title || 'this project'} deserves earned MRG airdrop missions. ${candidate.projectSummary || candidate.body || ''}`.trim();
  tokenLaunchBriefForm.proof_policy = candidate.proofPolicy || tokenLaunchBriefForm.proof_policy;
  tokenLaunchBriefDecisionContext.label = 'Candidate loaded';
  tokenLaunchBriefDecisionContext.candidate = candidate.title || tokenLaunchBriefForm.project_title;
  tokenLaunchBriefDecisionContext.score = candidate.scoreLabel || '';
  tokenLaunchBriefAttempted.value = false;
  tokenLaunchBriefError.value = '';
  showToast('CEO candidate loaded.');
  scrollTokenLaunchBriefCardIntoView();
}

function applyTokenLaunchCandidateDecision(candidate = {}, decision = {}) {
  prefillTokenLaunchBriefFromCandidate(candidate);
  const launchType = publicPage.value === 'presale' ? 'presale' : 'airdrop';
  const label = decision.label || 'CEO decision';
  tokenLaunchBriefForm.proof_policy = decision.proofPolicy || tokenLaunchBriefForm.proof_policy;
  tokenLaunchBriefForm.risk_notes = decision.riskNotes || tokenLaunchBriefForm.risk_notes;
  tokenLaunchBriefForm.allocation_policy = launchType === 'presale'
    ? `${label}: reserve window remains gated by tier cap, funding rail, receipt policy, and Solana contract proof.`
    : `${label}: earned missions remain gated by useful work, anti-bot review, proof quality, and wallet uniqueness.`;
  tokenLaunchBriefDecisionContext.label = label;
  tokenLaunchBriefDecisionContext.candidate = candidate.title || tokenLaunchBriefForm.project_title;
  tokenLaunchBriefDecisionContext.score = candidate.scoreLabel || tokenLaunchBriefDecisionContext.score;
  tokenLaunchBriefAttempted.value = false;
  tokenLaunchBriefError.value = '';
  showToast(`${label} loaded into CEO brief.`);
  scrollTokenLaunchBriefCardIntoView();
}

function openTokenLaunchBriefFromProofBoard() {
  prefillTokenLaunchBrief();
  scrollTokenLaunchBriefCardIntoView();
}

function tokenWorkflowIntegerAmount(value = 0) {
  return Math.round(Math.max(0, Number(value) || 0));
}

function applySelectedAirdropMissionDefaults(options = {}) {
  const mission = selectedAirdropMission.value;
  if (!mission) return;
  const current = Number(airdropClaimForm.allocation_mrg) || 0;
  const fallback = Number(mission.default_allocation_mrg) || AIRDROP_ALLOCATION_DEFAULT_MRG;
  const cap = Number(mission.max_allocation_mrg) || 100000;
  if (!options.preserveUserValue || current <= 0 || current > cap) {
    airdropClaimForm.allocation_mrg = Math.min(fallback, cap);
  }
}

async function submitAirdropClaim() {
  airdropClaimAttempted.value = true;
  airdropClaimError.value = '';
  if (!user.value) {
    openAuth('login');
    showToast('Log in to record an airdrop claim.');
    return;
  }
  if (airdropClaimValidationRows.value.length) {
    airdropClaimError.value = airdropClaimValidationRows.value[0]?.message || 'Fix airdrop claim details.';
    showToast(airdropClaimError.value);
    return;
  }
  airdropClaimBusy.value = true;
  try {
    const response = await api('/api/airdrop/claims', {
      method: 'POST',
      body: JSON.stringify({
        mission_id: airdropClaimForm.mission_id,
        worker_id: airdropClaimForm.worker_id,
        wallet_address: publicWorkflowWalletValue(airdropClaimForm.wallet_address || user.value?.wallet_address),
        task_reference: airdropClaimForm.task_reference,
        proof_url: airdropClaimForm.proof_url,
        proof_signals: selectedAirdropMission.value?.proof_signals || [],
        allocation_mrg: tokenWorkflowIntegerAmount(airdropClaimForm.allocation_mrg),
        notes: airdropClaimForm.notes,
      }),
    });
    airdropClaimResult.value = response;
    showToast('Airdrop claim recorded on the public ledger.');
    refreshTokenPageData();
  } catch (error) {
    airdropClaimError.value = error.message || 'Could not record airdrop claim.';
    showToast(airdropClaimError.value);
  } finally {
    airdropClaimBusy.value = false;
  }
}

async function submitPresaleReservation() {
  presaleReservationAttempted.value = true;
  presaleReservationError.value = '';
  if (!user.value) {
    openAuth('login');
    showToast('Log in to record a presale reservation.');
    return;
  }
  if (presaleReservationValidationRows.value.length) {
    presaleReservationError.value = presaleReservationValidationRows.value[0]?.message || 'Fix presale reservation details.';
    showToast(presaleReservationError.value);
    return;
  }
  presaleReservationBusy.value = true;
  try {
    const response = await api('/api/presale/reservations', {
      method: 'POST',
      body: JSON.stringify({
        wallet_address: publicWorkflowWalletValue(presaleReservationForm.wallet_address || user.value?.wallet_address),
        reserve_mrg: tokenWorkflowIntegerAmount(presaleReservationForm.reserve_mrg),
        funding_rail: presaleReservationForm.funding_rail,
        funding_reference: presaleReservationForm.funding_reference,
        tier: presaleReservationForm.tier,
        notes: presaleReservationForm.notes,
      }),
    });
    presaleReservationResult.value = response;
    showToast('Presale reservation recorded on the public ledger.');
    refreshTokenPageData();
  } catch (error) {
    presaleReservationError.value = error.message || 'Could not record presale reservation.';
    showToast(presaleReservationError.value);
  } finally {
    presaleReservationBusy.value = false;
  }
}

async function submitTokenLaunchBrief() {
  tokenLaunchBriefAttempted.value = true;
  tokenLaunchBriefError.value = '';
  if (!user.value) {
    openAuth('login');
    showToast('Log in to send a CEO launch brief.');
    return;
  }
  if (tokenLaunchBriefValidationRows.value.length) {
    tokenLaunchBriefError.value = tokenLaunchBriefValidationRows.value[0]?.message || 'Fix CEO launch brief details.';
    showToast(tokenLaunchBriefError.value);
    return;
  }
  tokenLaunchBriefBusy.value = true;
  try {
    const launchType = publicPage.value === 'presale' ? 'presale' : 'airdrop';
    const response = await api('/api/token/launch-briefs', {
      method: 'POST',
      body: JSON.stringify({
        launch_type: launchType,
        project_title: tokenLaunchBriefForm.project_title,
        project_summary: tokenLaunchBriefForm.project_summary,
        repository_url: tokenLaunchBriefForm.repository_url,
        allocation_policy: tokenLaunchBriefForm.allocation_policy,
        proof_policy: tokenLaunchBriefForm.proof_policy,
        wallet_policy: tokenLaunchBriefForm.wallet_policy || (launchType === 'presale' ? 'Require Solana wallet, funding reference, contract reference, and receipt review.' : 'Require Solana wallet uniqueness and anti-bot review.'),
        risk_notes: tokenLaunchBriefForm.risk_notes || (launchType === 'presale' ? 'Review reserve caps, funding rail risk, and compliance language before opening.' : 'Review bot farming, duplicated wallets, empty signups, and unverifiable proof.'),
        research_signals: tokenCeoResearchSignalRows.value,
      }),
    });
    tokenLaunchBriefResult.value = response;
    showToast('CEO launch brief recorded on the public ledger.');
    refreshTokenPageData();
  } catch (error) {
    tokenLaunchBriefError.value = error.message || 'Could not record CEO launch brief.';
    showToast(tokenLaunchBriefError.value);
  } finally {
    tokenLaunchBriefBusy.value = false;
  }
}

function formatTokenWorkflowResult(result = {}) {
  const id = result.claim_id || result.reservation_id || result.brief_id || 'workflow';
  const amount = result.allocation_mrg || result.reserve_mrg || result.ledger_entry?.amount_cents || 0;
  const sequence = result.ledger_entry?.sequence ? `ledger #${result.ledger_entry.sequence}` : 'ledger receipt';
  return `${id} / ${formatMRG(amount)} / ${toTitleLabel(result.status || 'pending review')} / ${sequence}`;
}

function mapTokenWorkflowProofRow(entry = {}) {
  const isLaunchBrief = entry.type === 'token_launch_brief';
  const isAirdrop = entry.type === 'airdrop_claim';
  const when = formatLedgerDateTime(entry.created_at);
  const reference = String(entry.reference || '').trim();
  let idPattern = /presale:([^;]+)/;
  if (isLaunchBrief) idPattern = /launch_brief:([^;]+)/;
  if (isAirdrop) idPattern = /airdrop:([^;]+)/;
  const idMatch = reference.match(idPattern);
  const id = idMatch?.[1] || `ledger-${entry.sequence || entry.entry_hash || 'proof'}`;
  const missionMatch = reference.match(/mission:([^;]+)/);
  const tierMatch = reference.match(/tier:([^;]+)/);
  const railMatch = reference.match(/rail:([^;]+)/);
  const scoreMatch = reference.match(/score:([^;]+)/);
  const launchTypeMatch = reference.match(/type:([^;]+)/);
  const decisionMatch = reference.match(/decision:([^;]+)/);
  const gatesMatch = reference.match(/gates:([^;]+)/);
  const gateSummaryMatch = reference.match(/gate_summary:([^;]+)/);
  const sourceMatch = reference.match(/source:([^;]+)/) || reference.match(/repo:([^;]+)/);
  const gateSummary = gateSummaryMatch?.[1] || (gatesMatch?.[1] ? `${gatesMatch[1].split(',').length} CEO gates` : 'CEO gates');
  const headline = isLaunchBrief
    ? `${toTitleLabel(decisionMatch?.[1] || 'pending open decision')} / ${gateSummary}${sourceMatch?.[1] ? ' / source linked' : ''}`
    : isAirdrop
    ? `${toTitleLabel(missionMatch?.[1] || 'Airdrop claim')} / ${scoreMatch?.[1] ? `${scoreMatch[1]} score` : 'pending score'}`
    : `${toTitleLabel(tierMatch?.[1] || 'Presale reserve')} / ${toTitleLabel(railMatch?.[1] || 'review rail')}`;
  return {
    key: `${entry.type}-${entry.sequence || id}`,
    icon: isLaunchBrief ? FileCheck2 : (isAirdrop ? Trophy : CircleDollarSign),
    tone: isLaunchBrief ? 'blue' : (isAirdrop ? 'purple' : 'green'),
    title: isLaunchBrief ? `CEO ${toTitleLabel(launchTypeMatch?.[1] || 'launch')} ${id}` : `${isAirdrop ? 'Airdrop' : 'Presale'} ${id}`,
    body: headline,
    amount: isLaunchBrief ? 'CEO memo' : formatLedgerMRGFromCents(entry.amount_cents),
    reference: shortLedgerReference(reference || entry.entry_hash || id),
    rawReference: reference,
    hash: shortLedgerHash(entry.entry_hash),
    created: when.full,
  };
}

function mapTokenLaunchBriefQueueRow(brief = {}) {
  const decision = toTitleLabel(brief.decision || 'pending open decision');
  const gateSummary = brief.gate_summary || 'CEO gates pending';
  const source = brief.research_source ? ' / source linked' : '';
  return {
    key: `public-token-launch-${brief.ledger_sequence || brief.brief_id || brief.entry_hash || 'memo'}`,
    title: `CEO ${toTitleLabel(brief.launch_type || 'launch')} ${brief.brief_id || 'memo'}`,
    body: `${decision} / ${gateSummary}${source}`,
    reference: brief.research_source || brief.entry_hash || '',
    hash: shortLedgerHash(brief.entry_hash),
    created: formatLedgerDateTime(brief.created_at).full,
  };
}

async function copyTokenWorkflowHash(result = {}) {
  const hash = result.ledger_entry?.entry_hash || '';
  if (!hash) {
    showToast('No ledger hash available yet.');
    return;
  }
  const copied = await copyTextToClipboard(hash);
  showToast(copied ? 'Ledger hash copied.' : `Ledger hash ${shortLedgerHash(hash)}`);
}

function navContextMenuInlineStyle(menu) {
  if (navContextGeometry.value.menu !== menu) return {};
  return {
    '--nav-context-left': `${navContextGeometry.value.left}px`,
    '--nav-context-top': `${navContextGeometry.value.top}px`,
    '--nav-context-width': `${navContextGeometry.value.width}px`,
    '--nav-context-anchor-left': `${navContextGeometry.value.anchorLeft}px`,
  };
}

function measureNavContextMenu(menu, event = {}) {
  if (!hasWindow) return;
  const source = event?.currentTarget;
  const container = source?.closest?.('.nav-menu') || source;
  const trigger = container?.querySelector?.('.nav-menu-trigger') || source;
  if (!trigger?.getBoundingClientRect) return;

  const rect = trigger.getBoundingClientRect();
  const headerRoot = trigger.closest?.('.home-navbar, .project-flow-navbar');
  const shellElement = trigger.closest?.('.nav-inner')
    || headerRoot?.querySelector?.('.nav-inner')
    || headerRoot;
  const shellRect = shellElement?.getBoundingClientRect?.();
  const viewportWidth = window.innerWidth || document.documentElement.clientWidth || 1024;
  const viewportGutter = viewportWidth < 720 ? 12 : viewportWidth < 1120 ? 14 : 18;
  const safeLeft = viewportGutter;
  const safeRight = viewportWidth - viewportGutter;
  const shellStyles = shellElement ? window.getComputedStyle(shellElement) : null;
  const shellPaddingLeft = Number.parseFloat(shellStyles?.paddingLeft || '0') || 0;
  const shellPaddingRight = Number.parseFloat(shellStyles?.paddingRight || '0') || 0;
  const contentLeft = Math.max(safeLeft, Math.round((shellRect?.left ?? 0) + shellPaddingLeft));
  const contentRight = Math.min(safeRight, Math.round((shellRect?.right ?? viewportWidth) - shellPaddingRight));
  const shellWidth = Math.max(320, contentRight - contentLeft);
  const availableWidth = Math.max(320, safeRight - safeLeft);
  const maxDesktopWidth = menu === 'product' ? 1080 : 920;
  const maxTabletWidth = menu === 'product' ? 940 : 860;
  const targetWidth = viewportWidth < 1120 ? maxTabletWidth : maxDesktopWidth;
  const width = viewportWidth < 720 ? availableWidth : Math.min(shellWidth, availableWidth, targetWidth);
  const centeredLeft = Math.round(contentLeft + ((shellWidth - width) / 2));
  const left = viewportWidth < 720
    ? safeLeft
    : Math.min(Math.max(safeLeft, centeredLeft), Math.max(safeLeft, safeRight - width));
  const headerBottom = Math.max(shellRect?.bottom ?? 0, rect.bottom);
  const top = Math.max(56, Math.round(headerBottom + 2));
  const anchorLeft = Math.min(Math.max(28, Math.round(rect.left + rect.width / 2 - left)), width - 28);

  navContextGeometry.value = {
    menu,
    left,
    top,
    width,
    anchorLeft,
  };
}

function openNavContextMenu(menu, event = {}) {
  cancelNavContextClose();
  if (pinnedNavMenu.value && pinnedNavMenu.value !== menu) {
    pinnedNavMenu.value = '';
  }
  measureNavContextMenu(menu, event);
  activeNavMenu.value = menu;
}

function toggleNavContextMenu(menu, event = {}) {
  cancelNavContextClose();
  if (activeNavMenu.value === menu && pinnedNavMenu.value === menu) {
    closeNavContextMenu();
    return;
  }
  measureNavContextMenu(menu, event);
  activeNavMenu.value = menu;
  pinnedNavMenu.value = menu;
}

function closeNavContextMenu() {
  cancelNavContextClose();
  activeNavMenu.value = '';
  pinnedNavMenu.value = '';
}

function scheduleNavContextClose() {
  cancelNavContextClose();
  if (pinnedNavMenu.value && pinnedNavMenu.value === activeNavMenu.value) return;
  if (!hasWindow) {
    closeNavContextMenu();
    return;
  }
  navContextCloseTimer = window.setTimeout(() => {
    navContextCloseTimer = 0;
    activeNavMenu.value = '';
  }, 900);
}

function cancelNavContextClose() {
  if (!navContextCloseTimer || !hasWindow) return;
  window.clearTimeout(navContextCloseTimer);
  navContextCloseTimer = 0;
}

function handleNavContextOutsideClick(event) {
  if (!activeNavMenu.value) return;
  const target = event.target;
  if (target?.closest?.('.nav-menu, .locale-menu, .account-menu')) return;
  closeNavContextMenu();
  const activeElement = document.activeElement;
  if (activeElement?.closest?.('.nav-menu, .locale-menu, .account-menu')) {
    activeElement.blur();
  }
}

function openLegalPageFromAuth(page = 'terms') {
