function applyProjectWizardIntent(intent = '') {
  const nextIntent = String(intent || '').trim();
  if (!nextIntent) return;

  if (nextIntent === 'repo-import' || nextIntent === 'issue-scanner') {
    projectSetupForm.projectType = 'Bug Fix';
    repoImportError.value = '';
    repoImportValidationErrors.value = {};
    repoImportShouldShowErrors.value = false;
    projectWizardStage.value = 'setup';
    projectWizardStep.value = 1;
    void nextTick().then(focusProjectWizardRepoField);
    return;
  }

  if (nextIntent === 'estimate' && !projectSetupForm.projectType) {
    projectSetupForm.projectType = 'New Project';
    projectWizardStage.value = 'setup';
    projectWizardStep.value = 1;
    return;
  }

  if (nextIntent === 'token-launch') {
    const isPresale = publicPage.value === 'presale';
    tokenLaunchBriefMode.value = isPresale ? 'presale' : 'airdrop';
    projectSetupForm.projectType = 'New Project';
    projectSetupForm.title = isPresale
      ? 'CEO research brief for MRG presale window'
      : 'CEO research brief for earned MRG airdrop';
    projectSetupForm.shortDescription = isPresale
      ? 'Ask the CEO agent to research utility, reserve caps, wallet path, funding rail, Solana contract proof, compliance language, and ledger receipt gates before opening presale.'
      : 'Ask the CEO agent to research repository demand, mission rules, anti-bot policy, allocation cap, Solana wallet readiness, and ledger proof gates before opening an earned airdrop.';
    projectSetupForm.overview = isPresale
      ? 'We want MergeOS CEO orchestration to decide whether this project is ready for a presale window. Review product utility, reserve tiers, funding rails, wallet verification, vesting/compliance notes, contract references, and public proof requirements.'
      : 'We want MergeOS CEO orchestration to decide whether this project deserves an earned airdrop. Review repository context, bounty/task demand, mission catalog fit, proof evidence, anti-bot risk, wallet uniqueness, and claim review capacity.';
    projectSetupForm.requirements = isPresale
      ? 'Deliver a CEO launch memo covering utility, allocation caps, funding checks, wallet gates, contract proof, ledger receipt policy, risk flags, and a clear open/no-open decision.'
      : 'Deliver a CEO launch memo covering mission-market fit, claim rules, proof requirements, anti-bot gates, allocation caps, review owner, ledger receipt policy, and a clear open/no-open decision.';
    projectSetupForm.techStack = projectSetupForm.techStack || 'MergeOS, Solana, MRG, ledger proof, CEO agent';
    projectSetupForm.allowAgents = true;
    projectWizardStage.value = 'setup';
    projectWizardStep.value = 1;
    return;
  }

  if (nextIntent === 'escrow') {
    if (!projectSetupForm.projectType) {
      projectSetupForm.projectType = 'New Project';
    }
    const invalidStep = firstInvalidProjectStep(3);
    projectWizardStage.value = 'setup';
    projectWizardStep.value = invalidStep || 3;
  }
}

function openProjectWizard(options = {}) {
  publicModeVisible.value = true;
  projectWizardVisible.value = true;
  projectPreviewVisible.value = false;
  projectWizardStage.value = 'setup';
  projectWizardStep.value = 1;
  tokenLaunchBriefMode.value = '';
  resetProjectValidation();
  errorMessage.value = '';
  projectPaymentSuccessMethod.value = '';
  restoreProjectDraft({ silent: Boolean(options.silentDraft), restoreStep: true });
  applyProjectWizardIntent(options.intent);
  updateProjectWizardBrowserPath(Boolean(options.replace));
  scrollProjectFlowTop();
}

function restartProjectWizard(options = {}) {
  publicModeVisible.value = true;
  projectWizardVisible.value = true;
  projectPreviewVisible.value = false;
  projectWizardStage.value = 'setup';
  projectWizardStep.value = 1;
  tokenLaunchBriefMode.value = '';
  resetProjectValidation();
  updateProjectWizardBrowserPath(Boolean(options.replace));
  scrollProjectFlowTop();
}

function closeProjectWizard(options = {}) {
  projectPreviewVisible.value = false;
  projectWizardVisible.value = false;
  projectWizardStage.value = 'setup';
  projectWizardStep.value = 1;
  tokenLaunchBriefMode.value = '';
  resetProjectValidation();
  if (options.updatePath !== false) {
    updatePublicBrowserPath(publicPage.value, Boolean(options.replace));
  }
}

async function loadRepoIssues() {
  const repoURL = projectSetupForm.repoUrl.trim();
  repoImportError.value = '';
  repoImportShouldShowErrors.value = true;
  const validationErrors = repoImportValidationErrorsForCurrentInput();
  repoImportValidationErrors.value = validationErrors;
  if (Object.keys(validationErrors).length) {
    repoImportResult.value = null;
    repoImportError.value = validationErrors.repoUrl || 'Fix repository import details before scanning.';
    showToast(repoImportError.value);
    void nextTick().then(focusFirstRepoImportValidationError);
    return;
  }
  const repo = parseRepoDescriptor(repoURL);
  const normalizedRepoURL = `https://github.com/${repo.owner}/${repo.name}`;

  repoImportBusy.value = true;
  try {
    const result = await publicApi('/api/public/repo/issues', {
      method: 'POST',
      body: JSON.stringify({ repo_url: normalizedRepoURL }),
    });
    repoImportResult.value = result;
    projectSetupForm.repoUrl = result.repo_url || normalizedRepoURL;
    repoImportValidationErrors.value = {};
    repoImportShouldShowErrors.value = false;
    if (repoImportedIssues.value.length) {
      projectSetupForm.projectType = 'Bug Fix';
      projectSetupForm.title = `Fix all issues in ${result.owner}/${result.name}`;
      projectSetupForm.shortDescription = `Fix ${repoImportedIssues.value.length} open GitHub issues in ${result.owner}/${result.name}.`;
      projectSetupForm.overview = repoImportedIssues.value
        .map((issue) => `#${issue.number} ${issue.title} - score ${issue.score}, ${issue.complexity}`)
        .join('\n');
      projectDeliverables.value = repoImportedIssues.value.map((issue) => `Fix #${issue.number}: ${issue.title}`);
      showToast(`${repoImportedIssues.value.length} issues loaded and scored.`);
    } else {
      showToast('No open issues found.');
    }
  } catch (error) {
    repoImportResult.value = null;
    repoImportError.value = error.message || 'Could not load repo issues.';
    showToast(repoImportError.value);
  } finally {
    repoImportBusy.value = false;
  }
}

function ensureImportedRepoProjectDraft() {
  if (!repoImportedIssues.value.length) {
    repoImportShouldShowErrors.value = true;
    repoImportError.value = repoImportResult.value
      ? 'No open issues were loaded for this repository.'
      : 'Load repository issues before continuing.';
    showToast(repoImportError.value);
    void nextTick().then(focusFirstRepoImportValidationError);
    return false;
  }

  const parsedRepo = parseRepoDescriptor(projectSetupForm.repoUrl);
  const owner = repoImportResult.value?.owner || parsedRepo?.owner || 'owner';
  const name = repoImportResult.value?.name || parsedRepo?.name || 'repo';
  const repoLabel = `${owner}/${name}`;
  const issueCount = repoImportedIssues.value.length;
  const issueLines = repoImportedIssues.value
    .map((issue) => `#${issue.number} ${issue.title} - score ${issue.score}, ${issue.complexity}`)
    .join('\n');

  projectSetupForm.projectType = 'Bug Fix';
  projectSetupForm.repoUrl = repoImportResult.value?.repo_url || projectSetupForm.repoUrl;
  if (!projectSetupForm.title.trim()) {
    projectSetupForm.title = `Fix all issues in ${repoLabel}`;
  }
  if (!projectSetupForm.shortDescription.trim()) {
    projectSetupForm.shortDescription = `Fix ${issueCount} open GitHub issue${issueCount === 1 ? '' : 's'} in ${repoLabel}.`;
  }
  if (!projectSetupForm.overview.trim()) {
    projectSetupForm.overview = issueLines;
  }
  if (!visibleDeliverables.value.length) {
    projectDeliverables.value = repoImportedIssues.value.map((issue) => `Fix #${issue.number}: ${issue.title}`);
  }
  if (!projectSetupForm.requirements.trim()) {
    projectSetupForm.requirements = [
      'Each imported issue must be resolved with reproducible evidence.',
      'Every fix needs a PR, test notes, or deployment proof before payout release.',
      'Accepted work must keep the public ledger, task state, and review notes in sync.',
    ].join('\n');
  }
  if (!projectSetupForm.skills.trim()) {
    projectSetupForm.skills = inferSkillList();
  }
  if (!projectSetupForm.startDate) {
    projectSetupForm.startDate = todayDateInput();
  }
  if (!projectSetupForm.deadline) {
    projectSetupForm.deadline = dateInputDaysFromNow(Math.min(45, Math.max(14, issueCount * 3)));
  }
  if (!projectBudgetAmount.value) {
    projectSetupForm.budgetAmount = Math.max(minimumProjectBudgetMRG, tokenAmountFromCents(repoImportedEstimateCents.value));
    projectSetupForm.budgetType = 'Range';
  }
  projectFundingAmount.value = Math.max(minimumProjectFundingUSD, Math.ceil(projectBudgetAmount.value / TOKEN_RATE_PER_USD) || minimumProjectFundingUSD);
  return true;
}

function openImportedRepoWizardStep(stepNumber = 2) {
  publicModeVisible.value = true;
  projectWizardVisible.value = true;
  projectPreviewVisible.value = false;
  projectWizardStage.value = 'setup';
  projectWizardStep.value = normalizeProjectWizardStep(stepNumber);
  resetProjectValidation();
  updateProjectWizardBrowserPath();
  scrollProjectFlowTop();
}

function continueImportedRepoProject(destination = 'scope') {
  if (!ensureImportedRepoProjectDraft()) return;

  if (destination === 'estimate') {
    openDashboardSection('estimate');
    void nextTick().then(() => runProjectPriceEvaluation());
    return;
  }

  if (destination === 'funding') {
    const invalidStep = firstInvalidProjectStep(4);
    if (invalidStep) {
      markProjectStepValidationAttempted(invalidStep);
      openImportedRepoWizardStep(invalidStep);
      showProjectValidationToast(invalidStep);
      void nextTick().then(focusFirstProjectValidationError);
      return;
    }
    publicModeVisible.value = true;
    projectWizardVisible.value = true;
    projectPreviewVisible.value = false;
    projectWizardStage.value = 'funding';
    projectWizardStep.value = 4;
    updateProjectWizardBrowserPath();
    scrollProjectFlowTop();
    showToast('Scored repository plan is ready for escrow funding.');
    return;
  }

  openImportedRepoWizardStep(2);
  showToast('Scored repository issues added to the project scope.');
}

function openImportedRepoPublishPreview(target = 'bounties') {
  if (!ensureImportedRepoProjectDraft()) return;

  const isAgentPreview = target === 'agents';
  const searchTerm = repoImportMarketplaceSearchTerm.value;
  if (isAgentPreview) {
    projectSetupForm.allowAgents = true;
  }

  if (user.value) {
    dashboardSearch.value = searchTerm;
    openDashboardSection(isAgentPreview ? 'agents' : 'bounties');
  } else {
    marketplaceSearch.value = searchTerm;
    openMarketplaceSection(isAgentPreview ? 'marketplace-agent-packets' : 'marketplace-bounties');
  }

  showToast(isAgentPreview
    ? 'Agent packet lanes are filtered for the imported repository.'
    : 'Bounty board is filtered for the imported repository.');
}

function openImportedRepoLiveProof() {
  if (!ensureImportedRepoProjectDraft()) return;
  activeLiveFeedType.value = 'Repository Scan';
  openPublicPage('live');
  showToast('Live proof view opened for repository scan and task events.');
}

function parseRepoDescriptor(value = '') {
  const raw = String(value || '').trim();
  if (!raw) return null;
  const sshMatch = raw.match(/^git@github\.com:([\w.-]+)\/([\w.-]+?)(?:\.git)?$/i);
  if (sshMatch) {
    return { owner: sshMatch[1], name: sshMatch[2], label: `${sshMatch[1]}/${sshMatch[2]}` };
  }
  try {
    const url = new URL(raw);
    const hostname = url.hostname.toLowerCase();
    if (hostname === 'github.com' || hostname === 'www.github.com') {
      const [owner, repo] = url.pathname.split('/').filter(Boolean);
      if (owner && repo) {
        return { owner, name: repo.replace(/\.git$/i, ''), label: `${owner}/${repo.replace(/\.git$/i, '')}` };
      }
    }
  } catch {
    // Fall through to owner/repo shorthand parsing.
  }
  const shorthand = raw.match(/^([\w.-]+)\/([\w.-]+)$/);
  if (!shorthand) return null;
  return { owner: shorthand[1], name: shorthand[2].replace(/\.git$/i, ''), label: `${shorthand[1]}/${shorthand[2].replace(/\.git$/i, '')}` };
}

function repoDescriptorIsGitHubSafe(repo = {}) {
  const owner = String(repo.owner || '').trim();
  const name = String(repo.name || '').trim();
  return /^[A-Za-z0-9](?:[A-Za-z0-9-]{0,37}[A-Za-z0-9])?$/.test(owner)
    && /^[A-Za-z0-9._-]{1,100}$/.test(name)
    && !name.startsWith('.')
    && !name.endsWith('.');
}

function projectRepoImportMatches(repo = {}) {
  if (!repo?.owner || !repo?.name || !repoImportResult.value) return false;
  const imported = parseRepoDescriptor(repoImportResult.value.repo_url || `${repoImportResult.value.owner || ''}/${repoImportResult.value.name || ''}`);
  if (!imported) return false;
  return imported.owner.toLowerCase() === repo.owner.toLowerCase()
    && imported.name.toLowerCase() === repo.name.toLowerCase();
}

function isValidDateInput(value = '') {
  const raw = String(value || '').trim();
  const match = raw.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) return false;
  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);
  const date = new Date(Date.UTC(year, month - 1, day));
  return date.getUTCFullYear() === year
    && date.getUTCMonth() === month - 1
    && date.getUTCDate() === day;
}

function projectDateDiffDays(startDate = '', endDate = '') {
  if (!isValidDateInput(startDate) || !isValidDateInput(endDate)) return 0;
  const start = Date.parse(`${startDate}T00:00:00Z`);
  const end = Date.parse(`${endDate}T00:00:00Z`);
  if (!Number.isFinite(start) || !Number.isFinite(end)) return 0;
  return Math.round((end - start) / 86400000);
}

function repoImportValidationErrorsForCurrentInput() {
  const errors = {};
  const raw = projectSetupForm.repoUrl.trim();
  if (!raw) {
    errors.repoUrl = 'Enter a GitHub repository URL before scanning.';
    return errors;
  }
  const repo = parseRepoDescriptor(raw);
  if (!repo || !repo.owner || !repo.name) {
    errors.repoUrl = 'Use a GitHub repo URL, SSH URL, or owner/repo shorthand.';
    return errors;
  }
  if (repo.owner.length > 100 || repo.name.length > 100) {
    errors.repoUrl = 'Repository owner and name must be shorter than 100 characters.';
  } else if (!repoDescriptorIsGitHubSafe(repo)) {
    errors.repoUrl = 'Use a real GitHub owner and repository name.';
  }
  return errors;
}

function repoImportFieldError(field = '') {
  if (!repoImportShouldShowErrors.value) return '';
  return repoImportValidationErrors.value[field] || '';
}

function clearRepoImportFieldError(field = '') {
  if (!field || !repoImportValidationErrors.value[field]) return;
  repoImportValidationErrors.value = {
    ...repoImportValidationErrors.value,
    [field]: '',
  };
  for (const [key, message] of Object.entries(repoImportValidationErrors.value)) {
    if (!message) delete repoImportValidationErrors.value[key];
  }
  if (!Object.keys(repoImportValidationErrors.value).length) {
    repoImportError.value = '';
  }
}

function focusFirstRepoImportValidationError() {
  if (!hasWindow) return;
  document.querySelector('.dashboard-tool-form label.invalid input')?.focus();
}

function todayDateInput() {
  const now = new Date();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  return `${now.getFullYear()}-${month}-${day}`;
}

function dateInputDaysFromNow(days = 0) {
  const next = new Date();
  next.setDate(next.getDate() + (Number(days) || 0));
  const month = String(next.getMonth() + 1).padStart(2, '0');
  const day = String(next.getDate()).padStart(2, '0');
  return `${next.getFullYear()}-${month}-${day}`;
}

function projectValidationErrorsForStep(stepNumber = projectWizardStep.value) {
  const step = normalizeProjectWizardStep(stepNumber);
  const errors = {};
  const title = projectSetupForm.title.trim();
  const shortDescription = projectSetupForm.shortDescription.trim();
  const overview = projectSetupForm.overview.trim();
  const deliverables = visibleDeliverables.value;
  const requirements = projectSetupForm.requirements.trim();
  const today = todayDateInput();

  if (step === 1) {
    if (title.length < projectTitleMinLength) {
      errors.title = `Enter a clear title with at least ${projectTitleMinLength} characters.`;
    } else if (title.length > projectTitleMaxLength) {
      errors.title = `Keep the title under ${projectTitleMaxLength} characters.`;
    } else if (/^https?:\/\//i.test(title)) {
      errors.title = 'Use a project title, not a URL.';
    }
    if (shortDescription.length < projectShortDescriptionMinLength) {
      errors.shortDescription = `Describe the work in at least ${projectShortDescriptionMinLength} characters.`;
    } else if (shortDescription.length > projectShortDescriptionMaxLength) {
      errors.shortDescription = `Keep the short description under ${projectShortDescriptionMaxLength} characters.`;
    } else if (title && shortDescription.toLowerCase() === title.toLowerCase()) {
      errors.shortDescription = 'Add context beyond the project title.';
    }
    if (!projectSetupForm.projectType) {
      errors.projectType = 'Choose New Project or Bug Fix.';
    }
    if (projectSetupForm.projectType === 'Bug Fix') {
      const repo = parseRepoDescriptor(projectSetupForm.repoUrl);
      if (!projectSetupForm.repoUrl.trim()) {
        errors.repoUrl = 'Attach the GitHub repository for this bug fix.';
      } else if (!repo) {
        errors.repoUrl = 'Use a valid GitHub URL or owner/repo shorthand.';
      } else if (!repoDescriptorIsGitHubSafe(repo)) {
        errors.repoUrl = 'Use a real GitHub owner and repository name.';
      } else if (!projectRepoImportMatches(repo) || !repoImportedIssues.value.length) {
        errors.repoImport = 'Load issues for this repository before continuing.';
      }
    }
    return errors;
  }

  if (step === 2) {
    if (overview.length < projectOverviewMinLength) {
      errors.overview = `Add at least ${projectOverviewMinLength} characters of goal, context, and expected behavior.`;
    } else if (overview.length > projectOverviewMaxLength) {
      errors.overview = `Keep the overview under ${projectOverviewMaxLength} characters.`;
    }
    if (deliverables.length < 2) {
      errors.deliverables = 'Add at least 2 concrete deliverables.';
    } else if (deliverables.some((item) => item.length < projectDeliverableMinLength)) {
      errors.deliverables = `Each deliverable should be at least ${projectDeliverableMinLength} characters.`;
    } else if (deliverables.some((item) => item.length > projectDeliverableMaxLength)) {
      errors.deliverables = `Keep each deliverable under ${projectDeliverableMaxLength} characters.`;
    } else if (new Set(deliverables.map((item) => item.toLowerCase())).size !== deliverables.length) {
      errors.deliverables = 'Remove duplicate deliverables.';
    }
    if (requirements.length > projectRequirementsMaxLength) {
      errors.requirements = `Keep requirements under ${projectRequirementsMaxLength} characters.`;
    }
    return errors;
  }

  if (step === 3) {
    const rawBudget = projectSetupForm.budgetAmount;
    const budgetValue = Number(rawBudget);
    if (rawBudget === '' || rawBudget === null || rawBudget === undefined) {
      errors.budgetAmount = 'Enter a budget amount.';
    } else if (!Number.isFinite(budgetValue)) {
      errors.budgetAmount = 'Budget must be a valid number.';
    } else if (budgetValue < minimumProjectBudgetMRG) {
      errors.budgetAmount = `Budget must be at least ${formatMRG(minimumProjectBudgetMRG)}.`;
    } else if (budgetValue > maximumProjectBudgetMRG) {
      errors.budgetAmount = `Budget must be ${formatMRG(maximumProjectBudgetMRG)} or less.`;
    }
    if (!budgetTypeOptions.some((item) => item.label === projectSetupForm.budgetType)) {
      errors.budgetAmount = 'Choose a valid budget type.';
    }
    if (!projectSetupForm.startDate) {
      errors.startDate = 'Choose a start date.';
    } else if (!isValidDateInput(projectSetupForm.startDate)) {
      errors.startDate = 'Use a valid start date.';
    } else if (projectSetupForm.startDate < today) {
      errors.startDate = 'Start date cannot be in the past.';
    }
    if (!projectSetupForm.deadline) {
      errors.deadline = 'Choose a deadline.';
    } else if (!isValidDateInput(projectSetupForm.deadline)) {
      errors.deadline = 'Use a valid deadline.';
    } else if (projectSetupForm.startDate && projectSetupForm.deadline < projectSetupForm.startDate) {
      errors.timeline = 'Deadline must be on or after the start date.';
    } else if (projectDurationDays.value > 365) {
      errors.timeline = 'Timeline should be 365 days or less.';
    }
    if (!fundingMethodOptions.some((item) => item.label === projectSetupForm.fundingMethod)) {
      errors.budget = 'Choose a valid funding method.';
    }
    if (!projectSetupForm.skills.trim() && !projectSetupForm.techStack.trim()) {
      errors.skills = 'Add skills required or a tech stack so routing can match talent.';
    } else if (projectSetupForm.skills.trim() && projectSetupForm.skills.trim().length < 3) {
      errors.skills = 'Add at least one recognizable skill.';
    }
    return errors;
  }

  if (step === 4) {
    if (!projectStepIsValid(1)) errors.details = 'Project details are incomplete.';
    if (!projectStepIsValid(2)) errors.scope = 'Scope and deliverables are incomplete.';
    if (!projectStepIsValid(3)) errors.budget = 'Budget, timeline, or skills are incomplete.';
  }
  return errors;
}

function projectValidationList(errors = {}) {
  return Object.entries(errors).map(([field, message]) => ({
    field,
    label: projectValidationLabels[field] || toTitleLabel(field),
    message,
  }));
}

function projectStepNavDone(stepNumber) {
  const step = normalizeProjectWizardStep(stepNumber);
  if (projectWizardStage.value !== 'setup') {
    return step < 4 ? projectStepIsValid(step) : projectAllSetupStepsValid();
  }
  return projectWizardStep.value > step && projectStepIsValid(step);
}

function projectStepNavInvalid(stepNumber) {
  const step = normalizeProjectWizardStep(stepNumber);
  return Boolean(projectStepValidationAttempted[step] && !projectStepIsValid(step));
}

function projectStepNavClass(stepNumber) {
  const step = normalizeProjectWizardStep(stepNumber);
  return {
    active: projectWizardStage.value === 'setup' && projectWizardStep.value === step,
    done: projectStepNavDone(step),
    invalid: projectStepNavInvalid(step),
  };
}

function markProjectFieldTouched(field) {
  if (!field) return;
  projectTouchedFields[field] = true;
  if (field === 'deadline') {
    projectTouchedFields.timeline = true;
  }
}

function projectFieldError(field) {
  if (!projectShouldShowStepErrors.value && !projectTouchedFields[field]) return '';
  return currentProjectValidationErrors.value[field] || '';
}

function projectStepErrorCount(stepNumber) {
  return Object.keys(projectValidationErrorsForStep(stepNumber)).length;
}

function projectStepIsValid(stepNumber) {
  return projectStepErrorCount(stepNumber) === 0;
}

function projectAllSetupStepsValid() {
  return [1, 2, 3].every((step) => projectStepIsValid(step));
}

function markProjectStepValidationAttempted(stepNumber) {
  projectStepValidationAttempted[normalizeProjectWizardStep(stepNumber)] = true;
}

function resetProjectValidation() {
  for (const step of [1, 2, 3, 4]) {
    projectStepValidationAttempted[step] = false;
  }
  for (const key of Object.keys(projectTouchedFields)) {
    delete projectTouchedFields[key];
  }
  projectFundingValidationAttempted.value = false;
  projectPaymentError.value = '';
  priceEvaluationValidationErrors.value = {};
  priceEvaluationShouldShowErrors.value = false;
}

function firstInvalidProjectStep(upToStep = 4) {
  const limit = normalizeProjectWizardStep(upToStep);
  for (const step of [1, 2, 3]) {
    if (step > limit) break;
    if (!projectStepIsValid(step)) return step;
  }
  if (limit === 4 && !projectStepIsValid(4)) return 4;
  return 0;
}

function focusFirstProjectValidationError() {
  if (!hasWindow) return;
  const focusTarget = () => {
    const selectors = [
      '.wizard-field.invalid input',
      '.wizard-field.invalid textarea',
      '.wizard-field.invalid select',
      '.wizard-section.invalid .rich-editor textarea',
      '.wizard-section.invalid .deliverable-row input',
      '.wizard-section.invalid .select-tile',
      '.wizard-validation-banner',
    ];
    const target = selectors
      .map((selector) => document.querySelector(selector))
      .find((element) => element && element.offsetParent !== null);
    if (!target) return false;
    target.scrollIntoView({ behavior: 'smooth', block: 'center' });
    if (typeof target?.focus === 'function') {
      target.focus({ preventScroll: true });
    }
    return document.activeElement === target || !['INPUT', 'TEXTAREA', 'SELECT', 'BUTTON'].includes(target.tagName);
  };
  window.requestAnimationFrame(() => {
    if (!focusTarget()) {
      window.setTimeout(focusTarget, 120);
    }
  });
}

function showProjectValidationToast(stepNumber) {
  const count = projectStepErrorCount(stepNumber);
  showToast(count === 1 ? 'Fix 1 required item before continuing.' : `Fix ${count} required items before continuing.`);
}

function openNextProjectQualityIssue() {
  const invalidStep = firstInvalidProjectStep(4);
  if (!invalidStep) {
    goProjectStep(4);
    return;
  }
  markProjectStepValidationAttempted(invalidStep);
  goProjectStep(invalidStep, { skipValidation: true });
  showProjectValidationToast(invalidStep);
  void nextTick().then(focusFirstProjectValidationError);
}

function projectQualityStepForItem(item = {}) {
  if (item.key === 'details') return 1;
  if (item.key === 'scope') return 2;
  if (item.key === 'budget') return 3;
  return 4;
}

function openProjectQualityItem(item = {}) {
  const step = projectQualityStepForItem(item);
  markProjectStepValidationAttempted(step);
  goProjectStep(step, { skipValidation: true });
  showProjectValidationToast(step);
  void nextTick().then(focusFirstProjectValidationError);
}

function guardProjectWizardRouteValidation(options = {}) {
  if (projectWizardStage.value !== 'setup' || projectWizardStep.value <= 1) return false;
  const invalidStep = firstInvalidProjectStep(projectWizardStep.value - 1);
  if (!invalidStep) return false;
  markProjectStepValidationAttempted(invalidStep);
  projectPreviewVisible.value = false;
  projectWizardStep.value = invalidStep;
  updateProjectWizardBrowserPath(Boolean(options.replace));
  scrollProjectFlowTop();
  if (!options.silent) {
    showProjectValidationToast(invalidStep);
  }
  void nextTick().then(focusFirstProjectValidationError);
  return true;
}

function projectFundingFieldError(field) {
  if (!projectFundingShouldShowErrors.value) return '';
  return projectFundingValidationErrors.value[field] || '';
}

function projectFundingErrorCount() {
  return Object.keys(projectFundingValidationErrors.value).length;
}

function showProjectFundingValidationToast() {
  const count = projectFundingErrorCount();
  showToast(count === 1 ? 'Fix 1 payment item before funding.' : `Fix ${count} payment items before funding.`);
}

function focusFirstProjectFundingValidationError() {
  if (!hasWindow) return;
  window.requestAnimationFrame(() => {
    const target = document.querySelector('.project-funding-validation, .funding-panel .wizard-field.invalid input, .funding-panel .wizard-section.invalid button');
    target?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    if (typeof target?.focus === 'function') {
      target.focus({ preventScroll: true });
    }
  });
}

function cardDigitsFrom(value = '') {
  return String(value || '').replace(/\D/g, '');
}

function cardCvcDigitsFrom(value = '') {
  return String(value || '').trim();
}

function projectCardDigits() {
  return cardDigitsFrom(projectCardForm.cardNumber);
}

function projectCardCvcDigits() {
  return cardCvcDigitsFrom(projectCardForm.cvc);
}

function projectCardExpiryDetails(value = projectCardForm.expiry) {
  const raw = String(value || '').trim();
  if (!raw) {
    return { error: 'Enter expiry date in MM/YY.' };
  }

  const normalized = raw.replace(/[\s.-]+/g, '/').replace(/\/+/g, '/');
  let parts = normalized.split('/').filter(Boolean);
  if (parts.length === 1) {
    const digits = normalized.replace(/\D/g, '');
    if (digits.length === 4 || digits.length === 6) {
      parts = [digits.slice(0, 2), digits.slice(2)];
    }
  }
  if (parts.length !== 2 || !/^\d+$/.test(parts[0]) || !/^\d+$/.test(parts[1])) {
    return { error: 'Use MM/YY for the expiry date.' };
  }

  const month = Number(parts[0]);
  if (!Number.isInteger(month) || month < 1 || month > 12) {
    return { error: 'Expiry month must be between 01 and 12.' };
  }

  const yearPart = parts[1];
  if (yearPart.length !== 2 && yearPart.length !== 4) {
    return { error: 'Use a 2 or 4 digit expiry year.' };
  }
  let year = Number(yearPart);
  if (!Number.isInteger(year)) {
    return { error: 'Expiry year is invalid.' };
  }
  if (year < 100) {
    year += 2000;
  }

  const expiresAt = new Date(Date.UTC(year, month, 1));
  if (!expiresAt.getTime() || expiresAt <= new Date()) {
    return { error: 'Card is expired.' };
  }

  const normalizedYear = yearPart.length === 2 ? String(yearPart).padStart(2, '0') : String(year);
  return { normalized: `${String(month).padStart(2, '0')}/${normalizedYear}` };
}

function projectCardExpiryForPayload() {
  return projectCardExpiryDetails().normalized || projectCardForm.expiry;
}

function repoTaskCardDigits() {
  return cardDigitsFrom(repoTaskFundingCardForm.cardNumber);
}

function repoTaskCardCvcDigits() {
  return cardCvcDigitsFrom(repoTaskFundingCardForm.cvc);
}

function repoTaskCardExpiryForPayload() {
  return projectCardExpiryDetails(repoTaskFundingCardForm.expiry).normalized || repoTaskFundingCardForm.expiry;
}

function luhnValid(value = '') {
  let sum = 0;
  let doubleDigit = false;
  for (let index = value.length - 1; index >= 0; index -= 1) {
    let digit = Number(value[index]);
    if (!Number.isInteger(digit)) return false;
    if (doubleDigit) {
      digit *= 2;
      if (digit > 9) digit -= 9;
    }
    sum += digit;
    doubleDigit = !doubleDigit;
  }
  return sum > 0 && sum % 10 === 0;
}

function projectDevPaymentReference() {
  return runtimeConfig.value?.dev_payment_enabled && runtimeConfig.value?.dev_payment_code
    ? runtimeConfig.value.dev_payment_code
    : '';
}

function cardCheckoutReady(config = runtimeConfig.value) {
  return Boolean(config?.card_ready || (config?.card_ready === undefined && config?.dev_payment_enabled && config?.dev_payment_code));
}

function projectFundingValidationErrorsForCurrentSelection() {
  const errors = {};
  const amount = Number(projectFundingAmount.value);
  const paymentMethod = paymentMethodForProject();
  const config = runtimeConfig.value;
  const devPaymentReference = projectDevPaymentReference();

  if (!Number.isFinite(amount) || amount <= 0) {
    errors.amount = 'Choose an escrow amount before funding.';
  } else if (amount < minimumProjectFundingUSD) {
    errors.amount = `Escrow funding must be at least ${formatMoney(minimumProjectFundingUSD)} USD.`;
  }

  if (config) {
    if (paymentMethod === 'card' && !cardCheckoutReady(config)) {
      errors.paymentMethod = 'Card checkout is not configured for this environment.';
    }
    if (paymentMethod === 'paypal' && !config.paypal_ready && !devPaymentReference) {
      errors.paymentMethod = 'PayPal checkout is not configured. Choose card or enable PayPal.';
    }
    if (paymentMethod === 'crypto' && !config.crypto_ready && !devPaymentReference) {
      errors.paymentMethod = 'USDC verification is not configured. Choose another method or enable crypto verification.';
    }
  }

  if (paymentMethod === 'card') {
    const digits = projectCardDigits();
    if (!digits) {
      errors.cardNumber = 'Enter the card number.';
    } else if (digits.length < 12 || digits.length > 19 || !luhnValid(digits)) {
      errors.cardNumber = 'Card number is invalid.';
    }

    const expiry = projectCardExpiryDetails();
    if (expiry.error) {
      errors.cardExpiry = expiry.error;
    }

    const cvc = projectCardCvcDigits();
    if (!/^\d{3,4}$/.test(cvc)) {
      errors.cardCvc = 'CVC must be 3 or 4 digits.';
    }

    if (String(projectCardForm.cardholderName || '').trim().length < 2) {
      errors.cardholderName = 'Enter the cardholder name shown on the card.';
    }
  }

  if (paymentMethod === 'crypto' && !devPaymentReference) {
    const reference = String(projectCryptoReference.value || '').trim();
    if (!reference) {
      errors.cryptoReference = 'Paste the confirmed Solana transaction signature.';
    } else if (!/^[1-9A-HJ-NP-Za-km-z]{80,100}$/.test(reference)) {
      errors.cryptoReference = 'Signature must be a Solana base58 transaction signature.';
    }
  }

  return errors;
}

function repoTaskFundingFieldError(field) {
  if (!repoTaskFundingShouldShowErrors.value) return '';
  return repoTaskFundingValidationErrors.value[field] || '';
}

function repoTaskFundingErrorCount() {
  return Object.keys(repoTaskFundingValidationErrors.value).length;
}

function paymentMethodForRepoTaskFunding() {
  if (repoTaskFundingMethod.value === 'Credit / Debit card') return 'card';
  if (repoTaskFundingMethod.value === 'USDC') return 'crypto';
  return 'paypal';
}

function repoTaskFundingValidationErrorsForCurrentSelection() {
  const errors = {};
  const paymentMethod = paymentMethodForRepoTaskFunding();
  const config = runtimeConfig.value;
  const devPaymentReference = projectDevPaymentReference();

  if (!repoTaskFundingTask.value?.id) {
    errors.details = 'Choose a suggested task to fund.';
  }
  if (repoTaskFundingAmountCents.value < minimumProjectFundingUSD * 100) {
    errors.amount = `Escrow funding must be at least ${formatMoney(minimumProjectFundingUSD)} USD.`;
  }

  if (config) {
    if (paymentMethod === 'card' && !cardCheckoutReady(config)) {
      errors.paymentMethod = 'Card checkout is not configured for this environment.';
    }
    if (paymentMethod === 'paypal' && !config.paypal_ready && !devPaymentReference) {
      errors.paymentMethod = 'PayPal checkout is not configured. Choose card or enable PayPal.';
    }
    if (paymentMethod === 'crypto' && !config.crypto_ready && !devPaymentReference) {
      errors.paymentMethod = 'USDC verification is not configured. Choose another method or enable crypto verification.';
    }
  }

  if (paymentMethod === 'card') {
    const digits = repoTaskCardDigits();
    if (!digits) {
      errors.cardNumber = 'Enter the card number.';
    } else if (digits.length < 12 || digits.length > 19 || !luhnValid(digits)) {
      errors.cardNumber = 'Card number is invalid.';
    }

    const expiry = projectCardExpiryDetails(repoTaskFundingCardForm.expiry);
    if (expiry.error) {
      errors.cardExpiry = expiry.error;
    }

    if (!/^\d{3,4}$/.test(repoTaskCardCvcDigits())) {
      errors.cardCvc = 'CVC must be 3 or 4 digits.';
    }

    if (String(repoTaskFundingCardForm.cardholderName || '').trim().length < 2) {
      errors.cardholderName = 'Enter the cardholder name shown on the card.';
    }
  }

  if (paymentMethod === 'crypto' && !devPaymentReference) {
    const reference = String(repoTaskFundingCryptoReference.value || '').trim();
    if (!reference) {
      errors.cryptoReference = 'Paste the confirmed Solana transaction signature.';
    } else if (!/^[1-9A-HJ-NP-Za-km-z]{80,100}$/.test(reference)) {
      errors.cryptoReference = 'Signature must be a Solana base58 transaction signature.';
    }
  }

  return errors;
}

function displayNameFromRepo(repo) {
  if (!repo?.name) return 'software delivery workflow';
  return repo.name
    .replace(/[-_]+/g, ' ')
    .replace(/\b\w/g, (char) => char.toUpperCase());
}

function mergeDeliverableSuggestions(suggestions = []) {
  const existing = visibleDeliverables.value;
  const seen = new Set(existing.map((item) => item.toLowerCase()));
  const next = [...existing];
  for (const suggestion of suggestions) {
    const clean = String(suggestion || '').trim();
    if (!clean || seen.has(clean.toLowerCase())) continue;
    seen.add(clean.toLowerCase());
    next.push(clean);
  }
  projectDeliverables.value = next.length ? next : [''];
}

function inferSkillList() {
  const stack = projectSetupForm.techStack.trim();
  const base = stack
    ? stack.split(/[,;/|]+/).map((item) => item.trim()).filter(Boolean)
    : ['Frontend', 'Backend', 'QA', 'DevOps'];
  const merged = new Set([...base, projectSetupForm.allowAgents ? 'AI orchestration' : '', 'Code review'].filter(Boolean));
  return Array.from(merged).slice(0, 8).join(', ');
}

function runProjectBriefAssistant() {
  if (briefAssistantBusy.value) return;
  briefAssistantBusy.value = true;
  try {
    const repo = parseRepoDescriptor(projectSetupForm.repoUrl);
    const repoLabel = repo?.label || '';
    const projectName = displayNameFromRepo(repo);
    const isBugFix = projectSetupForm.projectType === 'Bug Fix' || Boolean(repoLabel);

    if (!projectSetupForm.projectType) {
      projectSetupForm.projectType = isBugFix ? 'Bug Fix' : 'New Project';
    }
    if (!projectSetupForm.title.trim()) {
      projectSetupForm.title = isBugFix
        ? `Stabilize and ship ${projectName}`
        : 'Build an AI-orchestrated software delivery workflow';
    }
    if (!projectSetupForm.shortDescription.trim()) {
      projectSetupForm.shortDescription = isBugFix
        ? `Import ${repoLabel || 'the repository'}, scan technical debt, generate payable tasks, and validate fixes through review and deployment gates.`
        : 'Design and build a production-ready workflow with task generation, contributor routing, escrow-backed delivery, and public ledger proof.';
    }
    if (!projectSetupForm.overview.trim()) {
      projectSetupForm.overview = [
        `Goal: ${projectSetupForm.shortDescription.trim()}`,
        repoLabel ? `Repository: ${repoLabel}` : '',
        'Workflow: scan the scope, split the work into reviewable tasks, route tasks to human or AI workers, then verify PRs before release.',
        'Definition of done: accepted tasks have evidence, review notes, deployment validation, and ledger references.',
      ].filter(Boolean).join('\n\n');
    }
    mergeDeliverableSuggestions(isBugFix ? [
      'Repository scan with bugs, dependency risk, and technical debt findings',
      'Prioritized task graph with reward estimates and worker lane routing',
      'Implementation PRs with tests, screenshots, or deployment evidence',
      'AI review and QA validation report before payment release',
    ] : [
      'Product workflow map from repository import to payment release',
      'Customer dashboard with projects, tasks, escrow, AI logs, and deployments',
      'Marketplace views for live projects, public bounties, contributors, and AI agents',
      'Ledger-backed release flow with audit-ready payout records',
    ]);
    if (!projectSetupForm.requirements.trim()) {
      projectSetupForm.requirements = [
        'All work must include clear acceptance criteria and evidence.',
        'Task status, escrow state, AI actions, and deployment progress must stay visible in the dashboard.',
        'Contributor and AI-agent actions must be traceable through ledger or live-feed events.',
        'Implementation must include loading, empty, retry, and error states for user-facing flows.',
      ].join('\n');
    }
    if (!projectSetupForm.skills.trim()) {
      projectSetupForm.skills = inferSkillList();
    }
    if (!projectSetupForm.complexity) {
      projectSetupForm.complexity = isBugFix ? 'Medium' : 'High';
    }
    showToast('AI assistant structured the project brief.');
    if (projectWizardStep.value === 1) {
      goProjectStep(2);
    }
  } finally {
    briefAssistantBusy.value = false;
  }
}

function openReferenceFilePicker() {
  referenceUploadError.value = '';
  referenceFileInput.value?.click();
}

async function handleReferenceFilesSelected(event) {
  await uploadReferenceFiles(event?.target?.files);
  if (event?.target) {
    event.target.value = '';
  }
}

async function handleReferenceDrop(event) {
  await uploadReferenceFiles(event?.dataTransfer?.files);
}

async function uploadReferenceFiles(filesLike) {
  const files = Array.from(filesLike || []).filter((file) => file && file.size > 0);
  referenceUploadError.value = '';
  if (!files.length) return;

  if (!user.value || !token.value) {
    authReturnToProjectWizard.value = true;
    projectWizardVisible.value = false;
    openAuth('login');
    showToast('Log in to upload reference files.');
    return;
  }

  const oversized = files.find((file) => file.size > MAX_REFERENCE_UPLOAD_BYTES);
  if (oversized) {
    referenceUploadError.value = `${oversized.name} is larger than 15MB.`;
    showToast(referenceUploadError.value);
    return;
  }

  const form = new FormData();
  for (const file of files) {
    form.append('files', file);
  }

  referenceUploadBusy.value = true;
  try {
    const response = await fetch('/api/uploads', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${token.value}`,
      },
      body: form,
    });
    const text = await response.text();
    let payload = [];
    try {
      payload = text ? JSON.parse(text) : [];
    } catch {
      payload = { error: text || 'Upload failed' };
    }
    if (!response.ok) {
      if (response.status === 401) clearSession();
      throw createRequestError(response, payload);
    }
    const uploaded = Array.isArray(payload) ? payload : [payload];
    const byID = new Map(referenceAttachments.value.map((attachment) => [attachment.id, attachment]));
    for (const attachment of uploaded) {
      if (attachment?.id) byID.set(attachment.id, attachment);
    }
    referenceAttachments.value = Array.from(byID.values());
    showToast(`${uploaded.length} reference file${uploaded.length === 1 ? '' : 's'} uploaded.`);
  } catch (error) {
    referenceUploadError.value = error.message || 'Could not upload files.';
    showToast(referenceUploadError.value);
  } finally {
    referenceUploadBusy.value = false;
  }
}

function removeReferenceAttachment(id) {
  referenceAttachments.value = referenceAttachments.value.filter((attachment) => attachment.id !== id);
}

function projectDraftAttachment(attachment = {}) {
  return {
    id: attachment.id || '',
    original_name: attachment.original_name || '',
    stored_name: attachment.stored_name || '',
    content_type: attachment.content_type || '',
    size_bytes: Number(attachment.size_bytes) || 0,
    url: attachment.url || '',
    is_image: Boolean(attachment.is_image),
    created_at: attachment.created_at || '',
  };
}

function buildProjectDraft() {
  const setup = {};
  for (const key of Object.keys(projectSetupDefaults)) {
    setup[key] = projectSetupForm[key];
  }
  return {
    version: 1,
    saved_at: new Date().toISOString(),
    wizard_stage: projectWizardStage.value === 'funding' ? 'funding' : 'setup',
    wizard_step: normalizeProjectWizardStep(projectWizardStep.value),
    setup,
    deliverables: projectDeliverables.value.map((item) => String(item || '')),
    funding_amount: Number(projectFundingAmount.value) || '',
    payment_method: supportedProjectPaymentMethod(projectPaymentMethod.value),
    crypto_reference: String(projectCryptoReference.value || '').trim(),
    reference_attachments: referenceAttachments.value.map(projectDraftAttachment).filter((attachment) => attachment.id),
  };
}

function projectDraftHasContent(draft = {}) {
  const setup = draft.setup || {};
  return Object.keys(projectSetupDefaults).some((key) => {
    const value = setup[key];
    const fallback = projectSetupDefaults[key];
    return typeof value === 'boolean' ? value !== fallback : String(value || '').trim() !== String(fallback || '').trim();
  }) || (Array.isArray(draft.deliverables) && draft.deliverables.some((item) => String(item || '').trim()))
    || Number(draft.funding_amount) > 0
    || String(draft.crypto_reference || '').trim() !== ''
    || (Array.isArray(draft.reference_attachments) && draft.reference_attachments.length > 0);
}

function currentProjectDraftHasContent() {
  return projectDraftHasContent(buildProjectDraft());
}

function supportedProjectPaymentMethod(value = '') {
  const label = String(value || '').trim();
  const labels = paymentMethodOptions.map((method) => method.label);
  return labels.includes(label) ? label : 'Credit / Debit card';
}

function normalizeProjectDraft(raw = {}) {
  if (!raw || typeof raw !== 'object') return null;
  const setup = {};
  const rawSetup = raw.setup && typeof raw.setup === 'object' ? raw.setup : {};
  for (const [key, fallback] of Object.entries(projectSetupDefaults)) {
    if (typeof fallback === 'boolean') {
      setup[key] = typeof rawSetup[key] === 'boolean' ? rawSetup[key] : fallback;
    } else {
      setup[key] = rawSetup[key] === undefined || rawSetup[key] === null ? fallback : String(rawSetup[key]);
    }
  }
  const deliverables = Array.isArray(raw.deliverables)
    ? raw.deliverables.map((item) => String(item || '')).slice(0, 20)
    : [''];
  const attachments = Array.isArray(raw.reference_attachments)
    ? raw.reference_attachments.map(projectDraftAttachment).filter((attachment) => attachment.id).slice(0, 20)
    : [];
  return {
    version: 1,
    saved_at: String(raw.saved_at || ''),
    wizard_stage: raw.wizard_stage === 'funding' ? 'funding' : 'setup',
    wizard_step: normalizeProjectWizardStep(raw.wizard_step),
    setup,
    deliverables: deliverables.length ? deliverables : [''],
    funding_amount: Number(raw.funding_amount) > 0 ? Number(raw.funding_amount) : '',
    payment_method: supportedProjectPaymentMethod(raw.payment_method),
    crypto_reference: String(raw.crypto_reference || '').trim(),
    reference_attachments: attachments,
  };
}

function readProjectDraft() {
  try {
    const raw = browserStorage?.getItem(projectDraftStorageKey);
    if (!raw) return null;
    return normalizeProjectDraft(JSON.parse(raw));
  } catch {
    return null;
  }
}

function applyProjectDraft(draft = {}, options = {}) {
  Object.assign(projectSetupForm, draft.setup || projectSetupDefaults);
  projectDeliverables.value = Array.isArray(draft.deliverables) && draft.deliverables.length ? draft.deliverables : [''];
  projectFundingAmount.value = draft.funding_amount || '';
  projectPaymentMethod.value = supportedProjectPaymentMethod(draft.payment_method);
  projectCryptoReference.value = draft.crypto_reference || '';
  referenceAttachments.value = Array.isArray(draft.reference_attachments) ? draft.reference_attachments : [];
  priceEvaluation.value = null;
  priceEvaluationError.value = '';
  repoImportError.value = '';
  if (options.restoreStep) {
    projectWizardStage.value = draft.wizard_stage === 'funding' ? 'funding' : 'setup';
    projectWizardStep.value = normalizeProjectWizardStep(draft.wizard_step);
  }
}

function restoreProjectDraft(options = {}) {
  const draft = readProjectDraft();
  if (!draft || !projectDraftHasContent(draft)) return false;
  if (!options.force && currentProjectDraftHasContent()) return false;
  applyProjectDraft(draft, options);
  if (!options.silent) {
    showToast(draft.saved_at ? 'Project draft restored.' : 'Project draft loaded.');
  }
  return true;
}

function saveProjectDraft() {
  if (!browserStorage) {
    showToast('Local draft storage is not available in this browser.');
    return false;
  }
  const draft = buildProjectDraft();
  if (!projectDraftHasContent(draft)) {
    showToast('Add project details before saving a draft.');
    return false;
  }
  try {
    browserStorage.setItem(projectDraftStorageKey, JSON.stringify(draft));
    showToast('Project draft saved locally.');
    return true;
  } catch {
    showToast('Could not save the project draft locally.');
    return false;
  }
}

function clearProjectDraft() {
  try {
    browserStorage?.removeItem(projectDraftStorageKey);
  } catch {
    // Draft cleanup is best-effort and should not block checkout completion.
  }
}

function openAuthFromProjectWizard(mode = 'login') {
  closeProjectWizard();
  openAuth(mode);
}

async function openProjectPreview() {
  const invalidStep = firstInvalidProjectStep(4);
  if (invalidStep) {
    markProjectStepValidationAttempted(invalidStep);
    goProjectStep(invalidStep, { skipValidation: true });
    showProjectValidationToast(invalidStep);
    await nextTick();
    focusFirstProjectValidationError();
    return;
  }
  projectWizardStage.value = 'setup';
  projectWizardStep.value = 4;
  projectPreviewVisible.value = true;
  updateProjectWizardBrowserPath();
  await nextTick();
  projectPreviewDialog.value?.focus({ preventScroll: true });
}

function closeProjectPreview() {
  projectPreviewVisible.value = false;
}

function editProjectPreviewStep(stepNumber = 1) {
  closeProjectPreview();
  goProjectStep(stepNumber);
}

function publishProjectFromPreview() {
  closeProjectPreview();
  nextProjectStep();
}

function goProjectStep(stepNumber, options = {}) {
  const targetStep = normalizeProjectWizardStep(stepNumber);
  if (!options.skipValidation && projectWizardStage.value === 'setup' && targetStep > projectWizardStep.value) {
    const invalidStep = firstInvalidProjectStep(targetStep - 1);
    if (invalidStep) {
      markProjectStepValidationAttempted(invalidStep);
      projectPreviewVisible.value = false;
      projectWizardStage.value = 'setup';
      projectWizardStep.value = invalidStep;
      updateProjectWizardBrowserPath();
      scrollProjectFlowTop();
      showProjectValidationToast(invalidStep);
      void nextTick().then(focusFirstProjectValidationError);
      return;
    }
  }
  clearToast();
  projectPreviewVisible.value = false;
  projectWizardStage.value = 'setup';
  projectWizardStep.value = targetStep;
  updateProjectWizardBrowserPath();
  scrollProjectFlowTop();
}

function nextProjectStep() {
  projectPreviewVisible.value = false;
  const invalidStep = firstInvalidProjectStep(projectWizardStep.value);
  if (invalidStep) {
    markProjectStepValidationAttempted(invalidStep);
    if (invalidStep !== projectWizardStep.value) {
      projectWizardStep.value = invalidStep;
      updateProjectWizardBrowserPath();
      scrollProjectFlowTop();
    }
    showProjectValidationToast(invalidStep);
    void nextTick().then(focusFirstProjectValidationError);
    return;
  }

  if (projectWizardStep.value < 4) {
    clearToast();
    projectWizardStep.value += 1;
    updateProjectWizardBrowserPath();
    scrollProjectFlowTop();
    return;
  }

  if (projectBudgetAmount.value > 0 && projectBudgetAmount.value < TOKEN_RATE_PER_USD * 100) {
    projectSetupForm.budgetAmount = TOKEN_RATE_PER_USD * 100;
  }
  projectFundingAmount.value = Math.max(100, Math.ceil(projectBudgetAmount.value / TOKEN_RATE_PER_USD) || projectFundingAmount.value);
  projectWizardStage.value = 'funding';
  updateProjectWizardBrowserPath();
  scrollProjectFlowTop();
  showToast('Project published. Add funds to start receiving proposals.');
}

function buildPriceEvaluationPayload() {
  return {
    title: projectSetupForm.title,
    description: [projectSetupForm.shortDescription, projectSetupForm.overview].filter(Boolean).join('\n\n'),
    project_type: projectSetupForm.projectType,
    requirements: projectSetupForm.requirements,
    deliverables: visibleDeliverables.value,
    timeline: projectTimelineLabel.value,
    tech_stack: projectSetupForm.techStack,
    complexity: projectSetupForm.allowAgents ? 'moderate' : 'high',
    constraints: projectSetupForm.skills,
    reference_budget_cents: centsFromMRG(projectSetupForm.budgetAmount),
  };
}

function priceEvaluationValidationErrorsForCurrentInput() {
  const errors = {};
  const title = projectSetupForm.title.trim();
  const scope = [
    projectSetupForm.shortDescription,
    projectSetupForm.overview,
    projectSetupForm.requirements,
  ].filter(Boolean).join(' ').replace(/\s+/g, ' ').trim();

  if (title.length < 8) {
    errors.title = 'Enter a project title with at least 8 characters.';
  }
  if (scope.length < 40) {
    errors.scope = 'Describe the scope in at least 40 characters before estimating.';
  }
  return errors;
}

function firstPriceEvaluationError(errors = priceEvaluationValidationErrors.value) {
  return errors.title || errors.scope || Object.values(errors)[0] || '';
}

function priceEvaluationFieldError(field = '') {
  if (!priceEvaluationShouldShowErrors.value) return '';
  return priceEvaluationValidationErrors.value[field] || '';
}

function clearPriceEvaluationFieldError(field = '') {
  if (!field || !priceEvaluationValidationErrors.value[field]) return;
  priceEvaluationValidationErrors.value = {
    ...priceEvaluationValidationErrors.value,
    [field]: '',
  };
  for (const [key, message] of Object.entries(priceEvaluationValidationErrors.value)) {
    if (!message) delete priceEvaluationValidationErrors.value[key];
  }
  if (!Object.keys(priceEvaluationValidationErrors.value).length) {
    priceEvaluationError.value = '';
  }
}

function focusFirstPriceEvaluationValidationError() {
  if (!hasWindow) return;
  window.requestAnimationFrame(() => {
    const target = document.querySelector('.dashboard-tool-form label.invalid input, .dashboard-tool-form label.invalid textarea');
    target?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    target?.focus?.({ preventScroll: true });
  });
}

async function runProjectPriceEvaluation() {
  priceEvaluationError.value = '';
  priceEvaluationShouldShowErrors.value = true;
  const validationErrors = priceEvaluationValidationErrorsForCurrentInput();
  priceEvaluationValidationErrors.value = validationErrors;
  if (Object.keys(validationErrors).length) {
    priceEvaluation.value = null;
    priceEvaluationError.value = firstPriceEvaluationError(validationErrors);
    showToast(priceEvaluationError.value);
    if (projectWizardVisible.value) {
      const invalidStep = validationErrors.title ? 1 : 2;
      markProjectStepValidationAttempted(invalidStep);
      projectWizardStep.value = invalidStep;
      updateProjectWizardBrowserPath();
      void nextTick().then(focusFirstProjectValidationError);
    } else {
      void nextTick().then(focusFirstPriceEvaluationValidationError);
    }
    return;
  }
  if (!user.value) {
    authReturnToProjectWizard.value = projectWizardVisible.value;
    if (projectWizardVisible.value) {
      projectWizardVisible.value = false;
    }
    openAuth('login');
    showToast('Log in to estimate this project.');
    return;
  }
  if (priceEvaluationBusy.value) return;
  priceEvaluationBusy.value = true;
  try {
    priceEvaluation.value = await api('/api/projects/evaluate-price', {
      method: 'POST',
      body: JSON.stringify(buildPriceEvaluationPayload()),
    });
    priceEvaluationValidationErrors.value = {};
    priceEvaluationShouldShowErrors.value = false;
    applyPriceEvaluation();
    showToast('Budget estimate generated.');
  } catch (error) {
    priceEvaluationError.value = error.message;
    showToast(error.message);
  } finally {
    priceEvaluationBusy.value = false;
  }
}

function applyPriceEvaluation() {
  if (!priceEvaluation.value?.suggested_price_cents) return;
  projectSetupForm.budgetAmount = Math.max(TOKEN_RATE_PER_USD * 100, tokenAmountFromCents(priceEvaluation.value.suggested_price_cents));
  projectSetupForm.budgetType = 'Range';
}

function projectWizardBack() {
  if (projectWizardStage.value === 'success') {
    projectWizardStage.value = 'funding';
    updateProjectWizardBrowserPath();
    scrollProjectFlowTop();
    return;
  }

  if (projectWizardStage.value === 'funding') {
    projectWizardStage.value = 'setup';
    projectWizardStep.value = 4;
    updateProjectWizardBrowserPath();
    scrollProjectFlowTop();
    return;
  }

  if (projectWizardStep.value > 1) {
    projectWizardStep.value -= 1;
    updateProjectWizardBrowserPath();
    scrollProjectFlowTop();
    return;
  }

  closeProjectWizard();
}

function requireLoginForProjectPayment() {
  pendingProjectPaymentAfterAuth.value = true;
  authReturnToProjectWizard.value = true;
  projectPaymentError.value = '';
  projectWizardVisible.value = false;
  openAuth('login');
  showToast('Log in to continue payment.');
}

async function completeProjectFunding() {
  projectFundingValidationAttempted.value = true;
  projectPaymentError.value = '';

  const invalidStep = firstInvalidProjectStep(4);
  if (invalidStep) {
    projectWizardStage.value = 'setup';
    projectWizardStep.value = invalidStep;
    markProjectStepValidationAttempted(invalidStep);
    updateProjectWizardBrowserPath();
    scrollProjectFlowTop();
    showProjectValidationToast(invalidStep);
    void nextTick().then(focusFirstProjectValidationError);
    return;
  }

  try {
    await loadRuntimeConfig();
  } catch (error) {
    projectPaymentError.value = error.message || 'Could not load payment configuration.';
    showToast(projectPaymentError.value);
    return;
  }

  if (projectFundingErrorCount()) {
    showProjectFundingValidationToast();
    void nextTick().then(focusFirstProjectFundingValidationError);
    return;
  }

  if (!user.value) {
    requireLoginForProjectPayment();
    return;
  }

  if (projectPaymentBusy.value) return;
  projectPaymentBusy.value = true;
  try {
    const paymentMethod = paymentMethodForProject();
    if (paymentMethod === 'card') {
      const intent = await createProjectCardPaymentIntent();
      await submitProjectFunding(buildCreateProjectPayload({
        payment_method: 'stripe',
        payment_reference: intent.payment_reference,
      }), {
        paymentMethodLabel: cardPaymentLabel(intent),
      });
      return;
    }
    const devPaymentReference = projectDevPaymentReference();
    if (devPaymentReference) {
      await submitProjectFunding(buildCreateProjectPayload({
        payment_method: paymentMethod,
        payment_reference: devPaymentReference,
      }));
      return;
    }
    if (paymentMethod === 'paypal' && runtimeConfig.value?.paypal_ready) {
      await startProjectPayPalFunding();
      return;
    }
    if (paymentMethod === 'crypto') {
      if (!projectCryptoReference.value) {
        throw new Error('Paste the confirmed Solana transaction signature before funding.');
      }
      await submitProjectFunding(buildCreateProjectPayload({
        payment_method: 'crypto',
        payment_reference: projectCryptoReference.value,
      }), {
        paymentMethodLabel: 'USDC',
      });
      return;
    }
    throw new Error(paymentMethod === 'crypto'
      ? 'Crypto checkout needs a Solana signature before project funding can be verified.'
      : 'PayPal checkout is not configured. Enable PayPal credentials or local dev payments.');
  } catch (error) {
    if (error.status === 401 || /login is required/i.test(error.message || '')) {
      requireLoginForProjectPayment();
      return;
    }
    projectPaymentError.value = error.message;
    showToast(error.message);
  } finally {
    projectPaymentBusy.value = false;
  }
}

async function createProjectCardPaymentIntent() {
  const payload = buildCreateProjectPayload({ payment_method: 'stripe' });
  return createCardPaymentIntent({
    amount_cents: projectPaymentAmountCents.value,
    description: projectPayPalDescription(payload),
    flow: 'project_funding',
    cardholder_name: projectCardForm.cardholderName || user.value?.name || '',
  });
}

async function createCardPaymentIntent(payload = {}) {
  const intent = await api('/api/payments/card/intents', {
    method: 'POST',
    body: JSON.stringify(payload),
  });
  if (!intent?.payment_reference) {
    throw new Error('Card processor did not return a payment reference.');
  }
  return intent;
}

function cardPaymentLabel(intent = {}) {
  const brand = toTitleLabel(intent.brand || 'card');
  return intent.last4 ? `${brand} ending ${intent.last4}` : 'Credit / Debit card';
}

async function startProjectPayPalFunding() {
  if (!hasWindow) {
    throw new Error('PayPal checkout requires a browser session.');
  }
  const payload = buildCreateProjectPayload({
    payment_method: 'paypal',
    payment_reference: '',
  });
  const returnURL = absolutePublicPath('/paypal/return?flow=project_funding');
  const cancelURL = absolutePublicPath('/paypal/cancel?flow=project_funding');
  const order = await api('/api/payments/paypal/orders', {
    method: 'POST',
    body: JSON.stringify({
      amount_cents: payload.budget_cents,
      description: projectPayPalDescription(payload),
      flow: 'project_funding',
      return_url: returnURL,
      cancel_url: cancelURL,
    }),
  });
  if (!order?.approval_url || !order?.order_id) {
    throw new Error('PayPal did not return an approval URL.');
  }
  writePendingProjectFunding({
    flow: 'project_funding',
    payload,
    fundingAmount: Number(projectFundingAmount.value) || Math.round(payload.budget_cents / 100),
    paymentMethodLabel: projectPaymentMethod.value,
    orderID: order.order_id,
    createdAt: Date.now(),
  });
  showToast('Redirecting to PayPal checkout...');
  window.location.href = order.approval_url;
}

async function submitProjectFunding(payload = {}, options = {}) {
  const project = await api('/api/projects', {
    method: 'POST',
    body: JSON.stringify(payload),
  });
  fundedProject.value = project;
  if (Number(options.fundingAmount) > 0) {
    projectFundingAmount.value = Number(options.fundingAmount);
  } else if (Number(payload.budget_cents) > 0) {
    projectFundingAmount.value = Math.max(100, Math.round(Number(payload.budget_cents) / 100));
  }
  projectPaymentSuccessMethod.value = options.paymentMethodLabel || projectPaymentMethod.value;
  projectWizardVisible.value = true;
  projectWizardStage.value = 'success';
  projectWizardStep.value = 4;
  updateProjectWizardBrowserPath(Boolean(options.replacePath));
  pendingProjectPaymentAfterAuth.value = false;
  authReturnToProjectWizard.value = false;
  await loadLedgerData({ silent: true });
  await loadMarketplaceData({ silent: true });
  await loadDashboardData({ silent: true, selectProjectID: project.id });
  referenceAttachments.value = [];
  referenceUploadError.value = '';
  clearProjectDraft();
  resetProjectPaymentInputs();
  scrollProjectFlowTop();
  showToast('Payment recorded and tokens minted.');
  return project;
}

function resetProjectPaymentInputs() {
  projectFundingValidationAttempted.value = false;
  projectPaymentError.value = '';
  projectCryptoReference.value = '';
  Object.assign(projectCardForm, {
    cardNumber: '',
    expiry: '',
    cvc: '',
    cardholderName: '',
  });
}

function projectPayPalDescription(payload = {}) {
  const title = String(payload.title || projectTitleLabel.value || 'MergeOS project').trim();
  const runes = Array.from(`MergeOS project funding: ${title}`);
  return runes.length <= 120 ? runes.join('') : `${runes.slice(0, 117).join('').trim()}...`;
}

function repositorySuggestedTaskFundingDescription(task = {}) {
  const title = String(task.title || task.name || 'repository task').trim();
  const runes = Array.from(`MergeOS repository task funding: ${title}`);
  return runes.length <= 120 ? runes.join('') : `${runes.slice(0, 117).join('').trim()}...`;
}

function addDeliverable() {
  projectDeliverables.value.push('');
}

function removeDeliverable(index) {
  if (projectDeliverables.value.length <= 1) {
    projectDeliverables.value = [''];
    return;
  }

  projectDeliverables.value.splice(index, 1);
}

function loginWithSocial(provider) {
  const ready = provider === 'google' ? googleOAuthReady.value : githubOAuthReady.value;
  if (!ready) {
    const label = provider === 'google' ? 'Google OAuth' : 'GitHub App login';
    errorMessage.value = `${label} is not configured yet.`;
    showToast(errorMessage.value);
    return;
  }
  showToast(`Redirecting to ${provider === 'google' ? 'Google' : 'GitHub'}...`);
  window.location.href = `/api/auth/${provider}/login`;
}

async function triggerAiEvaluation() {
  aiEvaluationLoading.value = true;
  aiEvaluationError.value = '';
  aiEvaluationResult.value = null;
  try {
    const payload = {
      description: projectSetupForm.overview || projectSetupForm.shortDescription || '',
      requirements: projectSetupForm.requirements
        ? projectSetupForm.requirements.split('\n').map(r => r.trim()).filter(Boolean)
        : [],
      deliverables: visibleDeliverables.value,
      timeline: projectTimelineLabel.value,
      tech_stack: projectSetupForm.techStack || '',
      complexity: projectSetupForm.complexity || 'Medium',
      constraints: projectSetupForm.constraints || '',
      reference_budget: Math.round(usdFromMRG(projectSetupForm.budgetAmount))
    };

    // Try LLM-powered evaluation first, with fallback to rule-based
    try {
      const response = await api('/api/projects/evaluate-llm', {
        method: 'POST',
        body: JSON.stringify(payload)
      });
      aiEvaluationResult.value = response;
    } catch (_llmErr) {
      // LLM endpoint unavailable â€” use rule-based evaluation
      const response = await api('/api/projects/evaluate', {
        method: 'POST',
        body: JSON.stringify(payload)
      });
      aiEvaluationResult.value = response;
    }
  } catch (err) {
    console.error('AI evaluation failed:', err);
    aiEvaluationError.value = err.message || 'AI evaluation failed. Please try again.';
  } finally {
    aiEvaluationLoading.value = false;
  }
}

function applyAiSuggestedPrice() {
  if (aiEvaluationResult.value) {
    const avg = Math.round((aiEvaluationResult.value.suggested_low + aiEvaluationResult.value.suggested_high) / 2);
    projectSetupForm.budgetAmount = mrgFromUSD(avg);
    showToast(`Applied AI suggested budget: ${formatMRGFromUSD(avg)}`);
  }
}

function formatMoney(value) {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0,
  }).format(Number(value) || 0);
}

function formatFileSize(bytes = 0) {
  const value = Number(bytes) || 0;
  if (value < 1024) return `${value} B`;
  if (value < 1024 * 1024) return `${Math.round(value / 1024)} KB`;
  return `${(value / (1024 * 1024)).toFixed(value < 10 * 1024 * 1024 ? 1 : 0)} MB`;
}

function mrgFromUSD(value = 0) {
  return Math.round((Number(value) || 0) * TOKEN_RATE_PER_USD);
}

function usdFromMRG(value = 0) {
  return (Number(value) || 0) / TOKEN_RATE_PER_USD;
}

function centsFromMRG(value = 0) {
  return Math.round(usdFromMRG(value) * 100);
}

function formatMRG(value = 0) {
  return `${formatCompactNumber(value)} ${tokenSymbol.value}`;
}

function formatMRGFromUSD(value = 0) {
  return formatMRG(mrgFromUSD(value));
}

function formatMRGFromCents(cents = 0) {
  return formatMRG(tokenAmountFromCents(cents));
}

function formatLedgerMRGFromCents(cents = 0) {
  return formatMRGFromCents(cents);
}

function formatPublicMRGFromCents(cents = 0) {
  return formatMRGFromCents(cents);
}

function formatPublicTokenAmount(amount = 0) {
  return `${formatCompactNumber(amount)} ${tokenSymbol.value}`;
}

function formatHomeMRGFromCents(cents = 0) {
  return `${formatCompactMetricNumber(tokenAmountFromCents(cents))} ${tokenSymbol.value}`;
}

function formatHomeTokenAmount(amount = 0) {
  return `${formatCompactMetricNumber(amount)} ${tokenSymbol.value}`;
}

function formatCompactNumber(value = 0) {
  return new Intl.NumberFormat('en-US', {
    maximumFractionDigits: value >= 100 ? 0 : 1,
  }).format(Number(value) || 0);
}

function formatCompactMetricNumber(value = 0) {
  const numeric = Number(value) || 0;
  return new Intl.NumberFormat('en-US', {
    notation: 'compact',
    maximumFractionDigits: Math.abs(numeric) >= 1000000 ? 1 : 0,
  }).format(numeric);
}

function tokenAmountFromCents(cents = 0) {
  return Math.round(((Number(cents) || 0) / 100) * TOKEN_RATE_PER_USD);
}

function toTitleLabel(value = '') {
  return String(value)
    .trim()
    .split(/[\s._:-]+/)
    .filter(Boolean)
    .map((word) => {
      const lower = word.toLowerCase();
      if (['ai', 'api', 'ceo', 'dao', 'idl', 'mrg', 'pr', 'qa', 'sdk', 'ui', 'url', 'ux', 'go'].includes(lower)) return lower.toUpperCase();
      if (lower === 'devops') return 'DevOps';
      return `${lower.charAt(0).toUpperCase()}${lower.slice(1)}`;
    })
    .join(' ');
}

function dashboardStatusClass(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (!normalized) return 'is-waiting';
  if (/(error|failed|failure|attention)/.test(normalized)) return 'is-error';
  if (/(sync|scan|loading|refresh|fetch|recording)/.test(normalized)) return 'is-syncing';
  if (/(needs|review|finding|warning|blocked|queued|pending)/.test(normalized)) return 'is-warning';
  if (/(waiting|empty|no data|not loaded|not set)/.test(normalized)) return 'is-waiting';
  if (/(clear|live|ready|funded|released|paid|verified|protocol|routed|open|worker)/.test(normalized)) return 'is-live';
  return 'is-neutral';
}

function paymentModeLabel(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  return {
    'live-adapters': 'Live payment adapters',
    'local-dev-verifier': 'MergeOS verifier',
    'not-configured': 'Not configured',
    '': 'Not loaded',
  }[normalized] || toTitleLabel(value);
}

function repoProviderLabel(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (!normalized) return 'Not loaded';
  if (normalized.startsWith('github-private:')) return 'GitHub private repos';
  if (normalized === 'local-git') return 'MergeOS repositories';
  return toTitleLabel(value);
}

function formatMarketplaceDate(value) {
  const date = value ? new Date(value) : null;
  const label = publicMarketplaceCopy.value.projectLabels.funded;
  if (!date || Number.isNaN(date.getTime())) return label;
  return `${label} ${date.toLocaleDateString(activeLocale.value, { month: 'short', day: 'numeric' })}`;
}

function trimMarketplaceText(value = '', fallback = 'Funded MergeOS project with escrow-backed tasks and ledger proof.') {
  const text = String(value || '').replace(/\s+/g, ' ').trim();
  if (!text) return fallback;
  return text.length > 150 ? `${text.slice(0, 147).trim()}...` : text;
}

function shortAgentEndpoint(value = '') {
  const clean = String(value || '').replace(/^https?:\/\/[^/]+/i, '').trim();
  if (!clean) return 'endpoint';
  return clean.length > 42 ? `${clean.slice(0, 39)}...` : clean;
}

function marketplaceProjectIcon(project = {}) {
  const text = [
    project.title,
    project.brief,
    project.site_type,
    ...(project.tags || []),
  ].join(' ').toLowerCase();
  if (text.includes('mobile')) return Phone;
  if (text.includes('ai') || text.includes('agent')) return Bot;
  if (text.includes('analytics') || text.includes('dashboard')) return BarChart3;
  if (text.includes('payment') || text.includes('checkout') || text.includes('ledger')) return CreditCard;
  if (text.includes('api') || text.includes('code')) return Code2;
  return Globe2;
}

function marketplaceAgentIcon(type = '') {
  const text = String(type).toLowerCase();
  if (text.includes('design')) return PenLine;
  if (text.includes('ledger') || text.includes('go')) return CreditCard;
  if (text.includes('devops')) return GitBranch;
  if (text.includes('qa') || text.includes('test')) return CheckCircle2;
  if (text.includes('front')) return Code2;
  return Bot;
}

function mapMarketplaceProject(project = {}, index = 0) {
  const palette = marketplaceProjectPalettes[index % marketplaceProjectPalettes.length];
  const labels = publicMarketplaceCopy.value.projectLabels;
  const rawTags = (project.tags || []).map(toTitleLabel).filter(Boolean);
  const tags = rawTags.length ? rawTags : [toTitleLabel(project.site_type || 'Project')];
  const openTasks = Number(project.open_task_count) || 0;
  const acceptedTasks = Number(project.accepted_task_count) || 0;
  const taskCount = Number(project.task_count) || openTasks + acceptedTasks;
  const client = project.client_display_name || labels.client;
  const badge = openTasks > 0 ? `${openTasks} ${labels.open}` : (acceptedTasks > 0 ? labels.paidOut : toTitleLabel(project.status || labels.live));
  return {
    id: project.id || `project-${index}`,
    icon: marketplaceProjectIcon(project),
    badge,
    badgeTone: openTasks > 0 ? palette.badgeTone : 'green',
    title: project.title || labels.untitled,
    body: trimMarketplaceText(project.brief, labels.bodyFallback),
    tags: tags.slice(0, 3),
    extra: Math.max(0, tags.length - 3),
    budgetCents: Number(project.budget_cents) || 0,
    budget: formatPublicMRGFromCents(project.budget_cents),
    timeline: project.timeline || formatMarketplaceDate(project.created_at),
    client,
    clientInitials: initialsFor(client),
    avatarTone: palette.avatarTone,
    taskLabel: `${taskCount} ${taskCount === 1 ? labels.taskSingular : labels.taskPlural}`,
    verified: project.status === 'funded',
    urgent: openTasks > 0,
    accent: palette.accent,
    soft: palette.soft,
    workflowUrl: publicProjectWorkflowURL(project.id || `project-${index}`),
    workflowPulseUrl: absolutePublicPath(`/api/public/projects/${encodeURIComponent(project.id || `project-${index}`)}/workflow-pulse`),
    source_repo_url: project.source_repo_url || '',
    repo_url: project.repo_url || '',
    bounty_repo_name: project.bounty_repo_name || '',
    repo_provider: project.repo_provider || '',
  };
}

function mapMarketplaceBounty(bounty = {}, index = 0) {
  const labels = publicMarketplaceCopy.value.projectLabels;
  const workerKind = bounty.required_worker_kind || 'human';
  const agentType = bounty.suggested_agent_type || '';
  const issueNumber = Number(bounty.issue_number) || 0;
  const id = bounty.id || `${bounty.project_id || 'project'}:${issueNumber || index}`;
  const claimID = bounty.claim_id || id;
  return {
    id,
    claimId: claimID,
    claimEndpoint: bounty.claim_endpoint || `/api/tasks/${claimID}/claim`,
    proposalEndpoint: bounty.proposal_endpoint || '',
    icon: agentType ? marketplaceAgentIcon(agentType) : (workerKind === 'human' ? User : Bot),
    title: bounty.title || labels.openBounty,
    acceptance: trimMarketplaceText(bounty.acceptance, labels.acceptanceFallback),
    project: bounty.project_title || labels.projectFallback,
    rewardCents: Number(bounty.reward_cents) || 0,
    reward: formatPublicMRGFromCents(bounty.reward_cents),
    lane: agentType ? toTitleLabel(agentType) : toTitleLabel(workerKind),
    workerKind,
    agentType,
    issue: issueNumber > 0 ? `#${issueNumber}` : labels.waitingTask,
    url: bounty.issue_url || '',
    protocolUrl: publicTaskProtocolURL(id),
    tone: ['green', 'blue', 'purple', 'amber'][index % 4],
  };
}

function publicTaskProtocolPath(taskID = '') {
  const id = String(taskID || '').trim();
  return id ? `/api/public/protocol/tasks?task_id=${encodeURIComponent(id)}` : '/api/public/protocol/tasks';
}

function publicTaskProtocolURL(taskID = '') {
  return absolutePublicPath(publicTaskProtocolPath(taskID));
}

function publicProjectWorkflowPath(projectID = '') {
  const id = String(projectID || '').trim();
  return id ? `/api/public/projects/${encodeURIComponent(id)}/workflow` : '';
}

function publicProjectWorkflowURL(projectID = '') {
  const path = publicProjectWorkflowPath(projectID);
  return path ? absolutePublicPath(path) : '';
}

function absolutePublicPath(path = '') {
  const normalized = String(path || '/');
  if (!hasWindow) return normalized;
  return `${window.location.origin}${normalized.startsWith('/') ? normalized : `/${normalized}`}`;
}

function marketplaceSearchHaystack(project = {}) {
  return [
    project.title,
    project.body,
    project.client,
    project.budget,
    project.timeline,
    project.source_repo_url,
    project.repo_url,
    project.bounty_repo_name,
    ...(project.tags || []),
  ].join(' ').toLowerCase();
}

function marketplaceBountyHaystack(bounty = {}) {
  return [
    bounty.title,
    bounty.acceptance,
    bounty.project,
    bounty.reward,
    bounty.lane,
    bounty.issue,
  ].join(' ').toLowerCase();
}

function marketplaceAgentHaystack(agent = {}) {
  return [
    agent.type,
    agent.title,
    agent.body,
    agent.displayBody,
    agent.capability,
    agent.status,
    agent.rewardLabel,
    agent.capacityLabel,
    ...(agent.labels || []),
  ].join(' ').toLowerCase();
}

function matchesMarketplaceBudget(cents = 0) {
  const tokens = tokenAmountFromCents(cents);
  switch (activeMarketplaceBudget.value) {
  case 'Under 50K MRG':
    return tokens > 0 && tokens < 50000;
  case '50K-250K MRG':
    return tokens >= 50000 && tokens < 250000;
  case '250K+ MRG':
    return tokens >= 250000;
  default:
    return true;
  }
}

function matchesMarketplaceDelivery(project = {}) {
  const filter = activeMarketplaceDelivery.value;
  if (filter === 'Any delivery') return true;
  const timeline = String(project.timeline || '').toLowerCase();
  const dayMatch = timeline.match(/(\d+)\s+days?/);
  const days = dayMatch ? Number(dayMatch[1]) : 0;
  if (filter === 'Urgent') {
    return project.urgent || timeline.includes('urgent') || timeline.includes('asap') || timeline.includes('week');
  }
  if (filter === '30 days') {
    return days > 0 ? days <= 30 : timeline.includes('month');
  }
  if (filter === 'Quarter+') {
    return days >= 90 || timeline.includes('quarter') || timeline.includes('ongoing');
  }
  return true;
}

function nextOption(options = [], current = '') {
  if (!options.length) return current;
  const index = options.indexOf(current);
  return options[(index + 1) % options.length] || options[0];
}

function cycleMarketplaceCategory() {
  activeMarketplaceCategory.value = nextOption(marketplaceCategories.value, activeMarketplaceCategory.value);
}

function cycleMarketplaceBudget() {
  activeMarketplaceBudget.value = nextOption(marketplaceBudgetOptions, activeMarketplaceBudget.value);
}

function cycleMarketplaceDelivery() {
