  activeMarketplaceDelivery.value = 'Any delivery';
}

function claimPayloadForBounty(bounty = {}) {
  const packetPayload = bounty.claimPayload && typeof bounty.claimPayload === 'object' ? bounty.claimPayload : {};
  const workerKind = packetPayload.worker_kind || bounty.workerKind || bounty.required_worker_kind || 'human';
  const agentType = packetPayload.agent_type || bounty.agentType || bounty.suggested_agent_type || '';
  return {
    ...packetPayload,
    worker_kind: workerKind,
    worker_id: claimWorkerIDForProfile() || packetPayload.worker_id || 'current-user',
    agent_type: workerKind === 'human' ? '' : (agentType || 'mergeos-agent'),
  };
}

function proposalCoverLetterForBounty(bounty = {}) {
  const issue = bounty.issue ? `${bounty.issue} ` : '';
  const title = trimMarketplaceText(bounty.title, 'this bounty');
  const project = trimMarketplaceText(bounty.project, 'this MergeOS project');
  const acceptance = trimMarketplaceText(bounty.acceptance, 'the published acceptance criteria');
  const workerID = claimWorkerIDForProfile() || 'current session';
  return trimMarketplaceText(
    `I can deliver ${issue}${title} for ${project}. Scope: ${acceptance} I will attach PR evidence, tests, and release notes through MergeOS. Worker identity: ${workerID}.`,
    'I can deliver this bounty with PR evidence, tests, and release notes through MergeOS.',
  );
}

function proposalPayloadForBounty(bounty = {}) {
  const estimatedHours = Number(bounty.estimatedHours) > 0 ? Number(bounty.estimatedHours) : Math.max(1, Math.ceil((Number(bounty.rewardCents) || 5000) / 2500));
  const bidCents = Number(bounty.rewardCents) > 0 ? Number(bounty.rewardCents) : 5000;
  return {
    task_id: bounty.claimId || bounty.id,
    cover_letter: proposalCoverLetterForBounty(bounty),
    bid_cents: bidCents,
    estimated_hours: estimatedHours,
    availability: 'Available after customer approval',
  };
}

async function claimMarketplaceBounty(bounty = {}, options = {}) {
  if (!bounty?.id || claimingBountyID.value) return;
  if (bounty.canClaim === false) {
    showToast('This proposal is no longer available.');
    return;
  }
  if (!token.value || !user.value) {
    pendingClaimBounty.value = bounty;
    openAuth('login');
    showToast('Log in to claim this bounty.');
    return;
  }

  claimingBountyID.value = bounty.id;
  try {
    const endpoint = bounty.claimEndpoint || `/api/tasks/${encodeURIComponent(bounty.id)}/claim`;
    const claimed = await api(endpoint, {
      method: 'POST',
      body: JSON.stringify(claimPayloadForBounty(bounty)),
    });
    pendingClaimBounty.value = null;
    await Promise.all([
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
      loadWorkerDashboardData({ silent: true }),
      loadDashboardData({ silent: true }),
    ]);
    if (dashboardSection.value !== 'worker' && options.openWorker !== false) {
      dashboardSection.value = 'worker';
    }
    showToast(`Claimed task #${claimed.issue_number || ''}. Payout stays locked until review.`);
  } catch (error) {
    showToast(error.message || 'Could not claim bounty.');
  } finally {
    claimingBountyID.value = '';
  }
}

async function submitWorkerProposal(proposal = {}) {
  if (!proposal?.id || proposingBountyID.value) return;
  if (proposal.canClaim === false) {
    showToast('This proposal is no longer available.');
    return;
  }
  if (!token.value || !user.value) {
    openAuth('login');
    showToast('Log in to send a proposal.');
    return;
  }

  proposingBountyID.value = proposal.id;
  try {
    const created = await api('/api/proposals', {
      method: 'POST',
      body: JSON.stringify(proposalPayloadForBounty(proposal)),
    });
    await Promise.all([
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
      loadWorkerDashboardData({ silent: true }),
      loadDashboardData({ silent: true }),
      loadDashboardNotifications(),
    ]);
    dashboardSection.value = 'worker';
    showToast(`Proposal sent for ${proposal.issue || created.proposal?.title || 'the bounty'}.`);
  } catch (error) {
    showToast(error.message || 'Could not send proposal.');
  } finally {
    proposingBountyID.value = '';
  }
}

async function recordAgentQueueAction(task = {}, actionRow = {}) {
  const body = actionRow.body || {};
  const action = body.action || actionRow.action || '';
  if (!action) {
    showToast('Agent action payload is missing.');
    return;
  }
  if (!token.value || !user.value) {
    openAuth('login');
    showToast('Log in to record agent action evidence.');
    return;
  }
  const key = actionRow.key || `${task.id || 'agent'}:${action}`;
  if (recordingAgentActionKey.value) return;
  recordingAgentActionKey.value = key;
  try {
    const claimID = body.claim_id || body.bounty_id || task.claimID || task.bountyID || task.bounty_id || task.id;
    const payload = {
      ...body,
      claim_id: claimID,
      bounty_id: body.bounty_id || claimID,
      project_id: body.project_id || task.projectID,
      agent_type: body.agent_type || task.agentType,
      action,
      status: body.status && body.status !== 'queued' ? body.status : 'processed',
    };
    const endpoint = actionRow.endpoint || task.actionEndpoint || '/api/agents/actions';
    await api(endpoint, {
      method: 'POST',
      body: JSON.stringify(payload),
    });
    await Promise.all([
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
      loadDashboardData({ silent: true, selectProjectID: selectedDashboardProjectID.value }),
    ]);
    showToast(`Agent ${toTitleLabel(action)} recorded.`);
  } catch (error) {
    showToast(error.message || 'Could not record agent action.');
  } finally {
    recordingAgentActionKey.value = '';
  }
}

async function leaseAgentWorkPacket(task = {}) {
  const claimID = task.id || task.bounty_id || task.bountyID || task.claim_id || task.claimID || '';
  if (!claimID) {
    showToast('Agent lease needs a task claim ID.');
    return;
  }
  if (!token.value || !user.value) {
    openAuth('login');
    showToast('Log in to lease this agent work packet.');
    return;
  }
  if (leasingAgentTaskID.value) return;
  leasingAgentTaskID.value = claimID;
  try {
    const existingLease = agentLeaseResponses[claimID] || task.lease || {};
    const payload = {
      lease_id: existingLease.lease_id || '',
      claim_id: claimID,
      bounty_id: claimID,
      agent_type: task.agentType || task.agent_type || '',
      status: existingLease.lease_id ? 'heartbeat' : 'leased',
    };
    const lease = await api('/api/agent-queue/leases', {
      method: 'POST',
      body: JSON.stringify(payload),
    });
    agentLeaseResponses[claimID] = lease;
    await Promise.all([
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
    ]);
    showToast(`Agent lease ${shortAgentEndpoint(lease.lease_id || claimID)} ${lease.status || 'created'}.`);
  } catch (error) {
    showToast(error.message || 'Could not lease agent work packet.');
  } finally {
    leasingAgentTaskID.value = '';
  }
}

async function openRepositorySuggestedTaskFunding(task = {}) {
  if (!dashboardSelectedProject.value?.id || !task?.id || fundingSuggestedTaskID.value) return;
  if (!token.value) {
    showToast('Log in to fund this repository task.');
    return;
  }
  if (task.canFund === false) {
    showToast(task.status === 'already_funded' ? 'This repository task is already funded.' : 'This repository task is not ready for funding.');
    return;
  }
  try {
    await loadRuntimeConfig();
  } catch (error) {
    showToast(error.message || 'Could not load payment configuration.');
    return;
  }
  repoTaskFundingTask.value = task;
  repoTaskFundingMethod.value = runtimeConfig.value?.paypal_ready || projectDevPaymentReference() ? 'PayPal' : 'Credit / Debit card';
  repoTaskFundingError.value = '';
  repoTaskFundingValidationAttempted.value = false;
  repoTaskFundingVisible.value = true;
}

function closeRepositoryTaskFunding(options = {}) {
  if (repoTaskFundingBusy.value && !options.force) return;
  repoTaskFundingVisible.value = false;
  resetRepositoryTaskFundingInputs();
}

function resetRepositoryTaskFundingInputs() {
  repoTaskFundingTask.value = null;
  repoTaskFundingError.value = '';
  repoTaskFundingValidationAttempted.value = false;
  repoTaskFundingCryptoReference.value = '';
  Object.assign(repoTaskFundingCardForm, {
    cardNumber: '',
    expiry: '',
    cvc: '',
    cardholderName: '',
  });
}

async function submitRepositorySuggestedTaskFunding() {
  const task = repoTaskFundingTask.value || {};
  if (!dashboardSelectedProject.value?.id || !task?.id || fundingSuggestedTaskID.value) return;
  repoTaskFundingValidationAttempted.value = true;
  repoTaskFundingError.value = '';
  try {
    await loadRuntimeConfig();
  } catch (error) {
    repoTaskFundingError.value = error.message || 'Could not load payment configuration.';
    showToast(repoTaskFundingError.value);
    return;
  }
  if (repoTaskFundingErrorCount()) {
    showToast(repoTaskFundingErrorCount() === 1 ? 'Fix 1 funding item before continuing.' : `Fix ${repoTaskFundingErrorCount()} funding items before continuing.`);
    return;
  }

  const projectID = dashboardSelectedProject.value.id;
  const rewardCents = Number(task.fundingPayload?.reward_cents || task.reward_cents) || 0;
  fundingSuggestedTaskID.value = task.id;
  repoTaskFundingBusy.value = true;
  try {
    const paymentMethod = paymentMethodForRepoTaskFunding();
    if (paymentMethod === 'card') {
      const intent = await createCardPaymentIntent({
        amount_cents: repoTaskFundingAmountCents.value,
        description: repositorySuggestedTaskFundingDescription(task),
        flow: 'repo_task_funding',
        cardholder_name: repoTaskFundingCardForm.cardholderName || user.value?.name || '',
      });
      await submitRepositorySuggestedTaskFundingRequest(projectID, task.id, rewardCents, 'stripe', intent.payment_reference, { task });
      closeRepositoryTaskFunding({ force: true });
      return;
    }
    const devPaymentReference = projectDevPaymentReference();
    if (devPaymentReference) {
      await submitRepositorySuggestedTaskFundingRequest(projectID, task.id, rewardCents, paymentMethod, devPaymentReference, { task });
      closeRepositoryTaskFunding({ force: true });
      return;
    }
    if (paymentMethod === 'paypal' && runtimeConfig.value?.paypal_ready) {
      await startRepositorySuggestedTaskPayPalFunding(projectID, task);
      return;
    }
    if (paymentMethod === 'crypto') {
      await submitRepositorySuggestedTaskFundingRequest(projectID, task.id, rewardCents, 'crypto', repoTaskFundingCryptoReference.value, { task });
      closeRepositoryTaskFunding({ force: true });
      return;
    }
    throw new Error(paymentMethod === 'crypto'
      ? 'USDC verification needs a Solana signature before task funding can be verified.'
      : 'PayPal checkout is not configured for repository task funding.');
  } catch (error) {
    repoTaskFundingError.value = error.message || 'Could not fund repository task.';
    showToast(repoTaskFundingError.value);
  } finally {
    fundingSuggestedTaskID.value = '';
    repoTaskFundingBusy.value = false;
  }
}

async function startRepositorySuggestedTaskPayPalFunding(projectID, task = {}) {
  if (!hasWindow) {
    throw new Error('PayPal checkout requires a browser session.');
  }
  const paypalPayload = task.paypalPayload || {};
  const rewardCents = Number(paypalPayload.reward_cents || task.fundingPayload?.reward_cents || task.reward_cents) || 0;
  const fundingCents = Number(paypalPayload.budget_cents || task.recommendedFundingCents || task.fundingPayload?.budget_cents || rewardCents) || rewardCents;
  const returnURL = absolutePublicPath('/paypal/return?flow=repo_task_funding');
  const cancelURL = absolutePublicPath('/paypal/cancel?flow=repo_task_funding');
  const endpoint = task.paypalOrderEndpoint || `/api/projects/${encodeURIComponent(projectID)}/repo-scan/suggested-tasks/${encodeURIComponent(task.id)}/paypal-order`;
  const order = await api(endpoint, {
    method: 'POST',
    body: JSON.stringify({
      suggested_task_id: paypalPayload.suggested_task_id || task.id,
      reward_cents: rewardCents,
      budget_cents: fundingCents,
      return_url: returnURL,
      cancel_url: cancelURL,
    }),
  });
  if (!order?.approval_url || !order?.order_id) {
    throw new Error('PayPal did not return an approval URL.');
  }
  writePendingRepositoryTaskFunding({
    flow: 'repo_task_funding',
    projectID,
    taskID: task.id,
    rewardCents,
    orderID: order.order_id,
    createdAt: Date.now(),
  });
  showToast('Redirecting to PayPal checkout...');
  window.location.href = order.approval_url;
}

function repositoryTaskFundEndpoint(projectID, taskID, task = {}) {
  if (task?.fundEndpoint) return task.fundEndpoint;
  return `/api/projects/${encodeURIComponent(projectID)}/repo-scan/suggested-tasks/${encodeURIComponent(taskID)}/fund`;
}

async function submitRepositorySuggestedTaskFundingRequest(projectID, taskID, rewardCents, paymentMethod, paymentReference, options = {}) {
  const endpoint = repositoryTaskFundEndpoint(projectID, taskID, options.task || {});
  const task = options.task || {};
  const fundingPayload = task.fundingPayload || {};
  const budgetCents = Number(task.recommendedFundingCents || fundingPayload.budget_cents || rewardCents) || rewardCents;
  const payload = await api(endpoint, {
    method: 'POST',
    body: JSON.stringify({
      reward_cents: Number(rewardCents) || 0,
      budget_cents: budgetCents,
      payment_method: paymentMethod,
      payment_reference: paymentReference,
    }),
  });
  showToast(payload?.task?.issue_number ? `Funded task #${payload.task.issue_number}.` : 'Repository task funded.');
  await loadDashboardData({ silent: true, selectProjectID: projectID });
  await Promise.allSettled([
    loadDashboardRepositoryIntelligenceData(projectID, { silent: true }),
    loadDashboardEscrowData(projectID, { silent: true }),
    loadMarketplaceData({ silent: true }),
    loadLiveFeedData({ silent: true }),
  ]);
  return payload;
}

function reviewDraftForTask(task = {}) {
  const id = task.id || `${task.project_id || 'task'}-${task.issue_number || 'review'}`;
  if (!taskReviewDrafts[id]) {
    taskReviewDrafts[id] = {
      pullRequestURL: task.pullRequestURL || task.pull_request_url || '',
      evidenceURL: task.reviewEvidenceURL || task.review_evidence_url || '',
      notes: task.reviewNotes || task.review_notes || '',
    };
  }
  return taskReviewDrafts[id];
}

function taskReviewKey(task = {}) {
  return task.id || `${task.project_id || 'task'}-${task.issue_number || 'review'}`;
}

function isHttpURL(value = '') {
  const raw = String(value || '').trim();
  if (!raw) return false;
  try {
    const url = new URL(raw);
    return url.protocol === 'http:' || url.protocol === 'https:';
  } catch {
    return false;
  }
}

function isGitHubPullRequestURL(value = '') {
  const raw = String(value || '').trim();
  if (!raw) return false;
  try {
    const url = new URL(raw);
    if (url.hostname.toLowerCase() !== 'github.com') return false;
    return /^\/[^/]+\/[^/]+\/pull\/\d+\/?$/i.test(url.pathname);
  } catch {
    return false;
  }
}

function validateTaskReviewDraft(draft = {}) {
  const errors = {};
  const pullRequestURL = String(draft.pullRequestURL || '').trim();
  const evidenceURL = String(draft.evidenceURL || '').trim();
  const notes = String(draft.notes || '').trim();
  if (pullRequestURL && !isGitHubPullRequestURL(pullRequestURL)) {
    errors.pullRequestURL = 'Use a GitHub pull request URL like https://github.com/org/repo/pull/12.';
  }
  if (evidenceURL && !isHttpURL(evidenceURL)) {
    errors.evidenceURL = 'Use an http or https evidence URL.';
  }
  if (!pullRequestURL && !evidenceURL && notes.length < 12) {
    errors.notes = 'Add review notes, a pull request URL, or an evidence URL before submitting.';
  } else if (notes && notes.length < 12) {
    errors.notes = 'Review notes should be at least 12 characters.';
  }
  return errors;
}

function setTaskReviewErrors(task = {}, errors = {}) {
  const key = taskReviewKey(task);
  if (!key) return;
  taskReviewErrors[key] = errors;
}

function taskReviewFieldError(task = {}, field = '') {
  return taskReviewErrors[taskReviewKey(task)]?.[field] || '';
}

function clearTaskReviewFieldError(task = {}, field = '') {
  const key = taskReviewKey(task);
  if (!field || !taskReviewErrors[key]?.[field]) return;
  taskReviewErrors[key] = {
    ...taskReviewErrors[key],
    [field]: '',
  };
  for (const [errorField, message] of Object.entries(taskReviewErrors[key])) {
    if (!message) delete taskReviewErrors[key][errorField];
  }
}

function taskReviewErrorList(task = {}) {
  const errors = taskReviewErrors[taskReviewKey(task)] || {};
  return Object.entries(errors).map(([field, message]) => ({ field, message }));
}

function toggleTaskReviewSubmission(task = {}) {
  if (!task?.id) return;
  reviewDraftForTask(task);
  setTaskReviewErrors(task, {});
  expandedReviewTaskID.value = expandedReviewTaskID.value === task.id ? '' : task.id;
}

async function submitTaskReview(task = {}) {
  if (!task?.id || reviewSubmittingTaskID.value) return;
  const draft = reviewDraftForTask(task);
  const validationErrors = validateTaskReviewDraft(draft);
  setTaskReviewErrors(task, validationErrors);
  const errorCount = Object.keys(validationErrors).length;
  if (errorCount) {
    showToast(errorCount === 1 ? 'Fix 1 review item before submitting.' : `Fix ${errorCount} review items before submitting.`);
    return;
  }
  reviewSubmittingTaskID.value = task.id;
  try {
    const submitted = await api(`/api/tasks/${encodeURIComponent(task.id)}/submit`, {
      method: 'POST',
      body: JSON.stringify({
        pull_request_url: draft.pullRequestURL,
        evidence_url: draft.evidenceURL,
        notes: draft.notes,
      }),
    });
    setTaskReviewErrors(task, {});
    taskReviewDrafts[task.id] = {
      pullRequestURL: submitted.pull_request_url || draft.pullRequestURL,
      evidenceURL: submitted.review_evidence_url || draft.evidenceURL,
      notes: submitted.review_notes || draft.notes,
    };
    expandedReviewTaskID.value = '';
    await Promise.all([
      loadWorkerDashboardData({ silent: true }),
      loadDashboardData({ silent: true }),
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
    ]);
    showToast(`Task #${submitted.issue_number || task.issueNumber || ''} submitted for review. Payout remains locked.`);
  } catch (error) {
    showToast(error.message || 'Could not submit review evidence.');
  } finally {
    reviewSubmittingTaskID.value = '';
  }
}

async function releaseTaskPayment(task = {}) {
  if (!task?.id || releasingTaskID.value) return;
  const releasePacket = task.releasePacket || {};
  if (task.releasePacket && !releasePacket.can_release) {
    showToast(releasePacket.blockers?.[0] || 'This payout is not ready to release.');
    return;
  }
  releasingTaskID.value = task.id;
  try {
    const endpoint = releasePacket.release_endpoint || `/api/tasks/${encodeURIComponent(task.id)}/accept`;
    const payload = releasePacket.payload || {
      worker_kind: task.workerKind,
      worker_id: task.workerID,
      agent_type: task.agentType,
    };
    const accepted = await api(endpoint, {
      method: 'POST',
      body: JSON.stringify(payload),
    });
    await Promise.all([
      loadDashboardData({ silent: true }),
      loadDashboardEscrowData(selectedDashboardProjectID.value, { silent: true }),
      loadWorkerDashboardData({ silent: true }),
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
    ]);
    showToast(`Released payout for task #${accepted.issue_number || task.issueNumber || ''}.`);
  } catch (error) {
    showToast(error.message || 'Could not release payout.');
  } finally {
    releasingTaskID.value = '';
  }
}

async function requestTaskChanges(task = {}) {
  if (!task?.id || requestingChangesTaskID.value) return;
  const currentNotes = task.reviewNotes || task.review_notes || '';
  const promptText = 'Describe the changes needed before payout release.';
  const notes = hasWindow
    ? String(window.prompt(promptText, currentNotes) || '').trim()
    : '';
  if (!notes) return;
  if (notes.length < 12) {
    showToast('Add at least 12 characters for requested changes.');
    return;
  }
  requestingChangesTaskID.value = task.id;
  try {
    const response = await api(`/api/tasks/${encodeURIComponent(task.id)}/request-changes`, {
      method: 'POST',
      body: JSON.stringify({ review_notes: notes }),
    });
    await Promise.all([
      loadDashboardData({ silent: true }),
      loadDashboardPullRequestsData(selectedDashboardProjectID.value, { silent: true }),
      loadDashboardEscrowData(selectedDashboardProjectID.value, { silent: true }),
      loadWorkerDashboardData({ silent: true }),
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
    ]);
    showToast(`Requested changes for task #${response.issue_number || task.issueNumber || ''}.`);
  } catch (error) {
    showToast(error.message || 'Could not request changes.');
  } finally {
    requestingChangesTaskID.value = '';
  }
}

async function runProjectAutoRelease() {
  const projectID = dashboardSelectedProject.value?.id || selectedDashboardProjectID.value;
  const readyRows = dashboardAutoReleaseReadyRows.value;
  if (!projectID || !readyRows.length || autoReleasingProjectID.value) return;
  const packet = readyRows[0].autoReleasePacket || {};
  const endpoint = packet.release_endpoint || `/api/projects/${encodeURIComponent(projectID)}/auto-release`;
  const taskIDs = readyRows
    .flatMap((row) => row.autoReleasePacket?.payload?.task_ids || [row.id])
    .filter(Boolean);
  autoReleasingProjectID.value = projectID;
  try {
    const payload = await api(endpoint, {
      method: packet.method || 'POST',
      body: JSON.stringify({
        ...(packet.payload || {}),
        task_ids: taskIDs,
        policy: packet.policy || packet.payload?.policy,
      }),
    });
    await Promise.all([
      loadDashboardData({ silent: true, selectProjectID: projectID }),
      loadDashboardPullRequestsData(projectID, { silent: true }),
      loadDashboardEscrowData(projectID, { silent: true }),
      loadWorkerDashboardData({ silent: true }),
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
    ]);
    const released = Number(payload?.released_count) || 0;
    const skipped = Number(payload?.skipped_count) || 0;
    showToast(released ? `Auto-released ${released} payout${released === 1 ? '' : 's'}.` : skipped ? 'No eligible payouts auto-released.' : 'Auto-release queue is empty.');
  } catch (error) {
    showToast(error.message || 'Could not run auto-release.');
  } finally {
    autoReleasingProjectID.value = '';
  }
}

function applyAdminTriageFilter(item = {}) {
  dashboardSection.value = 'admin';
  dashboardSearch.value = item.searchTerm || '';
  showToast(`${item.label || 'Admin triage'} filter applied.`);
