  }

  const silent = Boolean(options.silent);
  if (!silent) dashboardPullRequestsLoading.value = true;
  dashboardPullRequestsError.value = '';
  try {
    const payload = await api(`/api/projects/${encodeURIComponent(targetProjectID)}/pull-requests`);
    dashboardPullRequests.value = normalizeDashboardPullRequestsPayload(payload, targetProjectID);
  } catch (error) {
    if (targetProjectID === selectedDashboardProjectID.value) {
      dashboardPullRequests.value = null;
      dashboardPullRequestsError.value = error.message || 'Could not load PR monitor';
    }
  } finally {
    dashboardPullRequestsLoading.value = false;
  }
}

async function loadDashboardRoutingData(projectID, options = {}) {
  const targetProjectID = String(projectID || '').trim();
  if (!token.value || !targetProjectID) {
    dashboardRouting.value = null;
    dashboardRoutingLoading.value = false;
    dashboardRoutingError.value = '';
    return;
  }

  const silent = Boolean(options.silent);
  if (!silent) dashboardRoutingLoading.value = true;
  dashboardRoutingError.value = '';
  try {
    const payload = await api(`/api/projects/${encodeURIComponent(targetProjectID)}/routing`);
    if (targetProjectID !== selectedDashboardProjectID.value) return;
    dashboardRouting.value = normalizeDashboardRoutingPayload(payload, targetProjectID);
  } catch (error) {
    if (targetProjectID === selectedDashboardProjectID.value) {
      dashboardRouting.value = null;
      dashboardRoutingError.value = error.message || 'Could not load contributor routing';
    }
  } finally {
    dashboardRoutingLoading.value = false;
  }
}

async function loadWorkerDashboardData(options = {}) {
  if (!token.value) {
    workerDashboard.value = {
      profile: {},
      stats: {},
      claimed_tasks: [],
      rewards: [],
      reputation: [],
      reputation_audit: {},
      proposals: [],
      submitted_proposals: [],
      identity_status: [],
    };
    workerDashboardError.value = '';
    return;
  }

  const silent = Boolean(options.silent);
  if (!silent) workerDashboardLoading.value = true;
  workerDashboardError.value = '';
  try {
    const payload = await api('/api/workers/me');
    workerDashboard.value = {
      profile: payload.profile || {},
      stats: payload.stats || {},
      claimed_tasks: Array.isArray(payload.claimed_tasks) ? payload.claimed_tasks : [],
      rewards: Array.isArray(payload.rewards) ? payload.rewards : [],
      reputation: Array.isArray(payload.reputation) ? payload.reputation : [],
      reputation_audit: payload.reputation_audit && typeof payload.reputation_audit === 'object' ? payload.reputation_audit : {},
      proposals: Array.isArray(payload.proposals) ? payload.proposals : [],
      submitted_proposals: Array.isArray(payload.submitted_proposals) ? payload.submitted_proposals : [],
      identity_status: Array.isArray(payload.identity_status) ? payload.identity_status : [],
    };
  } catch (error) {
    workerDashboardError.value = error.message || 'Could not load worker dashboard';
  } finally {
    workerDashboardLoading.value = false;
  }
}

async function loadDashboardNotifications(options = {}) {
  if (!token.value) {
    dashboardNotifications.value = [];
    dashboardNotificationsError.value = '';
    return;
  }
  const silent = Boolean(options.silent);
  if (!silent) dashboardNotificationsLoading.value = true;
  dashboardNotificationsError.value = '';
  try {
    const rows = await api('/api/notifications');
    dashboardNotifications.value = Array.isArray(rows) ? rows : [];
  } catch (error) {
    dashboardNotificationsError.value = error.message || 'Could not load notifications';
  } finally {
    if (!silent) dashboardNotificationsLoading.value = false;
  }
}

async function markAllNotificationsRead() {
  if (!token.value) return;
  try {
    await api('/api/notifications/read-all', { method: 'POST' });
    await loadDashboardNotifications();
  } catch (error) {
    showToast(error.message || 'Could not mark notifications as read.');
  }
}

async function markNotificationAsRead(notificationId) {
  if (!token.value || !notificationId) return;
  try {
    await api('/api/notifications/read', {
      method: 'POST',
      body: JSON.stringify({ notification_id: notificationId }),
    });
    const idx = dashboardNotifications.value.findIndex((n) => n.id === notificationId);
    if (idx !== -1) {
      dashboardNotifications.value[idx] = {
        ...dashboardNotifications.value[idx],
        read_at: new Date().toISOString(),
      };
    }
  } catch {
    // silently ignore â€” notification will refresh on next poll
  }
}

function closeDashboardNotificationMenu(options = {}) {
  dashboardNotificationMenuOpen.value = false;
  dashboardNotificationDropdownStyle.value = {};
  if (options.restoreFocus) {
    void nextTick().then(() => dashboardNotificationTrigger.value?.focus?.({ preventScroll: true }));
  }
}

function updateDashboardNotificationMenuPosition() {
  if (!hasWindow || !dashboardNotificationMenuOpen.value || !dashboardNotificationTrigger.value) return;
  const triggerRect = dashboardNotificationTrigger.value.getBoundingClientRect();
  const viewportWidth = window.innerWidth || document.documentElement.clientWidth || 0;
  const viewportHeight = window.innerHeight || document.documentElement.clientHeight || 0;
  if (viewportWidth <= 760) {
    const bottomInset = window.visualViewport
      ? Math.max(0, viewportHeight - window.visualViewport.height - window.visualViewport.offsetTop)
      : 0;
    dashboardNotificationMenuPlacement.value = 'mobile-sheet';
    dashboardNotificationDropdownStyle.value = {
      '--notification-list-max-height': `${Math.round(Math.max(120, Math.min(360, viewportHeight * 0.72 - 154)))}px`,
      '--dashboard-mobile-bottom-inset': `${Math.round(bottomInset)}px`,
    };
    return;
  }
  const margin = viewportWidth <= 700 ? 12 : 10;
  const width = Math.max(260, Math.min(368, viewportWidth - margin * 2));
  const maxLeft = Math.max(margin, viewportWidth - width - margin);
  const left = Math.min(Math.max(margin, triggerRect.right - width), maxLeft);
  const spaceBelow = viewportHeight - triggerRect.bottom - margin;
  const spaceAbove = triggerRect.top - margin;
  const placeAbove = spaceBelow < 260 && spaceAbove > spaceBelow;
  const availableHeight = Math.max(220, (placeAbove ? spaceAbove : spaceBelow) - 12);
  const maxHeight = Math.min(420, availableHeight);
  const arrowLeft = Math.min(
    Math.max(18, triggerRect.left + triggerRect.width / 2 - left - 6),
    width - 22,
  );

  dashboardNotificationMenuPlacement.value = placeAbove ? 'above' : 'below';
  dashboardNotificationDropdownStyle.value = {
    '--notification-arrow-left': `${Math.round(arrowLeft)}px`,
    '--notification-list-max-height': `${Math.round(Math.max(96, maxHeight - 132))}px`,
    bottom: placeAbove ? `${Math.round(viewportHeight - triggerRect.top + 12)}px` : 'auto',
    left: `${Math.round(left)}px`,
    maxHeight: `${Math.round(maxHeight)}px`,
    right: 'auto',
    top: placeAbove ? 'auto' : `${Math.round(triggerRect.bottom + 12)}px`,
    width: `${Math.round(width)}px`,
  };
}

async function openDashboardNotificationMenu(options = {}) {
  dashboardNotificationMenuOpen.value = true;
  await nextTick();
  updateDashboardNotificationMenuPosition();
  dashboardNotificationDropdown.value?.focus?.({ preventScroll: true });
  try {
    await loadDashboardNotifications();
  } finally {
    if (dashboardNotificationMenuOpen.value) {
      await nextTick();
      updateDashboardNotificationMenuPosition();
      if (options.focus !== false) {
        dashboardNotificationDropdown.value?.focus?.({ preventScroll: true });
      }
    }
  }
}

async function toggleDashboardNotificationMenu() {
  if (dashboardNotificationMenuOpen.value) {
    closeDashboardNotificationMenu({ restoreFocus: true });
    return;
  }
  await openDashboardNotificationMenu();
}

async function refreshDashboardNotificationMenu() {
  await openDashboardNotificationMenu({ focus: false });
}

async function markAllNotificationsReadFromMenu() {
  await markAllNotificationsRead();
  dashboardNotificationMenuOpen.value = true;
  await nextTick();
  updateDashboardNotificationMenuPosition();
}

function openDashboardNotificationCenter() {
  closeDashboardNotificationMenu({ restoreFocus: true });
  openDashboardSection('notifications');
}

function handleNotificationClick(note) {
  if (note.isUnread) {
    markNotificationAsRead(note.id);
  }
}

function handleNotificationMenuClick(note) {
  handleNotificationClick(note);
  closeDashboardNotificationMenu({ restoreFocus: true });
}

function handleDashboardNotificationOutsideClick(event) {
  if (!dashboardNotificationMenuOpen.value) return;
  const target = event.target;
  const menu = dashboardNotificationMenu.value;
  const dropdown = dashboardNotificationDropdown.value;
  if (menu?.contains(target) || dropdown?.contains(target)) return;
  closeDashboardNotificationMenu();
}

function startDashboardRealtime() {
  if (!hasWindow || dashboardRefreshTimer) return;
  dashboardRefreshTimer = window.setInterval(() => {
    if (!token.value || !user.value) return;
    if (document.visibilityState === 'hidden') return;
    void loadDashboardData({ silent: true });
    if (dashboardSection.value === 'worker') {
      void loadWorkerDashboardData({ silent: true });
    }
    if (dashboardSection.value === 'admin' && isAdminUser.value) {
      void loadAdminConsoleData({ silent: true });
    }
    void loadDashboardNotifications();
  }, DASHBOARD_REFRESH_MS);
}

function stopDashboardRealtime() {
  if (!hasWindow || !dashboardRefreshTimer) return;
  window.clearInterval(dashboardRefreshTimer);
  dashboardRefreshTimer = 0;
}

function openAuth(mode = 'login') {
  setAuthMode(mode);
  authVisible.value = true;
}

function openPasswordResetRequest() {
  const email = authForm.email;
  setAuthMode('reset-request');
  authForm.email = email;
}

function closeAuth() {
  if (authBusy.value) return;
  authVisible.value = false;
  errorMessage.value = '';
  authNotice.value = '';
  if (authReturnToProjectWizard.value) {
    projectWizardVisible.value = true;
    authReturnToProjectWizard.value = false;
    pendingProjectPaymentAfterAuth.value = false;
  }
}

function setSession(auth) {
  token.value = auth.token;
  user.value = auth.user;
  authVisible.value = false;
  errorMessage.value = '';
  authNotice.value = '';
  writeStoredToken(auth.token);
  if (authReturnToProjectWizard.value) {
    projectWizardVisible.value = true;
    authReturnToProjectWizard.value = false;
  }
  if (hasWindow && isPayPalCheckoutPath(window.location.pathname)) {
    void handlePayPalCheckoutReturn();
  } else if (pendingProjectPaymentAfterAuth.value) {
    pendingProjectPaymentAfterAuth.value = false;
    void completeProjectFunding();
  }
  if (publicPage.value === 'ledger') {
    void loadLedgerData({ silent: true });
  }
  if (publicPage.value === 'live') {
    void loadLiveFeedData({ silent: true });
  }
  void loadDashboardData({ silent: true });
  void loadWorkerDashboardData({ silent: true });
  if (auth.user?.role === 'admin') {
    void loadAdminConsoleData({ silent: true });
  }
  void loadDashboardNotifications();
  startDashboardRealtime();
  if (pendingClaimBounty.value) {
    void claimMarketplaceBounty(pendingClaimBounty.value);
  }
}

let _ws = null;
let _wsReconnectTimer = 0;
let _wsReconnectDelay = 1000;
const _wsSeenProjectIDs = new Set();
const _wsSeenEventIDs = new Set();
const realtimeTaskEventTypes = new Set(['task_opened', 'task_claimed', 'task_submitted', 'task_changes_requested', 'task_accepted']);
const realtimeProposalEventTypes = new Set(['proposal_created', 'proposal_decided', 'proposal_submitted', 'proposal_accepted', 'proposal_declined']);
const realtimeDeploymentEventTypes = new Set(['deployment_status']);
const realtimeAgentEventTypes = new Set(['agent_action', 'agent_lease']);
const realtimeLedgerEventTypes = new Set(['ledger_task_payment']);
const realtimeLifecycleEventTypes = new Set(['realtime_ready', 'connection_ready', 'realtime_snapshot', 'live_feed_snapshot', 'realtime_heartbeat']);

function wsURL() {
  if (!hasWindow) return '';
  const proto = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
  return `${proto}//${window.location.host}/api/ws`;
}

function connectWebSocket() {
  if (!hasWindow || _ws) return;
  wsConnectionState.value = 'connecting';
  try {
    _ws = new WebSocket(wsURL());
  } catch {
    _ws = null;
    wsConnectionState.value = 'reconnecting';
    scheduleWSReconnect();
    return;
  }
  _ws.onopen = () => {
    _wsReconnectDelay = 1000;
    wsReconnectDelayMs.value = 0;
    wsConnectionState.value = 'connected';
    wsLastEventAt.value = new Date().toISOString();
  };
  _ws.onmessage = (event) => {
    wsLastEventAt.value = new Date().toISOString();
    let payload;
    try {
      payload = JSON.parse(event.data);
    } catch {
      return;
    }
    handleWSEvent(payload);
  };
  _ws.onerror = () => {};
  _ws.onclose = () => {
    _ws = null;
    wsConnectionState.value = 'reconnecting';
    scheduleWSReconnect();
  };
}

function disconnectWebSocket() {
  if (_wsReconnectTimer) {
    window.clearTimeout(_wsReconnectTimer);
    _wsReconnectTimer = 0;
  }
  _wsReconnectDelay = 1000;
  wsReconnectDelayMs.value = 0;
  wsConnectionState.value = 'idle';
  _wsSeenProjectIDs.clear();
  _wsSeenEventIDs.clear();
  if (!_ws) return;
  _ws.onclose = null;
  _ws.onerror = null;
  _ws.onmessage = null;
  _ws.onopen = null;
  try {
    _ws.close();
  } catch {
    // ignore close errors
  }
  _ws = null;
}

function scheduleWSReconnect() {
  if (!hasWindow || _wsReconnectTimer) return;
  wsConnectionState.value = 'reconnecting';
  wsReconnectDelayMs.value = _wsReconnectDelay;
  _wsReconnectTimer = window.setTimeout(() => {
    _wsReconnectTimer = 0;
    _wsReconnectDelay = Math.min(_wsReconnectDelay * 2, 30000);
    connectWebSocket();
  }, _wsReconnectDelay);
}

function handleWSEvent(payload = {}) {
  if (!payload || !payload.type) return;
  if (realtimeLifecycleEventTypes.has(payload.type)) {
    handleWSLifecycle(payload);
    return;
  }
  if (payload.type === 'project_created') {
    handleWSProjectCreated(payload);
    return;
  }
  if (payload.type === 'notifications_updated') {
    handleWSNotificationsUpdated(payload);
    return;
  }
  if (payload.type === 'admin_ops_updated') {
    handleWSAdminOpsUpdated(payload);
    return;
  }
  if (payload.type === 'repo_scan') {
    handleWSRepositoryScan(payload);
    return;
  }
  if (payload.type === 'proposal_created' || payload.type === 'proposal_decided') {
    handleWSProposalCreated(payload);
    return;
  }
  if (realtimeTaskEventTypes.has(payload.type)) {
    handleWSTaskLifecycle(payload);
    return;
  }
  if (realtimeDeploymentEventTypes.has(payload.type)) {
    handleWSDeploymentStatus(payload);
    return;
  }
  if (realtimeLedgerEventTypes.has(payload.type) || String(payload.type || '').startsWith('ledger_')) {
    handleWSLedgerEvent(payload);
    return;
  }
  if (payload.type === 'contributor_activity') {
    handleWSContributorActivity(payload);
    return;
  }
  if (payload.type === 'escrow_status') {
    handleWSEscrowStatus(payload);
    return;
  }
  if (payload.type === 'agent_queue') {
    handleWSAgentQueue(payload);
    return;
  }
  if (payload.type === 'agent_presence') {
    handleWSAgentPresence(payload);
    return;
  }
  if (payload.type === 'agent_claim') {
    handleWSAgentClaim(payload);
    return;
  }
  if (payload.type === 'agent_submit') {
    handleWSAgentSubmit(payload);
    return;
  }
  if (payload.type === 'agent_release') {
    handleWSAgentRelease(payload);
    return;
  }
  if (payload.type === 'ai_review') {
    handleWSAIReview(payload);
    return;
  }
  if (realtimeAgentEventTypes.has(payload.type)) {
    handleWSAgentAction(payload);
  }
}

function handleWSLifecycle(payload = {}) {
  if (payload.type === 'realtime_heartbeat') return;
  if (payload.type === 'realtime_ready' || payload.type === 'connection_ready') {
    wsConnectionState.value = 'connected';
    wsLastEventAt.value = payload.created_at || new Date().toISOString();
    if (payload.event_id) rememberWSEvent(payload.event_id);
    return;
  }
  const eventID = payload.event_id || `realtime_snapshot:${payload.created_at || ''}`;
  if (rememberWSEvent(eventID)) return;
  wsConnectionState.value = 'synced';
  wsLastEventAt.value = payload.created_at || new Date().toISOString();
  hydrateRealtimeSnapshot(payload.snapshot || payload);
}

function hydrateRealtimeSnapshot(snapshot = {}) {
  const liveFeed = snapshot.live_feed || snapshot.liveFeed || snapshot.feed;
  if (liveFeed && typeof liveFeed === 'object') {
    liveFeedData.value = {
      stats: liveFeed.stats || {},
      items: Array.isArray(liveFeed.items) ? liveFeed.items : [],
    };
    liveFeedError.value = '';
    liveFeedLoading.value = false;
  }

  const agentQueue = snapshot.agent_queue || snapshot.agentQueue;
  if (agentQueue && typeof agentQueue === 'object') {
    hydrateAgentQueueData(agentQueue);
  }

  hydrateLedgerRealtimeData(snapshot);
}

function prependRealtimeLiveFeedItem(item = {}) {
  if (!item || !item.id) return;
  const current = liveFeedData.value || { stats: {}, items: [] };
  const items = Array.isArray(current.items) ? current.items : [];
  liveFeedData.value = {
    stats: current.stats || {},
    items: [item, ...items.filter((row) => row.id !== item.id)].slice(0, 80),
  };
  liveFeedLoading.value = false;
  liveFeedError.value = '';
}

function hydrateAgentQueueData(agentQueue = {}) {
  if (!agentQueue || typeof agentQueue !== 'object') return;
  agentQueueData.value = {
    stats: agentQueue.stats || {},
    agents: Array.isArray(agentQueue.agents) ? agentQueue.agents : [],
    tasks: Array.isArray(agentQueue.tasks) ? agentQueue.tasks : [],
  };
  if (Array.isArray(agentQueue.agents)) {
    marketplaceData.value = {
      ...marketplaceData.value,
      agents: agentQueue.agents,
    };
  }
  agentQueueError.value = '';
  agentQueueLoading.value = false;
}

function hydrateLedgerRealtimeData(payload = {}) {
  const events = payload.ledger_events || payload.ledgerEvents;
  const economy = payload.token_economy || payload.tokenEconomy;
  let hydrated = false;

  if (events && typeof events === 'object') {
    ledgerEventData.value = {
      stats: events.stats || {},
      items: Array.isArray(events.items) ? events.items : [],
    };
    hydrated = true;
  }

  if (economy && typeof economy === 'object') {
    ledgerEconomy.value = {
      stats: economy.stats || {},
      totals: economy.totals || {},
      balances: Array.isArray(economy.balances) ? economy.balances : [],
      flows: Array.isArray(economy.flows) ? economy.flows : [],
      recent_entries: Array.isArray(economy.recent_entries) ? economy.recent_entries : [],
    };
    hydrated = true;
  }

  if (hydrated) {
    ledgerError.value = '';
    ledgerLoading.value = false;
  }
}

function rememberWSEvent(eventID = '') {
  const id = String(eventID || '').trim();
  if (!id) return false;
  if (_wsSeenEventIDs.has(id)) return true;
  if (_wsSeenEventIDs.size > 500) {
    _wsSeenEventIDs.clear();
  }
  _wsSeenEventIDs.add(id);
  return false;
}

function realtimeReleaseReadiness(payload = {}) {
  const readiness = payload.release_readiness || payload.releaseReadiness || {};
  return readiness && typeof readiness === 'object' ? readiness : {};
}

function realtimeTaskIsReleaseReady(payload = {}) {
  const readiness = realtimeReleaseReadiness(payload);
  return payload.type === 'task_submitted' && (readiness.can_release === true || readiness.status === 'ready_for_release');
}

function realtimeTaskReleaseNotification(payload = {}) {
  if (!realtimeTaskIsReleaseReady(payload)) return null;
  const issueNumber = Number(payload.issue_number) || '';
  const projectTitle = payload.project_title || 'MergeOS project';
  const createdAt = payload.created_at || new Date().toISOString();
  return {
    id: `${payload.event_id || `task-release-ready:${payload.project_id || 'project'}:${issueNumber}:${createdAt}`}:notification`,
    project_id: payload.project_id || '',
    channel: 'realtime',
    subject: issueNumber ? `Payout ready to release for #${issueNumber}` : 'Payout ready to release',
    body: `${projectTitle} has submitted review evidence. The customer release packet is loading in the dashboard.`,
    status: 'live:release-ready',
    created_at: createdAt,
  };
}

function realtimeLedgerNotification(payload = {}) {
  if (payload.type !== 'ledger_task_payment') return null;
  const item = payload.item || {};
  const issueNumber = Number(payload.issue_number) || '';
  const projectTitle = payload.project_title || item.project_title || 'MergeOS project';
  const createdAt = payload.created_at || item.created_at || new Date().toISOString();
  const auditLabel = ledgerAuditLabel(payload) || ledgerAuditLabel(item);
  const amount = formatMRGFromCents(payload.amount_cents || item.amount_cents || 0);
  const autoRelease = payload.automation === 'auto_release' || item.automation === 'auto_release';
  return {
    id: `${payload.event_id || item.id || `ledger-payout:${payload.project_id || item.project_id || 'project'}:${issueNumber}:${createdAt}`}:notification`,
    project_id: payload.project_id || item.project_id || '',
    channel: 'realtime',
    subject: issueNumber
      ? `${autoRelease ? 'Auto-release' : 'Payout'} recorded for #${issueNumber}`
      : `${autoRelease ? 'Auto-release' : 'Payout'} recorded`,
    body: `${projectTitle} recorded ${amount}${auditLabel ? ` / ${auditLabel}` : ''} in the public ledger.`,
    status: autoRelease ? 'live:auto-release-payout' : 'live:payout-recorded',
    created_at: createdAt,
  };
}

function pushDashboardRealtimeNotification(note = {}) {
  if (!note.id) return;
  if (dashboardNotifications.value.some((notification) => notification.id === note.id)) return;
  dashboardNotifications.value = [note, ...dashboardNotifications.value].slice(0, 40);
}

function handleWSNotificationsUpdated(payload = {}) {
  if (payload.kind !== 'notification_signal' || !token.value) return;
  void loadDashboardNotifications({ silent: true });
}

function handleWSAdminOpsUpdated(payload = {}) {
  if (payload.kind !== 'admin_ops_signal' || !token.value || !isAdminUser.value) return;
  void loadAdminConsoleData({ silent: true });
  if (dashboardSection.value === 'admin') {
    showToast('Admin ops refreshed.');
  }
}

function handleWSProjectCreated(payload = {}) {
  const project = payload.project;
  if (!project || !project.id) return;

  if (_wsSeenProjectIDs.has(project.id) || rememberWSEvent(payload.event_id || `project:${project.id}`)) return;
  _wsSeenProjectIDs.add(project.id);

  if (user.value) {
    const exists = dashboardProjects.value.some((p) => p.id === project.id);
    if (!exists && !selectedDashboardProjectID.value) {
      selectedDashboardProjectID.value = project.id;
    }
    void loadDashboardData({ silent: true, selectProjectID: selectedDashboardProjectID.value || project.id });
    void loadDashboardNotifications();
  }

  if (marketplaceData.value && Array.isArray(marketplaceData.value.projects)) {
    const exists = marketplaceData.value.projects.some((p) => p.id === project.id);
    if (!exists) {
      marketplaceData.value = {
        ...marketplaceData.value,
        projects: [project, ...marketplaceData.value.projects],
        stats: {
          ...marketplaceData.value.stats,
          project_count: (Number(marketplaceData.value.stats?.project_count) || marketplaceData.value.projects.length) + 1,
          total_budget_cents: (Number(marketplaceData.value.stats?.total_budget_cents) || 0) + (Number(project.budget_cents) || 0),
        },
      };
    }
  }
  void loadMarketplaceData({ silent: true });
  void loadLiveFeedData({ silent: true });
}

function handleWSRepositoryScan(payload = {}) {
  const scan = payload.scan || {};
  const item = payload.item || {};
  const projectID = payload.project_id || scan.project_id || item.project_id || '';
  const eventID = payload.event_id || item.id || `repo_scan:${projectID}:${payload.status || scan.status || ''}:${payload.created_at || scan.updated_at || ''}`;
  if (rememberWSEvent(eventID)) return;
  if (!projectID) return;

  if (user.value) {
    const ownsProject = dashboardProjects.value.some((project) => project.id === projectID);
    const shouldShowProject = isAdminUser.value || ownsProject || projectID === selectedDashboardProjectID.value;
    if (shouldShowProject && projectID === selectedDashboardProjectID.value) {
      dashboardRepositoryScan.value = normalizeDashboardRepositoryScanPayload(scan, projectID);
